 weekly:[{id:uid('week'),day:'Monday',time:'8:30 AM',subject:'Reading',title:'Whole-group reading mini lesson',note:'Model the skill, then release students to partner practice.',createdAt:t,updatedAt:t},{id:uid('week'),day:'Monday',time:'10:00 AM',subject:'Math',title:'Small-group math rotations',note:'Teacher table, independent work, manipulatives, and review game.',createdAt:t,updatedAt:t},{id:uid('week'),day:'Wednesday',time:'1:00 PM',subject:'Science',title:'Dinosaur fossil investigation',note:'Use the cross-curricular dinosaur theme lessons.',createdAt:t,updatedAt:t}],
