 groups:[], gallery:[], gallerySearch:'', galleryFilter:'all', corkSettings:{freeMove:false,floralBorder:true}, dashboardPins:[{id:uid('pin'),type:'note',text:'Pin important reminders, celebrations, or photos here.',archived:false,createdAt:t,updatedAt:t,x:18,y:22,rot:-2,z:2}], classroomMap:{shape:'rectangle',width:900,height:520,items:[{id:uid('desk'),type:'desk',label:'Desk 1',x:40,y:50,w:110,h:80,studentIds:[]},{id:uid('desk'),type:'desk',label:'Desk 2',x:180,y:50,w:110,h:80,studentIds:[]},{id:uid('table'),type:'table',label:'Table A',x:360,y:90,w:160,h:95,studentIds:[]}]}, meetings:[{id:uid('meet'),title:'Grade-level planning',date:new Date().toISOString().slice(0,10),notes:'Bring pacing guide and lesson ideas.',createdAt:t,updatedAt:t}],
 todos:[{id:uid('todo'),text:'Print math center cards',done:false,priority:'Medium',createdAt:t,updatedAt:t},{id:uid('todo'),text:'Prep sub folder for Friday',done:false,priority:'High',createdAt:t,updatedAt:t}],
