let storageOk=true; let standardsGuideClosedSession=false; let state=load(); let dragItem=null; let resizeDrag=null; let pinDrag=null; let pinSuppressClickUntil=0; let timerLeft=0; let timerInt=null; let audioCtx=null;
function load(){try{const raw=localStorage.getItem(STORE_KEY); storageOk=true; if(raw)return merge(sampleState(),JSON.parse(raw));}catch(e){storageOk=false; console.warn('SOZY Workspace storage is in preview fallback mode:',e);} return sampleState();}
function merge(base,saved){for(const k of Object.keys(saved||{})){if(saved[k]&&typeof saved[k]==='object'&&!Array.isArray(saved[k])&&base[k]&&typeof base[k]==='object'&&!Array.isArray(base[k])) base[k]=merge(base[k],saved[k]); else base[k]=saved[k];} return base;}
function normalize(){const base=sampleState(); state.layout=merge(base.layout,state.layout||{}); state.editing=merge(base.editing,state.editing||{}); pages.forEach(p=>{const id=p[0]; state.layout.cardOrder[id]=state.layout.cardOrder[id]||pageCards[id]||[]; state.layout.collapsed[id]=state.layout.collapsed[id]||[]; state.layout.maximized[id]=state.layout.maximized[id]||[]; state.layout.sizes[id]=state.layout.sizes[id]||{};}); state.layout.menuOrder=(state.layout.menuOrder||topMenuIds).filter(id=>topMenuIds.includes(id)); topMenuIds.forEach(id=>{if(!state.layout.menuOrder.includes(id))state.layout.menuOrder.push(id);}); state.layout.menuHidden=(state.layout.menuHidden||[]).filter(id=>topMenuIds.includes(id)); if(state.activePage==='tools')state.activePage='groups'; if(!pages.some(p=>p[0]===state.activePage))state.activePage='dashboard'; state.layout.dashboardRemoved=state.layout.dashboardRemoved||[]; state.scores=state.scores||{}; state.lessonFilter=state.lessonFilter||'all'; state.lessonSort=state.lessonSort||'updated'; state.quickThemesOpen=!!state.quickThemesOpen; state.toolsMenuOpen=!!state.toolsMenuOpen; state.pinModalOpen=!!state.pinModalOpen; state.lessonModalOpen=!!state.lessonModalOpen; state.weeklyModalOpen=!!state.weeklyModalOpen; state.corkSettings=merge({freeMove:false,floralBorder:true}, state.corkSettings||{}); state.dashboardPins=state.dashboardPins||[]; state.dashboardPins.forEach((p,i)=>{if(typeof p.x!=='number')p.x=18+(i%5)*190;if(typeof p.y!=='number')p.y=22+Math.floor(i/5)*140;if(typeof p.rot!=='number')p.rot=((i%5)-2)*2;if(typeof p.z!=='number')p.z=2+i;}); state.gallery=state.gallery||[]; state.gallerySearch=state.gallerySearch||''; state.galleryFilter=state.galleryFilter||'all'; state.classroomMap=merge(base.classroomMap,state.classroomMap||{}); state.classroomMap.items=state.classroomMap.items||[]; state.classroomMap.items.forEach(it=>{ if(!Array.isArray(it.studentIds)){ it.studentIds=it.studentId?[it.studentId]:[]; } delete it.studentId; });}
function save(msg,render=true){state.lastSaved=nowIso(); try{localStorage.setItem(STORE_KEY,JSON.stringify(state)); storageOk=true;}catch(e){storageOk=false; console.warn('SOZY Workspace could not write local storage. This usually happens in a direct file preview. Buttons will still work, but saving is temporary until you use GitHub Pages or a normal browser origin.',e);} if(msg)toast(msg); renderStatus(); if(render)renderAll();}
function toast(msg){const el=document.getElementById('toast'); el.textContent=msg; el.style.display='block'; clearTimeout(toast.t); toast.t=setTimeout(()=>el.style.display='none',2400);} function esc(s){return String(s??'').replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));}
function val(id){const el=document.getElementById(id); return el?el.value:'';} function chk(id){const el=document.getElementById(id); return !!(el&&el.checked);} function fmt(iso){if(!iso)return 'not saved yet'; const d=new Date(iso); return isNaN(d)?esc(iso):d.toLocaleString([], {month:'short',day:'numeric',hour:'numeric',minute:'2-digit'});} function toDateInput(iso){return iso?new Date(iso).toISOString().slice(0,10):'';} function toLocalInput(iso){if(!iso)return''; const d=new Date(iso); if(isNaN(d))return''; d.setMinutes(d.getMinutes()-d.getTimezoneOffset()); return d.toISOString().slice(0,16);} function fromLocalInput(v){if(!v)return''; return new Date(v).toISOString();}
function applyTheme(){document.body.className=''; if(state.customTheme.enabled){const c=state.customTheme; const r=document.documentElement.style; Object.entries(c).forEach(([k,v])=>{if(k!=='enabled')r.setProperty('--'+k,v);}); document.querySelector('meta[name="theme-color"]').setAttribute('content',c.brand); return;} document.documentElement.removeAttribute('style'); if(state.theme&&state.theme!=='soft')document.body.classList.add('theme-'+state.theme); const t=themeList.find(x=>x[0]===state.theme)||themeList[0]; document.querySelector('meta[name="theme-color"]').setAttribute('content',t[2]);}
function renderStatus(){document.getElementById('statusbar').textContent=(storageOk?'Saved locally':'Preview only — upload to GitHub Pages for real saving')+' • '+fmt(state.lastSaved);} function setPage(id){goToPageCard(id,'');} function goToPageCard(id,cardId){normalize(); if(id!=='settings'&&state.layout.menuHidden.includes(id)){toast('That page is hidden in the menu settings.');return;} state.activePage=id; state.showMenuSettings=false; state.quickThemesOpen=false; save('',false); renderAll(); setTimeout(()=>{const target=cardId?document.getElementById('card-'+id+'-'+cardId):document.getElementById('page-'+id); if(target){target.scrollIntoView({behavior:'smooth',block:'start'}); target.classList.add('pulse-target'); setTimeout(()=>target.classList.remove('pulse-target'),1400);}else{window.scrollTo({top:0,behavior:'smooth'});}},60);} function pageInfo(id){return pages.find(p=>p[0]===id)||pages[0];}
function renderAll(){normalize(); applyTheme(); document.getElementById('app').classList.toggle('menu-hidden',!!state.menuHidden); renderNav(); renderMiniThemes(); renderHeader(); renderPages(); renderMenuPanel(); renderPinModal(); renderCorkSettingsModal(); renderLessonModal(); renderWeeklyModal(); renderStandardModal(); renderPrint(); renderStatus(); scheduleReminderCheck();}
const noLayoutButtonPages=new Set(['monthly','meetings','subexport','subreadiness','subnotes','gallery','supplies','routines','map','reminders','timer','groups','lessons','standards','settings']);
function renderHeader(){const p=pageInfo(state.activePage); document.getElementById('pageTitle').textContent=state.activePage==='dashboard'?'My Dashboard':p[2]; document.getElementById('pageDesc').textContent=state.activePage==='dashboard'?'Your very own visual command center to easily access and customize what you want to see.':p[3]; const actions=document.querySelector('.top-actions'); if(actions){actions.innerHTML=noLayoutButtonPages.has(state.activePage)?'':`<button class="secondary small" data-action="pageSettings">⚙️ Layout</button>`;} if(noLayoutButtonPages.has(state.activePage)&&state.layout.openSettingsPage===state.activePage){state.layout.openSettingsPage=null;}}
function orderedPages(){return state.layout.menuOrder.map(id=>pages.find(p=>p[0]===id)).filter(Boolean).concat(topMenuIds.filter(id=>!state.layout.menuOrder.includes(id)).map(id=>pages.find(p=>p[0]===id)).filter(Boolean));} function isToolSubPage(id){return toolSubIds.includes(id);} 
function renderNav(){
 const nav=document.getElementById('nav'); nav.innerHTML='';
 orderedPages().filter(p=>!state.layout.menuHidden.includes(p[0])).forEach(p=>{
  const b=document.createElement('button');
  const toolActive=p[0]==='tools' && (state.activePage==='tools'||isToolSubPage(state.activePage));
  b.className='navbtn'+((state.activePage===p[0]||toolActive)?' active':'');
  b.dataset.page=p[0]; b.dataset.menuRow=p[0];
  b.innerHTML=`<span>${p[1]}</span><span>${esc(p[2])}</span>${p[0]==='tools'?`<span class="nav-arrow">${(state.toolsMenuOpen||toolActive)?'⌄':'›'}</span>`:''}`;
  b.onclick=e=>{if(p[0]==='tools'){state.toolsMenuOpen=!(state.toolsMenuOpen||toolActive); state.quickThemesOpen=false; renderAll();} else setPage(p[0]);};
  nav.appendChild(b);
  if(p[0]==='tools' && (state.toolsMenuOpen||toolActive)){
   const sub=document.createElement('div'); sub.className='submenu';
   const normal=toolSubPages.slice(0,7), subArea=toolSubPages.slice(7);
   sub.innerHTML=normal.map(sp=>`<button class="subnav ${state.activePage===sp[0]?'active':''}" data-gopage="${sp[0]}"><span>${sp[1]}</span><span>${esc(sp[2])}</span></button>`).join('')+`<div class="submenu-label">Substitute Area</div>`+subArea.map(sp=>`<button class="subnav ${state.activePage===sp[0]?'active':''}" data-gopage="${sp[0]}"><span>${sp[1]}</span><span>${esc(sp[2])}</span></button>`).join('');
   nav.appendChild(sub);
  }
 });
}
function renderMiniThemes(){const el=document.getElementById('quickThemePop'); if(!el)return; el.classList.toggle('open',!!state.quickThemesOpen); el.innerHTML=`<h4>Quick themes</h4><div class="mini-themes">${themeList.map(t=>`<button class="mini-swatch ${(!state.customTheme.enabled&&state.theme===t[0])?'active':''}" title="${esc(t[1])}" data-theme="${t[0]}" style="background:linear-gradient(135deg,${t[2]},${t[3]},${t[4]})"></button>`).join('')}</div><p class="tiny">Open Settings for custom colors.</p>`;}
function renderMenuPanel(){const mount=document.getElementById('menuPanelMount'); if(!state.showMenuSettings){mount.innerHTML='';return;} mount.innerHTML=`<div class="menu-panel"><div class="item-head"><div><b>Menu Layout</b><div class="tiny">Choose menu side, hide pages, or reset the menu.</div></div><button class="icon-btn" data-action="toggleMenuSettings">✕</button></div>${orderedPages().map(p=>`<div class="menu-list-row" data-menu-row="${p[0]}"><span class="nav-handle" draggable="true" title="Drag page">☰</span><span>${p[1]} ${esc(p[2])}</span><button class="small secondary" data-action="toggleMenuPage" data-page="${p[0]}">${state.layout.menuHidden.includes(p[0])?'Show':'Hide'}</button></div>`).join('')}<div class="actions"><button class="secondary" data-action="resetMenu">Reset menu</button></div></div>`;}

function renderPages(){
 const mount=document.getElementById('pages');
 if(!mount)return;
 try{
  mount.innerHTML=pages.map(p=>`<section id="page-${p[0]}" class="page ${state.activePage===p[0]?'active':''}" data-page-section="${p[0]}">${renderPage(p[0])}</section>`).join('');
 }catch(err){
  console.error('SOZY Workspace render error:',err);
  mount.innerHTML=`<section class="page active"><div class="plain-block"><h3>This page had a loading hiccup.</h3><p class="tiny">Your saved data should still be safe. Refresh once. If it happens again, export a backup from Settings and send a screenshot of this message.</p><pre class="tiny">${esc(err.message||String(err))}</pre></div></section>`;
 }
}
function renderPage(id){let html=(state.layout.openSettingsPage===id?pageSettingsPanel(id):''); switch(id){case 'dashboard':return html+dashboardPage();case 'planner':return html+plannerPage();case 'lessons':return html+lessonsPage();case 'gallery':return html+galleryPage();case 'grades':return html+gradesPage();case 'meetings':return html+meetingsPage();case 'standards':return html+standardsPage();case 'groups':return html+groupsPage();case 'timer':return html+timerPage();case 'reminders':return html+remindersPage();case 'map':return html+mapPage();case 'routines':return html+routinesOnlyPage();case 'supplies':return html+suppliesOnlyPage();case 'subnotes':return html+subnotesPage();case 'subreadiness':return html+subreadinessPage();case 'subexport':return html+subexportPage();case 'settings':return html+settingsPage();case 'tools':return toolsLandingPage();default:return html+dashboardPage();}}
function pageSettingsPanel(page){const ids=pageCards[page]||[]; const isDash=page==='dashboard'; return `<div class="layout-panel"><div class="item-head"><div><b>Layout settings for this page</b><div class="tiny">Drag boxes with ☰. Use − to collapse, ⛶ to focus, ↔ to resize. ${isDash?'Use × to remove dashboard boxes you do not want.':''}</div></div><button class="icon-btn" data-action="pageSettings">✕</button></div>${isDash?`<label>Dashboard look</label><select id="dashboardStyle" data-action="changeDashboardStyle"><option value="soft" ${state.layout.dashboardStyle==='soft'?'selected':''}>Cute color boxes</option><option value="cork" ${state.layout.dashboardStyle==='cork'?'selected':''}>Cork board</option><option value="data" ${state.layout.dashboardStyle==='data'?'selected':''}>Professional data dashboard</option></select><div class="archive-box"><b>Removed dashboard boxes</b>${state.layout.dashboardRemoved.length?state.layout.dashboardRemoved.map(id=>`<div class="item"><span>${esc((dashboardCards.find(c=>c[0]===id)||[])[1]||id)}</span><div class="actions"><button class="small secondary" data-action="restoreDashCard" data-card="${id}">Add back</button></div></div>`).join(''):empty('Nothing removed. Dashboard boxes stay visible unless you remove them here.')}</div>`:''}<div class="actions"><button class="secondary" data-action="resetPageLayout" data-page="${page}">Reset this page layout</button></div></div>`;}
function card(page,id,title,body,opts={}){if(page==='dashboard'&&state.layout.dashboardRemoved.includes(id))return''; const noControls=opts.controls===false; const noHeading=opts.heading===false||!title; const collapsed=!noControls&&state.layout.collapsed[page]?.includes(id); const max=!noControls&&state.layout.maximized[page]?.includes(id); const size=state.layout.sizes[page]?.[id]||opts.size||'md'; const remove=(!noControls&&page==='dashboard'&&state.layout.openSettingsPage==='dashboard')?`<button class="icon-btn" title="Remove from dashboard" aria-label="Remove from dashboard" data-action="removeDashCard" data-card="${id}">×</button>`:''; const controls=noControls?'':`<div class="drag-corner"><button class="icon-btn drag-handle" draggable="true" title="Drag this box" aria-label="Drag this box">☰</button></div><div class="card-tools"><button class="icon-btn" title="Collapse or open" aria-label="Collapse or open" data-action="toggleCollapse" data-page="${page}" data-card="${id}">${collapsed?'+':'−'}</button><button class="icon-btn" title="Resize box" aria-label="Resize box" data-action="resizeCard" data-page="${page}" data-card="${id}">↔</button><button class="icon-btn" title="Focus or restore" aria-label="Focus or restore" data-action="toggleMax" data-page="${page}" data-card="${id}">${max?'↙':'⛶'}</button>${remove}</div>`; return `<article id="card-${page}-${id}" class="card size-${size} ${collapsed?'collapsed':''} ${max?'maximized':''} ${noControls?'standalone-card no-resize':''}" data-card-id="${id}" data-page-card="${page}">${controls}${noHeading?'':`<h3>${title}</h3>`}<div class="card-body">${body}</div></article>`;}
function renderCards(page,defs,cls='grid two'){const order=state.layout.cardOrder[page]||defs.map(d=>d[0]); const map=Object.fromEntries(defs); const cards=order.filter(id=>map[id]).map(id=>map[id]).concat(defs.filter(d=>!order.includes(d[0])).map(d=>d[1])).join(''); return `<div class="${cls}" data-card-container="${page}">${cards}</div>`;}
function dashboardPage(){const rs=readinessScore(), gs=gradeStats(); const hero=`<section class="dashboard-hero"><div><h2>Your cozy classroom command center</h2><p>This workspace syncs your planner, lessons, grades, supplies, routines, reminders, and substitute readiness.</p></div><div class="actions"><button class="secondary" data-gopage="planner">Plan week</button><button class="secondary" data-gopage="grades">Open grades</button><button class="secondary" data-gopage="subexport">Prep substitute guide</button></div></section>`; const defs=[
 ['stats',card('dashboard','stats','📊 Today’s Numbers',`<div class="stat-grid"><div class="stat"><div class="num">${state.lessons.filter(l=>!l.archived).length}</div><div class="lbl">Lessons</div></div><div class="stat"><div class="num">${activeAssignments().length}</div><div class="lbl">Assignments</div></div><div class="stat"><div class="num">${state.todos.filter(t=>!t.done).length}</div><div class="lbl">Open tasks</div></div><div class="stat"><div class="num">${lowSupplies().length}</div><div class="lbl">Low supplies</div></div></div>`,{size:'lg'})],
 ['planner',card('dashboard','planner','🗓️ Weekly Plan',`${state.weekly.slice(0,5).map(w=>`<div class="item"><div class="item-title">${esc(w.day)} • ${esc(w.time)}</div><div class="item-meta">${esc(w.subject)} — ${esc(w.title)}</div></div>`).join('')||empty('No planner entries yet.')}<div class="actions"><button class="secondary" data-gopage="planner">Edit planner</button></div>`)],
 ['lessons',card('dashboard','lessons','📚 Current Lessons',`<div class="progressbar"><span style="width:${lessonReadyPct()}%"></span></div><p class="tiny">${lessonReadyPct()}% of lessons are marked sub-ready.</p>${state.lessons.filter(l=>!l.archived).slice(0,3).map(l=>`<div class="item"><div class="item-title">${esc(l.title)}</div><div class="item-meta">${esc(l.subject)} • ${esc(l.standard)} • ${l.subReady?'Sub-ready':'Needs prep'}</div></div>`).join('')}<div class="actions"><button class="secondary" data-gopage="lessons">Search lessons</button></div>`)],
 ['grades',card('dashboard','grades','📝 Grading progress',`<div class="stat-grid"><div class="stat"><div class="num">${gs.avgText}</div><div class="lbl">Class average</div></div><div class="stat"><div class="num">${gs.completion}%</div><div class="lbl">Scores entered</div></div></div><div class="progressbar" style="margin-top:10px"><span style="width:${gs.completion}%"></span></div><div class="mini-chart" style="margin-top:12px">${gradeBarsHtml()}</div><div class="actions"><button class="secondary" data-gopage="grades">Open gradebook</button></div>`,{size:'lg'})],
 ['tasks',card('dashboard','tasks','📌 Tasks & Reminders',`${state.todos.filter(t=>!t.done).slice(0,3).map(t=>`<div class="item"><div class="item-title">${esc(t.text)}</div><div class="item-meta">${esc(t.priority)} • last edited ${fmt(t.updatedAt)}</div></div>`).join('')||empty('No open tasks.')}<hr>${reminderList(2)}<div class="actions"><button class="secondary" data-gopage="meetings">Edit tasks</button><button class="secondary" data-gopage="reminders">Open reminders</button></div>`)],
 ['supplies',card('dashboard','supplies','🧻 Low supplies',`${lowSupplies().slice(0,4).map(s=>`<div class="item"><div class="item-title">${esc(s.item)}</div><div class="item-meta">Have ${esc(s.have)} / Need ${esc(s.need)} • ${esc(s.location)}</div></div>`).join('')||empty('No low supplies right now.')}<div class="actions"><button class="secondary" data-gopage="supplies">Edit supplies</button></div>`)],
 ['routines',card('dashboard','routines','✅ Routines',`<div class="progressbar"><span style="width:${routinePct()}%"></span></div><p class="tiny">${routinePct()}% checked today.</p>${state.routines.slice(0,4).map(r=>`<div class="item">${r.done?'✅':'⬜'} ${esc(r.text)}</div>`).join('')}<div class="actions"><button class="secondary" data-gopage="routines">Open routines</button></div>`)],
 ['readiness',card('dashboard','readiness','🧰 Substitute Readiness',`<div class="progressbar"><span style="width:${Math.round(rs.done/rs.total*100)}%"></span></div><p class="tiny">${rs.done} of ${rs.total} sub packet basics are ready.</p>${readinessList(true)}<div class="actions"><button class="secondary" data-gopage="subreadiness">Open checklist</button></div>`)],
 ['skills',card('dashboard','skills','📈 Skill progress',`${state.standards.slice(0,4).map(s=>`<div class="item"><div class="item-title">${esc(s.skill)}</div><div class="item-meta">${esc(s.subject)} • ${esc(s.standard)} • ${esc(s.progress)}%</div><div class="progressbar"><span style="width:${Number(s.progress)||0}%"></span></div></div>`).join('')||empty('No skills entered.')}<div class="actions"><button class="secondary" data-gopage="standards">Edit skills</button></div>`)]
 ]; return hero+dashboardCorkBoard()+`<div class="dashboard-shell style-${state.layout.dashboardStyle||'soft'}">${renderCards('dashboard',defs,'grid')}</div>`;}
function dashboardCorkBoard(){const showArch=!!state.showArchivedPins; const pins=(state.dashboardPins||[]).filter(p=>showArch?!!p.archived:!p.archived); const free=!!state.corkSettings?.freeMove; return `<div class="cork-toolbar"><button class="secondary" data-action="openPinModal">Add a Pin</button><button class="secondary" data-action="togglePinArchives">${showArch?'Hide archives':'View archives'}</button><button class="secondary" data-action="openCorkSettings">Cork Board Settings</button></div><section class="dashboard-cork ${state.corkSettings?.floralBorder?'floral':''}"><div class="pin-board ${free?'free':''}" data-pin-board>${pins.map((p,i)=>dashPinHtml(p,i,free)).join('')||empty(showArch?'No archived pins.':'No pins yet. Add a note, file, or photo highlight.')}</div></section>`;}
function dashPinHtml(p,i=0,free=false){const isPhoto=p.type==='photo', isFile=p.type==='file'; const title=esc(p.text||p.name||'Pinned item'); const x=Number.isFinite(+p.x)?+p.x:18+(i%5)*190, y=Number.isFinite(+p.y)?+p.y:22+Math.floor(i/5)*140, rot=Number.isFinite(+p.rot)?+p.rot:((i%5)-2)*2, z=Number.isFinite(+p.z)?+p.z:2+i; const style=free?` style="left:${x}px;top:${y}px;--pin-rot:${rot}deg;--pin-z:${z};"`:` style="--pin-rot:${rot}deg;--pin-z:${z};"`; return `<div class="dash-pin ${isPhoto?'photo':isFile?'file':'note'} ${p.archived?'archived':''}" tabindex="0" data-action="viewPin" data-id="${p.id}" data-pin-id="${p.id}"${style}><button class="pin-menu-btn" title="Pin options" aria-label="Pin options" data-action="togglePinMenu" data-id="${p.id}">⋯</button><div class="pin-menu"><button class="secondary" data-action="viewPin" data-id="${p.id}">View</button><button class="secondary" data-action="editPin" data-id="${p.id}">Edit</button><button class="secondary" data-action="downloadPin" data-id="${p.id}">Download</button><button class="secondary" data-action="rotatePin" data-id="${p.id}" data-dir="-8">Rotate left</button><button class="secondary" data-action="rotatePin" data-id="${p.id}" data-dir="8">Rotate right</button><button class="secondary" data-action="archivePin" data-id="${p.id}">${p.archived?'Unarchive':'Archive'}</button><button class="danger" data-action="deleteDashPin" data-id="${p.id}">Delete</button></div>${isPhoto?`<img src="${esc(p.img||p.dataUrl||'')}" alt="Pinned classroom highlight"><div class="tiny">${title}</div>`:isFile?`<div style="font-size:28px">📎</div><div>${title}</div><div class="tiny">${esc(p.fileName||p.name||'Attached file')}</div>`:`<div>${title}</div>`}<small>${p.archived?'Archived • ':''}${fmt(p.createdAt)}</small></div>`;}

function corkSettingsHtml(){const c=state.corkSettings||{}; return `<p class="tiny">Use this window to make the cork board feel more like a real classroom board.</p><label class="setting-row"><input type="checkbox" id="corkFreeMove" ${c.freeMove?'checked':''}> Let me move, overlap, and rotate pins anywhere on the board.</label><label class="setting-row"><input type="checkbox" id="corkFloralBorder" ${c.floralBorder!==false?'checked':''}> Keep the soft floral border on the cork board.</label><div class="tiny">Tip: when free move is on, drag a pin to move it. Use the pin’s ⋯ menu to rotate, edit, archive, download, or delete it.</div><div class="actions"><button data-action="saveCorkSettings">Save Cork Board Settings</button><button class="secondary" data-action="resetPinLayout">Reset pin layout</button></div>`;}
function renderCorkSettingsModal(){const modal=document.getElementById('corkSettingsModal'); if(!modal)return; modal.classList.toggle('open',!!state.corkSettingsOpen); const body=document.getElementById('corkSettingsBody'); if(body)body.innerHTML=corkSettingsHtml();}
function renderPinModal(){const modal=document.getElementById('pinModal'); if(!modal)return; modal.classList.toggle('open',!!state.pinModalOpen); const p=(state.dashboardPins||[]).find(x=>x.id===state.editingPinId); const title=modal.querySelector('h2'); if(title)title.textContent=p?'Edit Pin':'Add a Pin'; const note=document.getElementById('pinText'); if(note&&document.activeElement!==note)note.value=p?(p.text||''):'';}
function renderLessonModal(){const modal=document.getElementById('lessonModal'); if(!modal)return; modal.classList.toggle('open',!!state.lessonModalOpen); const body=document.getElementById('lessonModalBody'); if(body)body.innerHTML=lessonForm({});}
function weeklyForm(){return `<div class="formrow four"><div><label>Day</label><select id="wDay">${days().map(d=>`<option>${d}</option>`).join('')}</select></div><div><label>Time</label><input id="wTime" placeholder="8:30 AM"></div><div><label>Subject</label><input id="wSubject" placeholder="Reading"></div><div><label>Title</label><input id="wTitle" placeholder="Mini lesson"></div></div><label>Notes</label><textarea id="wNote" placeholder="What happens during this block?"></textarea><p class="tiny">Save the block first, then upload worksheets, slides, or notes from the saved block.</p><div class="actions"><button data-action="addWeekly">Save block</button><button class="secondary" data-action="closeWeeklyModal">Cancel</button></div>`;}
function renderWeeklyModal(){const modal=document.getElementById('weeklyModal'); if(!modal)return; modal.classList.toggle('open',!!state.weeklyModalOpen); const body=document.getElementById('weeklyModalBody'); if(body)body.innerHTML=weeklyForm();}
function plannerPage(){const defs=[['board',card('planner','board','🗓️ Weekly board',weeklyBoard(),{size:'lg'})],['shift',card('planner','shift','🚨 Schedule shifter',`<p class="tiny">Use this when an assembly, fire drill, testing, or surprise event pushes the day back.</p><div class="formrow four"><div><label>Day</label><select id="shiftDay">${days().map(d=>`<option>${d}</option>`).join('')}</select></div><div><label>Shift entries after</label><input id="shiftAfter" placeholder="10:00 AM"></div><div><label>Minutes</label><input id="shiftMin" type="number" value="15"></div><div><label>Direction</label><select id="shiftDir"><option value="1">Later</option><option value="-1">Earlier</option></select></div></div><div class="actions"><button data-action="shiftSchedule">Shift schedule</button></div>`)] ]; return `<div class="weekly-add-row"><button data-action="openWeeklyModal">➕ Add Weekly Block</button><button class="secondary" data-action="downloadWeeklyCsv">Download Weekly Plan</button></div>`+renderCards('planner',defs,'grid');}
function weeklyBoard(){return `<div class="schedule-board">${days().map(d=>`<div class="daycol"><h4>${d}</h4>${state.weekly.filter(w=>w.day===d).sort((a,b)=>parseTime(a.time)-parseTime(b.time)).map(weeklyCard).join('')||empty('No blocks yet.')}</div>`).join('')}</div>`;}
function attachmentCount(area,itemId){return (state.gallery||[]).filter(d=>d.area===area&&String(d.itemId||'')===String(itemId||'')).length;}
function attachmentIndicator(area,itemId){const n=attachmentCount(area,itemId); return n?`<button class="paperclip-btn entry-has-file" title="${n} attached file${n===1?'':'s'}" aria-label="Open ${n} attached file${n===1?'':'s'}" data-action="openGalleryForItem" data-area="${area}" data-id="${itemId}">📎</button>`:'';}
function weeklyAttachmentIcon(w){return attachmentIndicator('weekly',w.id);}
function weeklyCard(w){if(state.editing.weekly[w.id])return `<div class="schedule-card"><div class="formrow three"><div><label>Time</label><input id="ew_time_${w.id}" value="${esc(w.time)}"></div><div><label>Subject</label><input id="ew_subject_${w.id}" value="${esc(w.subject)}"></div><div><label>Title</label><input id="ew_title_${w.id}" value="${esc(w.title)}"></div></div><label>Notes</label><textarea id="ew_note_${w.id}">${esc(w.note)}</textarea><label>Last edited</label><input type="datetime-local" id="ew_updated_${w.id}" value="${toLocalInput(w.updatedAt)}">${attachmentPanel('weekly',w.id,w.title)}<div class="actions"><button class="small good" data-action="saveWeekly" data-id="${w.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="weekly" data-id="${w.id}">Cancel</button><button class="small danger" data-action="deleteWeekly" data-id="${w.id}">Delete</button></div></div>`; return `<div class="schedule-card with-paperclip">${weeklyAttachmentIcon(w)}<div class="item-head"><div><div class="item-title">${esc(w.time)} • ${esc(w.subject)}</div><div>${esc(w.title)}</div><div class="tiny">Last edited ${fmt(w.updatedAt)}</div></div><div class="compact-menu-wrap"><button class="icon-btn" title="Options" aria-label="Options">⋯</button><div class="compact-options"><button class="small secondary" data-action="viewWeekly" data-id="${w.id}">View details</button><button class="small secondary" data-action="editWeekly" data-id="${w.id}">Edit</button><button class="small secondary" data-action="openGalleryForItem" data-area="weekly" data-id="${w.id}">Attachments</button><button class="small danger" data-action="deleteWeekly" data-id="${w.id}">Delete</button></div></div></div></div>`;}
function lessonsPage(){return `<div class="plain-block"><div class="searchbar"><input id="lessonSearchInput" value="${esc(state.currentLessonSearch)}" placeholder="Search lessons by subject, standard, reading level, theme, title, or support notes..."><button class="secondary" data-action="clearLessonSearch">Clear</button></div><div class="tiny search-tip-inline">Tip: Search results below are clickable.</div><div id="lessonSearchResults">${lessonSearchResults()}</div></div>`+renderCards('lessons',[['lessonList',card('lessons','lessonList','📚 Saved lesson plans',lessonList(),{size:'lg',controls:false})]],'grid');}
function lessonForm(l={}){const edit=!!l.id; return `<div class="formrow three"><div><label>Title</label><input id="${edit?'el':'l'}Title" value="${esc(l.title||'')}" placeholder="Lesson title"></div><div><label>Subject</label><input id="${edit?'el':'l'}Subject" value="${esc(l.subject||'')}" placeholder="Reading, Math..."></div><div><label>Standard</label><input id="${edit?'el':'l'}Standard" value="${esc(l.standard||'')}" placeholder="RI.3.1"></div></div><div class="formrow three"><div><label>Reading level</label><input id="${edit?'el':'l'}Lexile" value="${esc(l.lexile||'')}" placeholder="520L"></div><div><label>Theme</label><input id="${edit?'el':'l'}Theme" value="${esc(l.theme||'')}" placeholder="Dinosaurs"></div><div><label>Sub-ready?</label><select id="${edit?'el':'l'}Sub"><option value="false" ${!l.subReady?'selected':''}>Needs prep</option><option value="true" ${l.subReady?'selected':''}>Sub-ready</option></select></div></div><label>Lesson summary</label><textarea id="${edit?'el':'l'}Summary" placeholder="Explain what students do.">${esc(l.summary||'')}</textarea><label>Differentiation / support notes</label><textarea id="${edit?'el':'l'}Diff" placeholder="Small group notes, sentence frames, challenge options, accommodations...">${esc(l.diff||'')}</textarea>${edit?`${attachmentPanel('lessons',l.id,l.title)}<label>Last edited</label><input type="datetime-local" id="elUpdated" value="${toLocalInput(l.updatedAt)}"><div class="actions"><button class="good" data-action="saveLesson" data-id="${l.id}">Save</button><button class="secondary" data-action="cancelEdit" data-type="lessons" data-id="${l.id}">Cancel</button></div>`:`<p class="tiny">Save the lesson first, then upload worksheets, slides, photos, or PDFs from the saved lesson.</p><div class="actions"><button data-action="addLesson">Save lesson</button></div>`}`;}
function lessonList(){let lessons=state.lessons.filter(l=>!l.archived); const filter=state.lessonFilter||'all'; if(filter==='ready')lessons=lessons.filter(l=>l.subReady); else if(filter==='prep')lessons=lessons.filter(l=>!l.subReady); else if(filter!=='all')lessons=lessons.filter(l=>(l.subject||'').toLowerCase()===filter.toLowerCase()); const sort=state.lessonSort||'updated'; lessons=[...lessons].sort((a,b)=>{if(sort==='title')return (a.title||'').localeCompare(b.title||''); if(sort==='subject')return (a.subject||'').localeCompare(b.subject||'')||(a.title||'').localeCompare(b.title||''); if(sort==='status')return Number(b.subReady)-Number(a.subReady)||(a.title||'').localeCompare(b.title||''); return new Date(b.updatedAt||0)-new Date(a.updatedAt||0);}); const subjects=[...new Set(state.lessons.filter(l=>!l.archived).map(l=>l.subject).filter(Boolean))].sort(); return `<div class="lesson-list-toolbar"><button data-action="openLessonModal">➕ Add lesson plan</button><div><label>Filter saved lessons</label><select id="savedLessonFilter"><option value="all" ${filter==='all'?'selected':''}>All lessons</option><option value="ready" ${filter==='ready'?'selected':''}>Sub-ready only</option><option value="prep" ${filter==='prep'?'selected':''}>Needs prep only</option>${subjects.map(s=>`<option value="${esc(s)}" ${filter===s?'selected':''}>${esc(s)}</option>`).join('')}</select></div><div><label>Order lessons</label><select id="savedLessonSort"><option value="updated" ${sort==='updated'?'selected':''}>Newest edited first</option><option value="title" ${sort==='title'?'selected':''}>A to Z title</option><option value="subject" ${sort==='subject'?'selected':''}>Subject</option><option value="status" ${sort==='status'?'selected':''}>Sub-ready first</option></select></div><div><label>Shown</label><div class="pill">${lessons.length} lessons</div></div></div>`+(lessons.map(l=>state.editing.lessons[l.id]?`<div class="item" data-edit-lesson="${l.id}">${lessonForm(l)}</div>`:`<div class="item with-paperclip">${attachmentIndicator('lessons',l.id)}<div class="item-title-row"><div class="item-title">${esc(l.title)}</div><span class="pill ${l.subReady?'good':'warn'}">${l.subReady?'Sub-ready':'Needs prep'}</span></div><div class="item-meta">${esc(l.subject)} • ${esc(l.standard)} • Level ${esc(l.lexile||'n/a')} • Theme: ${esc(l.theme||'none')} • Last edited ${fmt(l.updatedAt)}</div><p class="tiny">${esc(l.summary)}</p><div class="entry-actions"><button class="small secondary" data-action="editLesson" data-id="${l.id}">Edit</button><button class="small danger delete-right" data-action="deleteLesson" data-id="${l.id}">Delete</button></div></div>`).join('')||empty('No lessons match this filter.'));}
function docSize(bytes){bytes=Number(bytes)||0; if(bytes<1024)return bytes+' B'; if(bytes<1024*1024)return Math.round(bytes/1024)+' KB'; return (bytes/1024/1024).toFixed(1)+' MB';}
function docIcon(type,name){type=type||''; name=name||''; if(type.startsWith('image/'))return '🖼️'; if(type.includes('pdf')||name.toLowerCase().endsWith('.pdf'))return '📄'; if(type.includes('sheet')||/\.csv|\.xlsx/i.test(name))return '📊'; if(type.includes('word')||/\.docx?/i.test(name))return '📝'; return '📎';}
function attachmentPanel(area,itemId,label){const docs=docsFor(area,itemId); return `<div class="attach-panel"><div class="attach-head"><b>📎 Files</b><span class="tiny">${docs.length} attached</span></div><div class="attach-list">${docs.map(d=>docMini(d)).join('')||'<span class="tiny">No files attached yet.</span>'}</div><label class="file-button">+ Upload file<input type="file" multiple data-attach-area="'+area+'" data-attach-id="'+itemId+'" data-attach-label="'+esc(label||linkedItemLabel(area,itemId))+'"></label></div>`;}
function docMini(d){return `<span class="doc-chip" title="${esc(d.name)}"><span>${docIcon(d.type,d.name)}</span><a href="${d.dataUrl}" download="${esc(d.name)}">${esc(d.name)}</a><button class="mini-x" data-action="deleteGalleryDoc" data-id="${d.id}" title="Remove file">×</button></span>`;}
function galleryPage(){return `<div class="gallery-upload-inline">${galleryUploadHtml()}</div>`+renderCards('gallery',[["galleryList",card('gallery','galleryList','🖼️ Gallery library',galleryListHtml(),{size:'lg'})]],'grid');}
function galleryUploadHtml(){return `<p class="tiny">Gallery is the local document library. Files attached inside planner, lessons, grades, meetings, to-dos, and standards also appear here. Keep backups private because attached files are part of your app save data.</p><div class="actions"><label class="file-button big-file">+ Upload general files<input type="file" multiple data-attach-area="general" data-attach-id="" data-attach-label="Gallery upload"></label></div><div class="archive-box"><b>Plain-English note</b><p class="tiny">Small PDFs, images, worksheets, and notes can be saved inside this browser. Very large files may make your browser backup too big, so use small files when possible.</p></div>`;}
function galleryListHtml(){const q=(state.gallerySearch||'').toLowerCase().trim(); const filter=state.galleryFilter||'all'; let docs=[...(state.gallery||[])]; const seen=new Set(); docs=docs.filter(d=>{const key=[d.name||'',d.size||'',d.area||'',d.itemId||'',d.dataUrl||''].join('|'); if(seen.has(key))return false; seen.add(key); return true;}); if(filter!=='all')docs=docs.filter(d=>d.area===filter); if(q)docs=docs.filter(d=>[d.name,d.area,d.label,d.note,areaName(d.area),linkedItemLabel(d.area,d.itemId)].join(' ').toLowerCase().includes(q)); docs.sort((a,b)=>new Date(b.updatedAt||b.createdAt||0)-new Date(a.updatedAt||a.createdAt||0)); const opts=['all','general','weekly','lessons','students','assignments','meetings','todos','standards']; return `<div class="filterbar"><div><label>Search Gallery</label><input id="gallerySearchInput" value="${esc(state.gallerySearch)}" placeholder="Search file name, page, lesson, student, task..."></div><div><label>Filter</label><select id="galleryFilter">${opts.map(o=>`<option value="${o}" ${filter===o?'selected':''}>${o==='all'?'All files':areaName(o)}</option>`).join('')}</select></div><div><label>Total</label><div class="pill">${docs.length} file${docs.length===1?'':'s'}</div></div><div><label>Tip</label><div class="tiny">Click Open to view or download. Click Go to jump to the linked page.</div></div></div><div class="gallery-grid">${docs.map(galleryDocHtml).join('')||empty('No files in Gallery yet.')}</div>`;}
function galleryDocHtml(d){const isImg=(d.type||'').startsWith('image/'); return `<div class="gallery-doc"><div class="gallery-thumb">${isImg?`<img src="${d.dataUrl}" alt="${esc(d.name)}">`:`<span>${docIcon(d.type,d.name)}</span>`}</div><div class="item-title">${esc(d.name)}</div><div class="item-meta">${areaName(d.area)}${d.itemId?' • '+esc(d.label||linkedItemLabel(d.area,d.itemId)):''} • ${docSize(d.size)} • Added ${fmt(d.createdAt)}</div><div class="actions"><a class="buttonlike small" href="${d.dataUrl}" download="${esc(d.name)}">Open</a>${d.area&&d.area!=='general'?`<button class="small secondary" data-gopage="${areaToPage(d.area)}" data-gocard="${areaToCard(d.area)}">Go</button>`:''}<button class="small danger" data-action="deleteGalleryDoc" data-id="${d.id}">Delete</button></div></div>`;}


function gradesPage(){const defs=[['gradeStats',card('grades','gradeStats','📊 Grade dashboard',gradeDashboardHtml(),{size:'lg',controls:false})],['students',card('grades','students','👧 Students',studentsHtml())],['assignments',card('grades','assignments','🧾 Assignments',assignmentsHtml())],['gradebook',card('grades','gradebook','📝 Gradebook table',gradebookHtml(),{size:'lg'})],['exports',card('grades','exports','📤 Exports',`<p class="tiny">Use these when you need a local copy for your own records. Keep exports private.</p><div class="actions"><button data-action="downloadGradesCsv">Download grades CSV</button><button class="secondary" data-action="downloadStudentsCsv">Download student list CSV</button><button class="secondary" data-action="printGrades">Print grade summary</button><button class="secondary" data-action="toggleGradeArchives">${state.gradeViewArchives?'Hide archives':'View archives'}</button></div>${state.gradeViewArchives?gradeArchivesHtml():''}`)]]; return renderCards('grades',defs,'grid');}
function gradeDashboardHtml(){const gs=gradeStats(); return `<div class="stat-grid"><div class="stat"><div class="num">${gs.avgText}</div><div class="lbl">Class average</div></div><div class="stat"><div class="num">${gs.completion}%</div><div class="lbl">Scores entered</div></div><div class="stat"><div class="num">${gs.missing}</div><div class="lbl">Missing</div></div><div class="stat"><div class="num">${activeStudents().length}</div><div class="lbl">Students</div></div></div><div class="progressbar" style="margin-top:12px"><span style="width:${gs.completion}%"></span></div><p class="tiny">This tab is for lesson planning + student grading. It saves locally on this device.</p><div class="mini-chart">${gradeBarsHtml()}</div>`;}
function studentsHtml(){return `<div class="formrow three"><div><label>Student first name or nickname</label><input id="studentName" placeholder="Avery"></div><div><label>Status</label><select id="studentStatus"><option>Active</option><option>Needs support</option><option>Monitor</option></select></div><div><label>Notes</label><input id="studentNotes" placeholder="Optional teacher notes"></div></div><div class="actions"><button data-action="addStudent">Add student</button></div>${state.students.filter(s=>!s.archived).map(studentRow).join('')||empty('No students yet. Add first names or nicknames only if you want extra privacy.')}`;}
function studentRow(s){if(state.editing.students[s.id])return `<div class="item"><div class="formrow three"><div><label>Name</label><input id="es_name_${s.id}" value="${esc(s.name)}"></div><div><label>Status</label><input id="es_status_${s.id}" value="${esc(s.status)}"></div><div><label>Notes</label><input id="es_notes_${s.id}" value="${esc(s.notes)}"></div></div><label>Last edited</label><input type="datetime-local" id="es_time_${s.id}" value="${toLocalInput(s.updatedAt)}">${attachmentPanel('students',s.id,s.name)}<div class="actions"><button class="small good" data-action="saveStudent" data-id="${s.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="students" data-id="${s.id}">Cancel</button></div></div>`; return `<div class="item with-paperclip">${attachmentIndicator('students',s.id)}<div class="item-head"><div><div class="item-title">${esc(s.name)}</div><div class="item-meta">${esc(s.status)} • ${esc(s.notes)} • Last edited ${fmt(s.updatedAt)}</div></div><span>${gradeBadge(studentAverage(s.id))}</span></div><div class="entry-actions"><button class="small secondary" data-action="editStudent" data-id="${s.id}">Edit</button><button class="small secondary" data-action="archiveStudent" data-id="${s.id}">Archive</button><button class="small danger delete-right" data-action="deleteStudent" data-id="${s.id}">Delete</button></div></div>`;}
function assignmentsHtml(){return `<div class="formrow four"><div><label>Assignment</label><input id="assignmentTitle" placeholder="Reading check"></div><div><label>Subject</label><input id="assignmentSubject" placeholder="Reading"></div><div><label>Category</label><select id="assignmentCategory"><option>Classwork</option><option>Homework</option><option>Quiz</option><option>Test</option><option>Project</option><option>Participation</option></select></div><div><label>Points</label><input id="assignmentPoints" type="number" value="10"></div></div><div class="formrow two"><div><label>Date</label><input id="assignmentDate" type="date" value="${new Date().toISOString().slice(0,10)}"></div><div><label>Link to lesson</label><select id="assignmentLesson"><option value="">No lesson link</option>${state.lessons.filter(l=>!l.archived).map(l=>`<option value="${l.id}">${esc(l.title)}</option>`).join('')}</select></div></div><p class="tiny">After you add an assignment, you can attach rubrics, answer keys, worksheets, or examples to that saved assignment.</p><div class="actions"><button data-action="addAssignment">Add assignment</button></div>${activeAssignments().map(assignmentRow).join('')||empty('No assignments yet.')}`;}
function assignmentRow(a){if(state.editing.assignments[a.id])return `<div class="item"><div class="formrow four"><div><label>Title</label><input id="ea_title_${a.id}" value="${esc(a.title)}"></div><div><label>Subject</label><input id="ea_subject_${a.id}" value="${esc(a.subject)}"></div><div><label>Category</label><input id="ea_category_${a.id}" value="${esc(a.category)}"></div><div><label>Points</label><input id="ea_points_${a.id}" type="number" value="${esc(a.points)}"></div></div><div class="formrow two"><div><label>Date</label><input id="ea_date_${a.id}" type="date" value="${esc(a.date)}"></div><div><label>Last edited</label><input id="ea_time_${a.id}" type="datetime-local" value="${toLocalInput(a.updatedAt)}"></div></div>${attachmentPanel('assignments',a.id,a.title)}<div class="actions"><button class="small good" data-action="saveAssignment" data-id="${a.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="assignments" data-id="${a.id}">Cancel</button></div></div>`; const linked=state.lessons.find(l=>l.id===a.lessonId); return `<div class="item with-paperclip">${attachmentIndicator('assignments',a.id)}<div class="item-title">${esc(a.title)}</div><div class="item-meta">${esc(a.subject)} • ${esc(a.category)} • ${esc(a.points)} pts • ${esc(a.date)} ${linked?'• Lesson: '+esc(linked.title):''} • Last edited ${fmt(a.updatedAt)}</div><div class="entry-actions"><button class="small secondary" data-action="editAssignment" data-id="${a.id}">Edit</button><button class="small secondary" data-action="archiveAssignment" data-id="${a.id}">Archive</button><button class="small danger delete-right" data-action="deleteAssignment" data-id="${a.id}">Delete</button></div></div>`;}
function gradebookHtml(){const st=activeStudents(), as=activeAssignments(); if(!st.length||!as.length)return empty('Add students and assignments first. Then the gradebook table appears here.'); return `<p class="tiny">Type scores directly in the boxes. Use M for missing and X for excused. Every score gets a timestamp when saved.</p><div class="grade-table-wrap"><table class="grade-table"><thead><tr><th>Student</th>${as.map(a=>`<th>${esc(a.title)}<div class="tiny">${esc(a.points)} pts</div></th>`).join('')}<th>Average</th></tr></thead><tbody>${st.map(s=>`<tr><td class="student-cell">${esc(s.name)}<div class="tiny">${esc(s.status)}</div></td>${as.map(a=>scoreCell(s,a)).join('')}<td>${gradeBadge(studentAverage(s.id))}</td></tr>`).join('')}</tbody></table></div>`;}
function scoreCell(s,a){const key=s.id+'_'+a.id; const sc=state.scores[key]||{}; return `<td><input type="text" value="${esc(sc.missing?'M':sc.excused?'X':(sc.score??''))}" data-score="${key}" data-student="${s.id}" data-assignment="${a.id}" placeholder="0-${esc(a.points)}"><div class="tiny">${sc.updatedAt?'Saved '+fmt(sc.updatedAt):'Not entered'}</div></td>`;}
function gradeArchivesHtml(){const ss=state.students.filter(s=>s.archived), aa=state.assignments.filter(a=>a.archived); return `<div class="archive-box"><b>Archived students</b>${ss.map(s=>`<div class="item">${esc(s.name)} <button class="small secondary" data-action="restoreStudent" data-id="${s.id}">Restore</button></div>`).join('')||empty('No archived students.')}</div><div class="archive-box"><b>Archived assignments</b>${aa.map(a=>`<div class="item">${esc(a.title)} <button class="small secondary" data-action="restoreAssignment" data-id="${a.id}">Restore</button></div>`).join('')||empty('No archived assignments.')}</div>`;}
function centersPage(){const defs=[['groupMaker',card('centers','groupMaker','👥 Group generator',`<p class="tiny">Paste first names or nicknames. The generated groups will show the names so the teacher can actually use them.</p><div class="split"><div><label>Student names</label><textarea id="studentNames" placeholder="Avery, Mia, Leo, Sam"></textarea></div><div><label>Number of groups</label><input id="groupCount" type="number" value="3"><div class="actions"><button data-action="makeGroups">Make groups</button></div><div class="groups">${renderGroups()}</div></div></div>`,{size:'lg'})],['timer',card('centers','timer','⏱️ Center timer',`<div class="timer-display" id="timerDisplay">00:00</div><div class="formrow three"><div><label>Minutes</label><input id="timerMinutes" type="number" value="10"></div><div><label>Sound</label><select id="quickSound"><option value="chime">Chime</option><option value="bell">Bell</option><option value="ding">Ding</option><option value="soft">Soft</option></select></div><div><label>Volume</label><input id="quickVolume" type="range" min="0" max="1" step="0.05" value="${state.notificationSettings.volume}"></div></div><div class="actions"><button data-action="startTimer">Start</button><button class="secondary" data-action="pauseTimer">Pause</button><button class="secondary" data-action="resetTimer">Reset</button><button class="secondary" data-action="testSound">Test sound</button></div>`,{size:'lg'})]]; return renderCards('centers',defs,'grid');}
function meetingsPage(){return `<div class="meetings-columns"><section>${card('meetings','meetingForm','🗒️ Meeting Notes',meetingHtml(),{size:'lg',controls:false})}</section><section>${card('meetings','todoList','✅ To-Dos',todoHtml(),{size:'lg',controls:false})}</section></div>`;}
function meetingHtml(){let notes=[...state.meetings]; const q=(state.meetingFilter||'').toLowerCase().trim(); if(q)notes=notes.filter(m=>[m.title,m.date,m.notes].join(' ').toLowerCase().includes(q)); const order=state.meetingOrder||'received'; notes.sort((a,b)=>{if(order==='newest')return new Date(b.createdAt||b.date||0)-new Date(a.createdAt||a.date||0); if(order==='title')return (a.title||'').localeCompare(b.title||''); return new Date(a.createdAt||a.date||0)-new Date(b.createdAt||b.date||0);}); const form=state.showMeetingForm?`<div class="meet-add-panel"><div class="formrow two"><div><label>Meeting title</label><input id="meetingTitle" placeholder="IEP meeting, grade-level planning..."></div><div><label>Date</label><input id="meetingDate" type="date" value="${new Date().toISOString().slice(0,10)}"></div></div><label>Notes</label><textarea id="meetingNotes" placeholder="What was decided? What needs follow-up?"></textarea><p class="tiny">After saving a meeting note, you can attach agendas, PDFs, screenshots, or forms in edit mode.</p><div class="actions"><button data-action="addMeeting">Save meeting note</button><button class="secondary" data-action="toggleMeetingForm">Cancel</button></div></div>`:''; return `<button data-action="toggleMeetingForm">➕ Add Meeting Note</button>${form}<div class="meeting-history-head"><h4>Meeting Notes History</h4><span class="pill">${notes.length} note${notes.length===1?'':'s'}</span></div><div class="meeting-controls"><input id="meetingFilterInput" value="${esc(state.meetingFilter||'')}" placeholder="Filter meeting notes..."><select id="meetingOrder"><option value="received" ${order==='received'?'selected':''}>Oldest received first</option><option value="newest" ${order==='newest'?'selected':''}>Newest first</option><option value="title" ${order==='title'?'selected':''}>Title A to Z</option></select></div><div class="meeting-list">${notes.map(m=>meetingRow(m)).join('')||empty('No meeting notes yet.')}</div>`;}
function meetingRow(m){if(state.editing.meetings[m.id])return `<div class="item"><div class="formrow two"><div><label>Title</label><input id="em_title_${m.id}" value="${esc(m.title)}"></div><div><label>Date</label><input id="em_date_${m.id}" type="date" value="${esc(m.date)}"></div></div><label>Notes</label><textarea id="em_notes_${m.id}">${esc(m.notes)}</textarea><label>Last edited</label><input type="datetime-local" id="em_time_${m.id}" value="${toLocalInput(m.updatedAt)}">${attachmentPanel('meetings',m.id,m.title)}<div class="actions"><button class="small good" data-action="saveMeeting" data-id="${m.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="meetings" data-id="${m.id}">Cancel</button></div></div>`; return `<div class="item with-paperclip">${attachmentIndicator('meetings',m.id)}<div class="item-title">${esc(m.title)}</div><div class="item-meta">${esc(m.date)} • Last edited ${fmt(m.updatedAt)}</div><p class="tiny">${esc(m.notes)}</p><div class="entry-actions"><button class="small secondary" data-action="editMeeting" data-id="${m.id}">Edit</button><button class="small danger delete-right" data-action="deleteMeeting" data-id="${m.id}">Delete</button></div></div>`;}
function todoHtml(){const order={High:0,Medium:1,Low:2}; const show=!!state.todoViewArchives; const tasks=[...state.todos].filter(t=>show?!!t.archived:!t.archived).sort((a,b)=>(order[a.priority]??9)-(order[b.priority]??9)||Number(a.done)-Number(b.done)||new Date(a.createdAt||0)-new Date(b.createdAt||0)); return `<div class="formrow three"><div><label>Task</label><input id="todoText" placeholder="Prep copies"></div><div><label>Priority</label><select id="todoPriority"><option>Low</option><option selected>Medium</option><option>High</option></select></div><div><label>&nbsp;</label><button data-action="addTodo">Add task</button></div></div><p class="tiny">After adding a task, you can attach files in edit mode. High = red, Medium = yellow, Low = green.</p><div class="actions"><button class="secondary" data-action="toggleTodoArchives">${show?'Hide archived tasks':'View archived tasks'}</button></div><div class="todo-list">${tasks.map(todoRow).join('')||empty(show?'No archived tasks.':'No tasks yet.')}</div>`;}
function priorityClass(p){p=(p||'').toLowerCase(); return p.includes('high')?'high':p.includes('low')?'low':'medium';}
function todoRow(t){if(state.editing.todos[t.id])return `<div class="item"><div class="formrow three"><div><label>Task</label><input id="et_text_${t.id}" value="${esc(t.text)}"></div><div><label>Priority</label><select id="et_priority_${t.id}"><option ${t.priority==='Low'?'selected':''}>Low</option><option ${t.priority==='Medium'?'selected':''}>Medium</option><option ${t.priority==='High'?'selected':''}>High</option></select></div><div><label>Last edited</label><input type="datetime-local" id="et_time_${t.id}" value="${toLocalInput(t.updatedAt)}"></div></div>${attachmentPanel('todos',t.id,t.text)}<div class="actions"><button class="small good" data-action="saveTodo" data-id="${t.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="todos" data-id="${t.id}">Cancel</button></div></div>`; return `<div class="item with-paperclip">${attachmentIndicator('todos',t.id)}<div class="item-head"><div><div class="item-title">${t.done?'✅':'⬜'} ${esc(t.text)}</div><div class="item-meta"><span class="priority-pill ${priorityClass(t.priority)}">${esc(t.priority||'Medium')}</span> • Last edited ${fmt(t.updatedAt)} ${t.archived?'• Archived':''}</div></div></div><div class="todo-actions"><button class="small secondary" data-action="toggleTodo" data-id="${t.id}">${t.done?'Reopen':'Done'}</button><button class="small secondary" data-action="editTodo" data-id="${t.id}">Edit</button><button class="small secondary" data-action="archiveTodo" data-id="${t.id}">${t.archived?'Restore':'Archive'}</button><button class="small danger" data-action="deleteTodo" data-id="${t.id}">Delete</button></div></div>`;}
function remindersHtml(){return `<div class="formrow three"><div><label>Reminder title</label><input id="remTitle" placeholder="Switch groups"></div><div><label>Date and time</label><input id="remTime" type="datetime-local"></div><div><label>Category</label><input id="remCategory" placeholder="Centers"></div></div><label>Note</label><input id="remNote" placeholder="Optional note"><div class="actions"><button data-action="addReminder">Add reminder</button><button class="secondary" data-action="requestNotifications">Allow notifications</button></div>${state.reminders.map(reminderRow).join('')||empty('No reminders yet.')}`;}
function reminderRow(r){if(state.editing.reminders[r.id])return `<div class="item"><div class="formrow three"><div><label>Title</label><input id="er_title_${r.id}" value="${esc(r.title)}"></div><div><label>Time</label><input id="er_time_${r.id}" type="datetime-local" value="${toLocalInput(r.time)}"></div><div><label>Category</label><input id="er_cat_${r.id}" value="${esc(r.category)}"></div></div><label>Note</label><input id="er_note_${r.id}" value="${esc(r.note)}"><label>Last edited</label><input type="datetime-local" id="er_updated_${r.id}" value="${toLocalInput(r.updatedAt)}"><div class="actions"><button class="small good" data-action="saveReminder" data-id="${r.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="reminders" data-id="${r.id}">Cancel</button></div></div>`; return `<div class="item ${(!r.done&&new Date(r.time)<=new Date())?'reminder-due':''}"><div class="item-title">${r.done?'✅':'🔔'} ${esc(r.title)}</div><div class="item-meta">${fmt(r.time)} • ${esc(r.category||'General')} • ${esc(r.note||'')} • Last edited ${fmt(r.updatedAt)}</div><div class="entry-actions"><button class="small secondary" data-action="toggleReminder" data-id="${r.id}">${r.done?'Reopen':'Done'}</button><button class="small secondary" data-action="editReminder" data-id="${r.id}">Edit</button><button class="small danger delete-right" data-action="deleteReminder" data-id="${r.id}">Delete</button></div></div>`;}
function reminderList(limit){const arr=[...state.reminders].sort((a,b)=>new Date(a.time)-new Date(b.time)); return arr.slice(0,limit||arr.length).map(r=>`<div class="item"><div class="item-title">${r.done?'✅':'🔔'} ${esc(r.title)}</div><div class="item-meta">${fmt(r.time)} • ${esc(r.category||'General')}</div></div>`).join('')||empty('No reminders.');}
function notificationHtml(){return `<p class="tiny">Notifications and sounds are optional. They work best while the app is open or allowed by the browser.</p><div class="formrow four"><div><label>Notifications</label><select id="notEnabled"><option value="false" ${!state.notificationSettings.enabled?'selected':''}>Off</option><option value="true" ${state.notificationSettings.enabled?'selected':''}>On</option></select></div><div><label>Sound</label><select id="soundEnabled"><option value="true" ${state.notificationSettings.sound?'selected':''}>On</option><option value="false" ${!state.notificationSettings.sound?'selected':''}>Off</option></select></div><div><label>Sound type</label><select id="soundType"><option ${state.notificationSettings.soundType==='chime'?'selected':''}>chime</option><option ${state.notificationSettings.soundType==='bell'?'selected':''}>bell</option><option ${state.notificationSettings.soundType==='ding'?'selected':''}>ding</option><option ${state.notificationSettings.soundType==='soft'?'selected':''}>soft</option></select></div><div><label>Volume</label><input id="soundVolume" type="range" min="0" max="1" step="0.05" value="${state.notificationSettings.volume}"></div></div><div class="actions"><button data-action="saveNotificationSettings">Save settings</button><button class="secondary" data-action="testSound">Test sound</button><button class="secondary" data-action="testNotification">Test notification</button></div>`;}
function routinesPage(){const defs=[['routines',card('routines','routines','✅ Classroom routines checklist',routinesHtml())],['supplies',card('routines','supplies','🧻 Supplies tracker',suppliesHtml(),{size:'lg'})]]; return renderCards('routines',defs,'grid');}
function routinesHtml(){return `<div class="formrow two"><div><label>Routine item</label><input id="routineText" placeholder="Post visual schedule"></div><div><label>&nbsp;</label><button data-action="addRoutine">Add routine</button></div></div>${state.routines.map(routineRow).join('')||empty('No routines yet.')}`;}
function routineRow(r){if(state.editing.routines[r.id])return `<div class="item"><label>Routine</label><input id="erou_text_${r.id}" value="${esc(r.text)}"><label>Last edited</label><input type="datetime-local" id="erou_time_${r.id}" value="${toLocalInput(r.updatedAt)}"><div class="actions"><button class="small good" data-action="saveRoutine" data-id="${r.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="routines" data-id="${r.id}">Cancel</button></div></div>`; return `<div class="item"><div class="item-title">${r.done?'✅':'⬜'} ${esc(r.text)}</div><div class="item-meta">Last edited ${fmt(r.updatedAt)}</div><div class="entry-actions"><button class="small secondary" data-action="toggleRoutine" data-id="${r.id}">${r.done?'Uncheck':'Check'}</button><button class="small secondary" data-action="editRoutine" data-id="${r.id}">Edit</button><button class="small danger delete-right" data-action="deleteRoutine" data-id="${r.id}">Delete</button></div></div>`;}
function suppliesHtml(){const active=state.supplies.filter(s=>!s.archived), arch=state.supplies.filter(s=>s.archived); return `<div class="formrow four"><div><label>Item</label><input id="sItem" placeholder="Glue sticks"></div><div><label>Have</label><input id="sHave" type="number" value="0"></div><div><label>Need</label><input id="sNeed" type="number" value="0"></div><div><label>Location</label><input id="sLocation" placeholder="Cabinet"></div></div><label>Note</label><input id="sNote" placeholder="Optional note"><div class="actions"><button data-action="addSupply">Add supply</button><button class="secondary" data-action="toggleSupplyArchives">${state.supplyViewArchives?'Hide archives':'View archives'}</button></div>${active.map(supplyRow).join('')||empty('No active supplies saved.')} ${state.supplyViewArchives?`<div class="archive-box"><b>Archived supplies</b>${arch.map(s=>`<div class="item"><span>${esc(s.item)}</span><div class="actions"><button class="small secondary" data-action="restoreSupply" data-id="${s.id}">Restore</button><button class="small danger" data-action="deleteSupply" data-id="${s.id}">Delete forever</button></div></div>`).join('')||empty('No archived supplies.')}</div>`:''}`;}
function supplyRow(s){if(state.editing.supplies[s.id])return `<div class="item"><div class="formrow four"><div><label>Item</label><input id="esu_item_${s.id}" value="${esc(s.item)}"></div><div><label>Have</label><input id="esu_have_${s.id}" type="number" value="${esc(s.have)}"></div><div><label>Need</label><input id="esu_need_${s.id}" type="number" value="${esc(s.need)}"></div><div><label>Location</label><input id="esu_loc_${s.id}" value="${esc(s.location)}"></div></div><label>Note</label><input id="esu_note_${s.id}" value="${esc(s.note)}"><label>Last edited</label><input type="datetime-local" id="esu_time_${s.id}" value="${toLocalInput(s.updatedAt)}"><div class="actions"><button class="small good" data-action="saveSupply" data-id="${s.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="supplies" data-id="${s.id}">Cancel</button></div></div>`; return `<div class="item"><div class="item-head"><div><div class="item-title">${Number(s.have)<Number(s.need)?'⚠️ ':''}${esc(s.item)}</div><div class="item-meta">Have ${esc(s.have)} / Need ${esc(s.need)} • ${esc(s.location)} • Last edited ${fmt(s.updatedAt)}</div><p class="tiny">${esc(s.note)}</p></div><span class="pill ${Number(s.have)<Number(s.need)?'warn':'good'}">${Number(s.have)<Number(s.need)?'Low':'OK'}</span></div><div class="entry-actions"><button class="small secondary" data-action="editSupply" data-id="${s.id}">Edit</button><button class="small secondary" data-action="archiveSupply" data-id="${s.id}">Archive</button><button class="small danger delete-right" data-action="deleteSupply" data-id="${s.id}">Delete</button></div></div>`;}
function toolsPage(){const defs=[
 ['groupMaker',card('tools','groupMaker','👥 Groups',`<p class="tiny">Paste first names or nicknames. After you click Make groups, each group number and student list appears below.</p><div class="split"><div><label>Student names</label><textarea id="studentNames" placeholder="Avery, Mia, Leo, Sam"></textarea><p class="tiny">Tip: You can copy names from My Students if you use the same first names/nicknames.</p></div><div><label>Number of groups</label><input id="groupCount" type="number" value="3"><div class="actions"><button data-action="makeGroups">Make groups</button></div><div class="groups">${renderGroups()}</div></div></div>`,{size:'lg'})],
 ['timer',card('tools','timer','⏱️ Center timer',`<div class="timer-display" id="timerDisplay">00:00</div><div class="formrow three"><div><label>Minutes</label><input id="timerMinutes" type="number" value="10"></div><div><label>Sound</label><select id="quickSound"><option value="chime">Chime</option><option value="bell">Bell</option><option value="ding">Ding</option><option value="soft">Soft</option></select></div><div><label>Volume</label><input id="quickVolume" type="range" min="0" max="1" step="0.05" value="${state.notificationSettings.volume}"></div></div><div class="actions"><button data-action="startTimer">Start</button><button class="secondary" data-action="pauseTimer">Pause</button><button class="secondary" data-action="resetTimer">Reset</button><button class="secondary" data-action="testSound">Test sound</button></div>`,{size:'lg'})],
 ['reminders',card('tools','reminders','🔔 Reminders',remindersHtml(),{size:'lg'})],
 ['classroomMap',card('tools','classroomMap','🪑 Classroom map',classroomMapHtml(),{size:'lg'})],
 ['routines',card('tools','routines','✅ Classroom routines checklist',routinesHtml())],
 ['supplies',card('tools','supplies','🧻 Supplies tracker',suppliesHtml(),{size:'lg'})],
 ['subNotes',card('tools','subNotes','📝 Substitute Guide notes',subNotesHtml(),{size:'lg'})],
 ['subReadiness',card('tools','subReadiness','🧰 Sub-readiness checklist',readinessList(false))],
 ['subPacket',card('tools','subPacket','📄 Substitute Guide export',`<p class="tiny">This creates a clean packet using your saved notes, schedule, routines, sub-ready lessons, supplies, reminders, and grade-safe teacher notes.</p><div class="actions"><button data-action="printSubPacket">Print / Save as PDF</button></div><div id="packetPreview" class="archive-box">${subPacketHtml()}</div>`,{size:'lg'})]
]; return renderCards('tools',defs,'grid');}

function toolsLandingPage(){return `<div class="plain-block"><h3>🧰 Tools & Resources</h3><p>Use the submenu under Tools & Resources to open Group Generator, Timer, Reminders, Map, Routines Checklist, Supplies Tracker, and the Substitute Area.</p></div>`;}
function groupsPage(){const defs=[['groupMaker',card('groups','groupMaker','',`<div class="split"><div><label>Student names</label><textarea id="studentNames" placeholder="Avery, Mia, Leo, Sam">${activeStudents().map(s=>esc(s.name)).join(', ')}</textarea><p class="tiny">Tip: Names sync from My Students as a starting point, but you can edit this box before making groups.</p></div><div><label>Number of groups</label><input id="groupCount" type="number" value="3"><div class="actions"><button data-action="makeGroups">Make groups</button></div><div class="groups">${renderGroups()}</div></div></div>`,{size:'lg',controls:false,heading:false})]]; return renderCards('groups',defs,'grid');}
function timerPage(){const defs=[['timer',card('timer','timer','',`<div class="timer-display" id="timerDisplay">00:00</div><div class="formrow three"><div><label>Minutes</label><input id="timerMinutes" type="number" value="10"></div><div><label>Sound</label><select id="quickSound"><option value="chime">Chime</option><option value="bell">Bell</option><option value="ding">Ding</option><option value="soft">Soft</option></select></div><div><label>Volume</label><input id="quickVolume" type="range" min="0" max="1" step="0.05" value="${state.notificationSettings.volume}"></div></div><div class="actions"><button data-action="startTimer">Start</button><button class="secondary" data-action="pauseTimer">Pause</button><button class="secondary" data-action="resetTimer">Reset</button><button class="secondary" data-action="testSound">Test sound</button></div>`,{size:'lg',controls:false,heading:false})]]; return renderCards('timer',defs,'grid');}
function remindersPage(){const defs=[['reminders',card('reminders','reminders','',remindersHtml(),{size:'lg',controls:false,heading:false})]]; return renderCards('reminders',defs,'grid');}
function mapPage(){const defs=[['classroomMap',card('map','classroomMap','',classroomMapHtml(),{size:'lg',controls:false,heading:false})]]; return renderCards('map',defs,'grid');}
function routinesOnlyPage(){const defs=[['routines',card('routines','routines','',routinesHtml(),{size:'lg',controls:false,heading:false})]]; return renderCards('routines',defs,'grid');}
function suppliesOnlyPage(){const defs=[['supplies',card('supplies','supplies','',suppliesHtml(),{size:'lg',controls:false,heading:false})]]; return renderCards('supplies',defs,'grid');}
function subnotesPage(){const defs=[['subNotes',card('subnotes','subNotes','',subNotesHtml(),{size:'lg',controls:false,heading:false})]]; return renderCards('subnotes',defs,'grid');}
function subreadinessPage(){const defs=[['subReadiness',card('subreadiness','subReadiness','',readinessList(false),{size:'lg',controls:false,heading:false})]]; return renderCards('subreadiness',defs,'grid');}
function subexportPage(){const defs=[['subPacket',card('subexport','subPacket','',`<p class="tiny">This creates a clean packet using your saved notes, schedule, routines, sub-ready lessons, supplies, reminders, and grade-safe teacher notes.</p><div class="actions"><button data-action="printSubPacket">Print / Save as PDF</button></div><div id="packetPreview" class="archive-box">${subPacketHtml()}</div>`,{size:'lg',controls:false,heading:false})]]; return renderCards('subexport',defs,'grid');}
function classroomMapHtml(){const m=state.classroomMap||{}; const assigned=new Set((m.items||[]).flatMap(i=>mapAssignedIds(i))); const unassigned=activeStudents().filter(s=>!assigned.has(s.id)); const h=Math.max(460,Number(m.height)||620); return `<div class="classroom-controls"><div><label>Add furniture</label><div class="actions"><button class="secondary" data-action="addMapDesk">+ Desk</button><button class="secondary" data-action="addMapTable">+ Table</button></div></div></div><div class="map-workspace"><div class="classroom-board" data-classroom-board style="height:${h}px">${(m.items||[]).map(mapItemHtml).join('')}<button class="small secondary clear-map-btn" data-action="clearMap">Clear map</button></div><aside class="map-side unassigned-zone"><div class="map-settings-side"><div class="actions"><button data-action="saveMapSettings">Save Settings</button><button class="secondary" data-action="downloadMap">Download</button></div></div><b>Unassigned students</b><p class="tiny">Drag names onto a desk or table.</p><div>${unassigned.map(s=>`<span class="student-chip" draggable="true" data-student-chip="${s.id}">${esc(s.name)}</span>`).join('')||'<span class="tiny">Every active student is assigned, or no students are listed yet.</span>'}</div></aside></div>`;}
function mapAssignedIds(it){return Array.isArray(it.studentIds)?it.studentIds.filter(Boolean):(it.studentId?[it.studentId]:[]);}
function mapItemHtml(it){const ids=mapAssignedIds(it); const names=ids.map(id=>state.students.find(s=>s.id===id)).filter(Boolean); const x=Math.max(0,Number(it.x)||0),y=Math.max(0,Number(it.y)||0),w=Math.max(80,Number(it.w)||110),h=Math.max(58,Number(it.h)||80); const emptyText=it.type==='table'?'Drop student(s) here':'Drop student here'; return `<div class="map-item ${it.type==='table'?'table':'desk'}" draggable="true" data-map-id="${it.id}" style="left:${x}px;top:${y}px;width:${w}px;height:${h}px"><button class="map-menu-btn" title="Furniture options" aria-label="Furniture options">⋯</button><div class="map-menu-pop"><button class="secondary" data-action="unassignMapItem" data-id="${it.id}">Clear</button><button class="danger" data-action="deleteMapItem" data-id="${it.id}">Delete</button></div><b>${esc(it.label||it.type)}</b><div class="assigned ${names.length?'has-names':''}">${names.length?names.map(s=>`<span class="seat-name">${esc(s.name)} <button class="mini-x" data-action="unassignMapStudent" data-id="${it.id}" data-student="${s.id}">×</button></span>`).join(''):emptyText}</div><span class="resize-corner" data-resize-map="${it.id}" title="Drag to resize"></span></div>`;}
function standardsPage(){const guideBox=(!state.hideStandardsGuide&&!standardsGuideClosedSession)?`<div class="standard-explainer plain-block standard-guide"><button class="icon-btn guide-close" title="Close explanation" aria-label="Close explanation" data-action="closeStandardsGuide">×</button><p><strong>What is this page for?</strong> Use this to track the skill or standard itself, like “main idea,” “multiplication facts,” or “writing complete sentences.”</p><p><strong>How is this different from Lesson Library?</strong> Lesson Library stores the actual lesson plan. Standards / Skills tracks whether the class is learning, practicing, or mastering the skill across many lessons.</p><p class="tiny">Example: You may have 5 reading lessons in Lesson Library, but only 1 skill tracker for “finding text evidence.”</p><label class="guide-check"><input id="dontShowStandardGuide" type="checkbox"> Don't show me this again</label></div>`:''; const search=`<div class="plain-block standards-search-row"><div class="searchbar"><input id="standardSearchInput" value="${esc(state.currentStandardSearch||'')}" placeholder="Search standards, skills, subjects, status, or notes..."><button class="secondary" data-action="clearStandardSearch">Clear</button></div></div>`; const defs=[['standardList',card('standards','standardList','📈 Our Progress',standardList(),{size:'lg',controls:false})]]; return guideBox+search+renderCards('standards',defs,'grid');}
function standardForm(s={}){const edit=!!s.id; return `<div class="formrow four"><div><label>Skill</label><input id="${edit?'est_skill_'+s.id:'stdSkill'}" value="${esc(s.skill||'')}" placeholder="Main idea"></div><div><label>Subject</label><input id="${edit?'est_subject_'+s.id:'stdSubject'}" value="${esc(s.subject||'')}" placeholder="Reading"></div><div><label>Standard</label><input id="${edit?'est_standard_'+s.id:'stdStandard'}" value="${esc(s.standard||'')}" placeholder="RI.3.2"></div><div><label>Progress %</label><input id="${edit?'est_progress_'+s.id:'stdProgress'}" type="number" min="0" max="100" value="${esc(s.progress??0)}"></div></div><label>Status</label><input id="${edit?'est_status_'+s.id:'stdStatus'}" value="${esc(s.status||'')}" placeholder="Practicing, mastered, needs review"><label>Notes</label><textarea id="${edit?'est_notes_'+s.id:'stdNotes'}">${esc(s.notes||'')}</textarea>${edit?`<label>Last edited</label><input type="datetime-local" id="est_time_${s.id}" value="${toLocalInput(s.updatedAt)}">${attachmentPanel('standards',s.id,s.skill)}<div class="actions"><button class="small good" data-action="saveStandard" data-id="${s.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="standards" data-id="${s.id}">Cancel</button><button class="small danger" data-action="deleteStandard" data-id="${s.id}">Delete</button></div>`:`<p class="tiny">Save the skill first, then upload standard documents, checklists, rubrics, or examples from the saved skill.</p><div class="actions"><button data-action="addStandard">Save skill</button><button class="secondary" data-action="closeStandardModal">Cancel</button></div>`}`;}
function renderStandardModal(){const modal=document.getElementById('standardModal'); if(!modal)return; modal.classList.toggle('open',!!state.standardModalOpen); const body=document.getElementById('standardModalBody'); if(body)body.innerHTML=standardForm({});}
function standardList(){const q=(state.currentStandardSearch||'').toLowerCase().trim(); let rows=[...state.standards]; if(q)rows=rows.filter(x=>[x.skill,x.subject,x.standard,x.status,x.notes].join(' ').toLowerCase().includes(q)); return `<div class="standard-list-toolbar"><button data-action="openStandardModal">➕ Add a Standard/Skill</button><div></div><div></div><div class="pill">${rows.length} skill${rows.length===1?'':'s'}</div></div>`+(rows.map(s=>state.editing.standards[s.id]?`<div class="item">${standardForm(s)}</div>`:`<div class="item with-paperclip">${attachmentIndicator('standards',s.id)}<div class="item-title">${esc(s.skill)}</div><div class="item-meta">${esc(s.subject)} • ${esc(s.standard)} • ${esc(s.status)} • Last edited ${fmt(s.updatedAt)}</div><div class="progressbar"><span style="width:${Number(s.progress)||0}%"></span></div><p class="tiny">${esc(s.notes)}</p><div class="entry-actions"><button class="small secondary" data-action="editStandard" data-id="${s.id}">Edit</button><button class="small danger delete-right" data-action="deleteStandard" data-id="${s.id}">Delete</button></div></div>`).join('')||empty(q?'No skills match that search.':'No skills yet.'));}
function activeStudents(){return state.students.filter(s=>!s.archived);} function activeAssignments(){return state.assignments.filter(a=>!a.archived);} function lowSupplies(){return state.supplies.filter(s=>!s.archived&&Number(s.have)<Number(s.need));} function days(){return ['Monday','Tuesday','Wednesday','Thursday','Friday'];}
function lessonReadyPct(){const a=state.lessons.filter(l=>!l.archived); return a.length?Math.round(a.filter(l=>l.subReady).length/a.length*100):0;} function routinePct(){return state.routines.length?Math.round(state.routines.filter(r=>r.done).length/state.routines.length*100):0;}
function gradeStats(){const st=activeStudents(), as=activeAssignments(); let possible=0, entered=0, totalScore=0, totalPts=0, missing=0; st.forEach(s=>as.forEach(a=>{possible++; const sc=state.scores[s.id+'_'+a.id]; if(sc&&sc.excused)return; if(sc&&(sc.missing||sc.score!==''&&sc.score!=null)){entered++; totalPts+=Number(a.points)||0; totalScore+=sc.missing?0:Number(sc.score)||0; if(sc.missing)missing++;}})); const avg=totalPts?Math.round(totalScore/totalPts*100):null; return {avg,avgText:avg==null?'—':avg+'%',completion:possible?Math.round(entered/possible*100):0,missing};}
function studentAverage(sid){let total=0, pts=0; activeAssignments().forEach(a=>{const sc=state.scores[sid+'_'+a.id]; if(!sc||sc.excused)return; if(sc.missing||sc.score!==''&&sc.score!=null){pts+=Number(a.points)||0; total+=sc.missing?0:Number(sc.score)||0;}}); return pts?Math.round(total/pts*100):null;}
function gradeBadge(avg){let cls='grade-none',txt='—'; if(avg!=null){txt=avg+'%'; cls=avg>=90?'grade-a':avg>=80?'grade-b':avg>=70?'grade-c':avg>=60?'grade-d':'grade-f';} return `<span class="grade-badge ${cls}">${txt}</span>`;} function gradeBarsHtml(){const buckets=[0,0,0,0,0]; activeStudents().forEach(s=>{const a=studentAverage(s.id); if(a==null)return; if(a>=90)buckets[0]++; else if(a>=80)buckets[1]++; else if(a>=70)buckets[2]++; else if(a>=60)buckets[3]++; else buckets[4]++;}); const max=Math.max(1,...buckets); return ['A','B','C','D','F'].map((l,i)=>`<div class="bar" style="height:${Math.max(8,buckets[i]/max*100)}%"><span>${l}:${buckets[i]}</span></div>`).join('');}
function parseTime(s){const d=new Date('2000-01-01 '+s);return isNaN(d)?0:d.getTime();} function shiftTimeText(s,min){const d=new Date('2000-01-01 '+s); if(isNaN(d))return s; d.setMinutes(d.getMinutes()+min); return d.toLocaleTimeString([], {hour:'numeric',minute:'2-digit'});} function renderGroups(){return state.groups.map((g,i)=>`<div class="group-card"><b>Group ${i+1}</b>${g.map(n=>`<div>${esc(n)}</div>`).join('')}</div>`).join('')||empty('No groups made yet.');} function empty(msg){return `<div class="empty">${esc(msg)}</div>`;}
function readinessItems(){return [{label:'Substitute notes are saved',page:'subnotes',card:'subNotes',done:!!state.subNotes.saved,tip:'Answer and save the Substitute Guide prompts.'},{label:'Weekly planner has entries',page:'planner',card:'board',done:state.weekly.length>0,tip:'Add the daily schedule blocks.'},{label:'At least one lesson is sub-ready',page:'lessons',card:'lessonList',done:state.lessons.some(l=>l.subReady&&!l.archived),tip:'Mark emergency-friendly lessons as sub-ready.'},{label:'Routines are listed',page:'routines',card:'routines',done:state.routines.length>0,tip:'Add arrival, bathroom, lunch, dismissal, and behavior routines.'},{label:'Supplies are tracked',page:'supplies',card:'supplies',done:state.supplies.some(s=>!s.archived),tip:'Tell the sub where common materials are.'},{label:'Reminders are entered',page:'reminders',card:'reminders',done:state.reminders.length>0,tip:'Add special events, duties, or timing reminders.'},{label:'Skill progress is tracked',page:'standards',card:'standardList',done:state.standards.length>0,tip:'Add standards and skills.'},{label:'Grades have students and assignments',page:'grades',card:'gradebook',done:activeStudents().length>0&&activeAssignments().length>0,tip:'Add students and assignments if the sub needs grading context.'},{label:'Classroom map has seats or tables',page:'map',card:'classroomMap',done:(state.classroomMap.items||[]).length>0,tip:'Add desks or tables if the sub needs seating guidance.'}];}
function readinessList(compact){const cls=compact?'readiness-grid compact':'readiness-grid'; return `<div class="${cls}">${readinessItems().map(it=>`<div class="readiness-item" data-gopage="${it.page}" data-gocard="${it.card}"><span>${it.done?'✅':'⬜'}</span><div><b>${esc(it.label)}</b><div class="tiny">${esc(it.tip)}</div></div><button class="small secondary" data-gopage="${it.page}" data-gocard="${it.card}">${compact?'Open':'Go'}</button></div>`).join('')}</div>`;} function readinessScore(){const a=readinessItems(); return {done:a.filter(i=>i.done).length,total:a.length};}
function subPacketHtml(){const f=state.subNotes.fields||{}; const gs=gradeStats(); return `<div class="subpacket"><h1>Substitute Teacher Packet</h1><p>Generated from SOZY Workspace. Last app save: ${fmt(state.lastSaved)}</p><h2>Class Overview</h2><p>${esc(f.overview||'No overview saved.')}</p><h2>Attendance / Lunch Count</h2><p>${esc(f.attendance||'No attendance notes saved.')}</p><h2>Daily Flow</h2><p>${esc(f.schedule||'No daily flow notes saved.')}</p><h2>Behavior Support</h2><p>${esc(f.behavior||'No behavior support notes saved.')}</p><h2>Student Support Notes</h2><p>${esc(f.students||'No student support notes saved.')}</p><h2>Materials / Technology</h2><p>${esc(f.materials||'No materials notes saved.')}</p><h2>Emergency Procedures</h2><p>${esc(f.emergency||'No emergency notes saved.')}</p><h2>Dismissal</h2><p>${esc(f.dismissal||'No dismissal notes saved.')}</p><h2>Extra Comments</h2><p>${esc(f.extra||'No extra comments saved.')}</p><h2>Weekly Schedule</h2><table><tr><th>Day</th><th>Time</th><th>Subject</th><th>Plan</th><th>Notes</th></tr>${state.weekly.map(w=>`<tr><td>${esc(w.day)}</td><td>${esc(w.time)}</td><td>${esc(w.subject)}</td><td>${esc(w.title)}</td><td>${esc(w.note)}</td></tr>`).join('')}</table><h2>Sub-ready Lessons</h2><table><tr><th>Lesson</th><th>Subject</th><th>Standard</th><th>Theme</th><th>Notes</th></tr>${state.lessons.filter(l=>l.subReady&&!l.archived).map(l=>`<tr><td>${esc(l.title)}</td><td>${esc(l.subject)}</td><td>${esc(l.standard)}</td><td>${esc(l.theme)}</td><td>${esc(l.summary)}<br><b>Support:</b> ${esc(l.diff)}</td></tr>`).join('')||'<tr><td colspan="5">No sub-ready lessons marked yet.</td></tr>'}</table><h2>Routines</h2><ul>${state.routines.map(r=>`<li>${esc(r.text)}</li>`).join('')}</ul><h2>Supplies</h2><table><tr><th>Item</th><th>Have</th><th>Need</th><th>Location</th><th>Note</th></tr>${state.supplies.filter(s=>!s.archived).map(s=>`<tr><td>${esc(s.item)}</td><td>${esc(s.have)}</td><td>${esc(s.need)}</td><td>${esc(s.location)}</td><td>${esc(s.note)}</td></tr>`).join('')}</table><h2>Grading Snapshot</h2><p>Class average: ${gs.avgText}. Scores entered: ${gs.completion}%. Missing items marked: ${gs.missing}.</p><h2>Reminders</h2><ul>${state.reminders.map(r=>`<li>${fmt(r.time)} — ${esc(r.title)} (${esc(r.category||'General')}) ${esc(r.note||'')}</li>`).join('')||'<li>No reminders saved.</li>'}</ul></div>`;}
function renderPrint(){document.getElementById('printSection').innerHTML=subPacketHtml(); const p=document.getElementById('packetPreview'); if(p)p.innerHTML=subPacketHtml();}
function faqItems(){return [['What is this app for?','SOZY Workspace helps elementary teachers plan lessons, track student grading, prepare for substitutes, manage routines, track supplies, and remember tasks in one place.'],['Does this app message families or students?','No. This version is only for the teacher. It does not include family communication, student messaging, or photo sharing.'],['Where is my data saved?','Your data is saved in your browser on your device using local storage. It does not go to a cloud database from this app.'],['What does local storage mean?','Local storage means the browser keeps the app data for this website on this device. If you clear browser data or use a different device, the data may not be there unless you restored a backup.'],['What is backed up?','The backup JSON file includes your planner, lessons, Gallery files, grades, students, assignments, scores, meetings, tasks, reminders, routines, supplies, standards, classroom map, sub notes, themes, and layout settings. Keep it private.'],['What is a JSON file?','A JSON file is just a data file. Think of it like a save file for the app. You usually do not open or edit it. You save it somewhere safe, then restore it if needed.'],['How do I restore a backup?','Click Restore, choose your SOZY Workspace backup JSON file, and the app will load that saved information.'],['How do I install this from GitHub Pages?','Open the GitHub Pages link in your browser. On phone or tablet, use Share/Add to Home Screen if available. On desktop Chrome or Edge, look for the install icon in the address bar.'],['How do I update the GitHub app files?','Open your GitHub repository, upload the new files from the ZIP, replace the old index.html, manifest.json, service-worker.js, icons folder, and README.md, then commit the changes.'],['What is the Standards / Skills explanation box?','It explains the difference between Lesson Library and Standards / Skills. You can close it with the ×. If you check Don’t show me this again before closing, it stays hidden. You can always read this FAQ if you need the explanation again.'],['What does the grade tab do?','The grade tab lets you add students, assignments, scores, missing work, averages, archived items, and CSV exports. It is for local teacher organization.'],['Should I use full student names?','Use whatever your school allows. For extra privacy, many teachers may choose first names, initials, or nicknames.'],['How do I edit a lesson?','Go to Lesson Library, find the lesson, click Edit, make changes, then click Save.'],['How do I move boxes around?','Use the ☰ icon in the upper-left corner of a box. Drag it to a new location on the same page.'],['How do I make a box bigger?','Use the ↔ icon in the upper-right corner of the box. Use ⛶ to focus on one box, then ↙ to return.'],['How do I remove a dashboard box?','Open Page layout on the Dashboard. Then each dashboard box shows an × button. Removed boxes can be added back from the same layout panel.'],['How do I hide the menu?','Click the < arrow on the menu to hide it. When hidden, click the > arrow on the left edge to bring it back.'],['Why are notifications not working?','The browser must allow notifications first. Some devices also block notifications when the browser or app is fully closed.'],['How do sounds work?','Sounds play from the app when reminders or timers trigger, if sound is turned on and your device volume is up.'],['How do I make a substitute packet?','Go to Tools & Resources, answer the Substitute Guide prompts, save changes, then click Print / Save as PDF.'],['What is archived?','Archived items are not deleted. They move out of the active list but can be viewed and restored later from the View archives button.'],['What should I test after uploading to GitHub?','Check the menu, themes, layout, adding lessons, editing lessons, adding grades, saving scores, backup, restore, sub packet print, timer sound, and install option.']];}
function faqResultsHtml(q){const term=(q||'').toLowerCase().trim(); const arr=faqItems().filter(x=>!term||x[0].toLowerCase().includes(term)||x[1].toLowerCase().includes(term)); return arr.map(x=>`<div class="faq-item"><b>${esc(x[0])}</b><p>${esc(x[1])}</p></div>`).join('')||empty('No answer found. Try a simpler word like grades, backup, JSON, local, install, PDF, edit, theme, notification, or sound.');}
// Actions
function viewWeekly(id){const w=state.weekly.find(x=>x.id===id); if(!w)return; alert(`${w.day} ${w.time}\n${w.subject}: ${w.title}\n\n${w.note||'No notes saved.'}\n\nLast edited ${fmt(w.updatedAt)}`);}
function openGalleryForItem(area,itemId){state.activePage='gallery'; state.galleryFilter=area||'all'; const label=linkedItemLabel(area,itemId)||''; state.gallerySearch=label; save('',false); renderAll(); setTimeout(()=>document.getElementById('page-gallery')?.scrollIntoView({behavior:'smooth',block:'start'}),50);}
function addWeekly(){const t=nowIso(); state.weekly.push({id:uid('week'),day:val('wDay')||'Monday',time:val('wTime')||'8:00 AM',subject:val('wSubject')||'General',title:val('wTitle')||'Untitled block',note:val('wNote'),createdAt:t,updatedAt:t}); save('Weekly block saved.');}
function saveWeekly(id){const w=state.weekly.find(x=>x.id===id); if(!w)return; w.time=val('ew_time_'+id); w.subject=val('ew_subject_'+id); w.title=val('ew_title_'+id); w.note=val('ew_note_'+id); w.updatedAt=fromLocalInput(val('ew_updated_'+id))||nowIso(); delete state.editing.weekly[id]; save('Weekly block saved.');}
function shiftSchedule(){const day=val('shiftDay'), after=val('shiftAfter'), min=(Number(val('shiftMin')||0)*Number(val('shiftDir')||1)); let count=0; state.weekly.forEach(w=>{if(w.day===day&&(!after||parseTime(w.time)>=parseTime(after))){w.time=shiftTimeText(w.time,min);w.updatedAt=nowIso();count++;}}); save(`Shifted ${count} planner blocks.`);}
function addLesson(){const t=nowIso(); state.lessons.push({id:uid('lesson'),title:val('lTitle')||'Untitled lesson',subject:val('lSubject'),standard:val('lStandard'),lexile:val('lLexile'),theme:val('lTheme'),summary:val('lSummary'),diff:val('lDiff'),subReady:val('lSub')==='true',archived:false,createdAt:t,updatedAt:t}); save('Lesson saved.');}
function saveLesson(id){const l=state.lessons.find(x=>x.id===id); if(!l)return; Object.assign(l,{title:val('elTitle'),subject:val('elSubject'),standard:val('elStandard'),lexile:val('elLexile'),theme:val('elTheme'),summary:val('elSummary'),diff:val('elDiff'),subReady:val('elSub')==='true',updatedAt:fromLocalInput(val('elUpdated'))||nowIso()}); delete state.editing.lessons[id]; save('Lesson changes saved.');}
function addStudent(){const t=nowIso(); state.students.push({id:uid('stu'),name:val('studentName')||'New student',status:val('studentStatus'),notes:val('studentNotes'),archived:false,createdAt:t,updatedAt:t}); save('Student saved.');}
function saveStudent(id){const s=state.students.find(x=>x.id===id); if(!s)return; s.name=val('es_name_'+id); s.status=val('es_status_'+id); s.notes=val('es_notes_'+id); s.updatedAt=fromLocalInput(val('es_time_'+id))||nowIso(); delete state.editing.students[id]; save('Student saved.');}
function addAssignment(){const t=nowIso(); state.assignments.push({id:uid('asmt'),title:val('assignmentTitle')||'Untitled assignment',subject:val('assignmentSubject'),category:val('assignmentCategory'),points:Number(val('assignmentPoints')||0),date:val('assignmentDate'),lessonId:val('assignmentLesson'),archived:false,createdAt:t,updatedAt:t}); save('Assignment saved.');}
function saveAssignment(id){const a=state.assignments.find(x=>x.id===id); if(!a)return; a.title=val('ea_title_'+id); a.subject=val('ea_subject_'+id); a.category=val('ea_category_'+id); a.points=Number(val('ea_points_'+id)||0); a.date=val('ea_date_'+id); a.updatedAt=fromLocalInput(val('ea_time_'+id))||nowIso(); delete state.editing.assignments[id]; save('Assignment saved.');}
function setScore(el){const key=el.dataset.score, raw=el.value.trim(); const obj=state.scores[key]||{}; obj.updatedAt=nowIso(); obj.missing=/^m$/i.test(raw); obj.excused=/^x$/i.test(raw); obj.score=(!obj.missing&&!obj.excused&&raw!=='')?Number(raw):''; state.scores[key]=obj; save('Score saved.',false); renderStatus(); setTimeout(renderAll,200);}
function addMeeting(){const t=nowIso(); state.meetings.push({id:uid('meet'),title:val('meetingTitle')||'Untitled meeting',date:val('meetingDate'),notes:val('meetingNotes'),createdAt:t,updatedAt:t}); save('Meeting note saved.');}
function saveMeeting(id){const m=state.meetings.find(x=>x.id===id); if(!m)return; m.title=val('em_title_'+id); m.date=val('em_date_'+id); m.notes=val('em_notes_'+id); m.updatedAt=fromLocalInput(val('em_time_'+id))||nowIso(); delete state.editing.meetings[id]; save('Meeting note saved.');}
function addTodo(){const t=nowIso(); state.todos.push({id:uid('todo'),text:val('todoText')||'Untitled task',priority:val('todoPriority'),done:false,createdAt:t,updatedAt:t}); save('Task added.');}
function saveTodo(id){const x=state.todos.find(t=>t.id===id); if(!x)return; x.text=val('et_text_'+id); x.priority=val('et_priority_'+id); x.updatedAt=fromLocalInput(val('et_time_'+id))||nowIso(); delete state.editing.todos[id]; save('Task saved.');}
function addReminder(){const t=nowIso(); state.reminders.push({id:uid('rem'),title:val('remTitle')||'Reminder',time:fromLocalInput(val('remTime'))||new Date(Date.now()+3600000).toISOString(),category:val('remCategory'),note:val('remNote'),done:false,createdAt:t,updatedAt:t}); save('Reminder added.');}
function saveReminder(id){const r=state.reminders.find(x=>x.id===id); if(!r)return; r.title=val('er_title_'+id); r.time=fromLocalInput(val('er_time_'+id)); r.category=val('er_cat_'+id); r.note=val('er_note_'+id); r.updatedAt=fromLocalInput(val('er_updated_'+id))||nowIso(); delete state.editing.reminders[id]; save('Reminder saved.');}
function addRoutine(){const t=nowIso(); state.routines.push({id:uid('routine'),text:val('routineText')||'New routine',done:false,createdAt:t,updatedAt:t}); save('Routine added.');}
function saveRoutine(id){const r=state.routines.find(x=>x.id===id); if(!r)return; r.text=val('erou_text_'+id); r.updatedAt=fromLocalInput(val('erou_time_'+id))||nowIso(); delete state.editing.routines[id]; save('Routine saved.');}
function addSupply(){const t=nowIso(); state.supplies.push({id:uid('sup'),item:val('sItem')||'Supply item',have:Number(val('sHave')||0),need:Number(val('sNeed')||0),location:val('sLocation'),note:val('sNote'),archived:false,createdAt:t,updatedAt:t}); save('Supply saved.');}
function saveSupply(id){const s=state.supplies.find(x=>x.id===id); if(!s)return; s.item=val('esu_item_'+id); s.have=Number(val('esu_have_'+id)||0); s.need=Number(val('esu_need_'+id)||0); s.location=val('esu_loc_'+id); s.note=val('esu_note_'+id); s.updatedAt=fromLocalInput(val('esu_time_'+id))||nowIso(); delete state.editing.supplies[id]; save('Supply saved.');}
function addStandard(){const t=nowIso(); state.standards.push({id:uid('std'),skill:val('stdSkill')||'New skill',subject:val('stdSubject'),standard:val('stdStandard'),progress:Number(val('stdProgress')||0),status:val('stdStatus'),notes:val('stdNotes'),createdAt:t,updatedAt:t}); state.standardModalOpen=false; save('Skill saved.');}
function saveStandard(id){const s=state.standards.find(x=>x.id===id); if(!s)return; s.skill=val('est_skill_'+id); s.subject=val('est_subject_'+id); s.standard=val('est_standard_'+id); s.progress=Number(val('est_progress_'+id)||0); s.status=val('est_status_'+id); s.notes=val('est_notes_'+id); s.updatedAt=fromLocalInput(val('est_time_'+id))||nowIso(); delete state.editing.standards[id]; save('Skill saved.');}
function saveSubNotes(){state.subNotes.fields={overview:val('sub_overview'),attendance:val('sub_attendance'),schedule:val('sub_schedule'),behavior:val('sub_behavior'),students:val('sub_students'),materials:val('sub_materials'),emergency:val('sub_emergency'),dismissal:val('sub_dismissal'),extra:val('sub_extra')}; state.subNotes.saved=JSON.stringify(state.subNotes.fields); state.subNotes.lastSaved=nowIso(); save('Substitute notes saved.');}
function undoSubNotes(){try{if(state.subNotes.saved)state.subNotes.fields=JSON.parse(state.subNotes.saved);}catch(e){} save('Substitute notes restored to last save.');}
function clearSubNotes(){if(!confirm('Clear all substitute note boxes?'))return; state.subNotes.fields={overview:'',attendance:'',schedule:'',behavior:'',students:'',materials:'',emergency:'',dismissal:'',extra:''}; state.subNotes.saved=''; state.subNotes.lastSaved=null; save('Substitute notes cleared.');}
function makeGroups(){const names=val('studentNames').split(/\n|,/).map(x=>x.trim()).filter(Boolean); const count=Math.max(1,Number(val('groupCount')||1)); const shuffled=[...names].sort(()=>Math.random()-.5); state.groups=Array.from({length:count},()=>[]); shuffled.forEach((n,i)=>state.groups[i%count].push(n)); save('Groups made. Names are shown in the groups.');}
function saveNotificationSettings(){state.notificationSettings.enabled=val('notEnabled')==='true'; state.notificationSettings.sound=val('soundEnabled')==='true'; state.notificationSettings.soundType=val('soundType'); state.notificationSettings.volume=Number(val('soundVolume')||.45); save('Notification and sound settings saved.');}
function saveCustomTheme(){state.customTheme.enabled=chk('customEnabled'); ['bg','surface','surface2','ink','muted','brand','brand2','brand3','line'].forEach(k=>state.customTheme[k]=val('ct_'+k)); save('Custom theme saved.');}
function resetCustomTheme(){state.customTheme=sampleState().customTheme; save('Custom theme reset.');}
function addMapItem(type){const m=state.classroomMap; const t=nowIso(); const n=(m.items||[]).filter(i=>i.type===type).length+1; m.items=m.items||[]; m.items.push({id:uid(type),type,label:type==='table'?'Table '+String.fromCharCode(64+n):'Desk '+n,x:40+((n*35)%360),y:60+((n*28)%260),w:type==='table'?180:110,h:type==='table'?110:80,studentIds:[],createdAt:t,updatedAt:t}); save((type==='table'?'Table':'Desk')+' added.');}
function saveMapSettings(){const board=document.querySelector('[data-classroom-board]'); if(board){state.classroomMap.width=Math.round(board.offsetWidth); state.classroomMap.height=Math.round(board.offsetHeight);} save('Classroom map settings saved.');}
function assignMapStudent(mapId,studentId){const it=(state.classroomMap.items||[]).find(x=>x.id===mapId); if(!it)return; it.studentIds=mapAssignedIds(it); if(!studentId){it.studentIds=[]; it.updatedAt=nowIso(); save('Seat cleared.'); return;} (state.classroomMap.items||[]).forEach(x=>{x.studentIds=mapAssignedIds(x).filter(id=>id!==studentId);}); if(it.type==='table'){ if(!it.studentIds.includes(studentId))it.studentIds.push(studentId); } else { it.studentIds=[studentId]; } it.updatedAt=nowIso(); save('Seat assignment saved.');}
function unassignMapStudent(mapId,studentId){const it=(state.classroomMap.items||[]).find(x=>x.id===mapId); if(!it)return; it.studentIds=mapAssignedIds(it).filter(id=>id!==studentId); it.updatedAt=nowIso(); save('Student removed from seat.');}
function resizeMapItem(id){toast('Drag the corner handle on the furniture to resize it.');}
function deleteMapItem(id){state.classroomMap.items=(state.classroomMap.items||[]).filter(x=>x.id!==id); save('Map item removed.');}
function clearMap(){if(!confirm('Clear all furniture and seating assignments from the map?'))return; state.classroomMap.items=[]; save('Classroom map cleared.');}
function downloadMap(){const m=state.classroomMap||{}; const lines=['SOZY Workspace Classroom Map','Shape: '+(m.shape||'rectangle'),'Saved: '+new Date().toLocaleString(),'']; (m.items||[]).forEach(it=>{const names=mapAssignedIds(it).map(id=>(state.students.find(s=>s.id===id)||{}).name).filter(Boolean).join(', ')||'No students assigned'; lines.push((it.label||it.type)+' — '+names);}); const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([lines.join('\n')],{type:'text/plain'})); a.download='SOZY_Workspace_Classroom_Map_'+new Date().toISOString().slice(0,10)+'.txt'; a.click(); URL.revokeObjectURL(a.href); toast('Classroom map downloaded.');}
function moveMapItem(id,x,y){const it=(state.classroomMap.items||[]).find(x=>x.id===id); const board=document.querySelector('[data-classroom-board]'); if(!it||!board)return; const maxX=Math.max(0,board.clientWidth-(Number(it.w)||110)-8), maxY=Math.max(0,board.clientHeight-(Number(it.h)||80)-8); it.x=Math.max(0,Math.min(maxX,Math.round(x))); it.y=Math.max(0,Math.min(maxY,Math.round(y))); it.updatedAt=nowIso(); save('Classroom map updated.');}
function toggleIn(arr,id){const i=arr.indexOf(id); if(i>=0)arr.splice(i,1); else arr.push(id);} function reorderArray(arr,from,to){if(!from||!to||from===to)return; if(!arr.includes(from))arr.push(from); if(!arr.includes(to))arr.push(to); const fi=arr.indexOf(from),ti=arr.indexOf(to); if(fi<0||ti<0)return; arr.splice(ti,0,arr.splice(fi,1)[0]);}

function openPinModal(id){state.editingPinId=id||null; state.pinModalOpen=true; renderAll(); setTimeout(()=>document.getElementById('pinText')?.focus(),80);}
function closePinModal(){state.pinModalOpen=false; state.editingPinId=null; const f=document.getElementById('pinFile'); if(f)f.value=''; renderAll();}
function savePin(){const text=(val('pinText')||'').trim(); const file=document.getElementById('pinFile')?.files?.[0]; const existing=(state.dashboardPins||[]).find(x=>x.id===state.editingPinId); if(!text&&!file&&!existing){toast('Add a note, file, or photo first.');return;} const finish=(dataUrl,type,name,mime,size)=>{if(existing){existing.text=text||existing.text||name||'Pinned item'; if(dataUrl){existing.type=type; existing.dataUrl=dataUrl; existing.img=type==='photo'?dataUrl:''; existing.fileName=name; existing.mime=mime; existing.size=size;} existing.updatedAt=nowIso(); save('Pin updated.');}else{state.dashboardPins.unshift({id:uid('pin'),type:type||'note',text:text||name||'Pinned item',dataUrl:dataUrl||'',img:type==='photo'?dataUrl:'',fileName:name||'',mime:mime||'',size:size||0,archived:false,createdAt:nowIso(),updatedAt:nowIso()}); save('Pin added.');} closePinModal();}; if(file){const r=new FileReader(); r.onload=()=>finish(r.result,(file.type||'').startsWith('image/')?'photo':'file',file.name,file.type,file.size); r.onerror=()=>toast('That file could not be added.'); r.readAsDataURL(file);}else finish('',existing?.type||'note',existing?.fileName||'',existing?.mime||'',existing?.size||0);}
function viewPin(id){const p=(state.dashboardPins||[]).find(x=>x.id===id); if(!p)return; if(p.dataUrl||p.img){const w=window.open('','_blank'); w.document.write(`<title>${esc(p.text||p.fileName||'Pin')}</title><body style="font-family:Arial;padding:20px"><h1>${esc(p.text||p.fileName||'Pin')}</h1>${(p.type==='photo')?`<img src="${p.img||p.dataUrl}" style="max-width:100%;height:auto">`:`<p><a href="${p.dataUrl}" download="${esc(p.fileName||'SOZY_pin_file')}">Download attached file</a></p>`}<p>${esc(p.fileName||'')}</p><p>${fmt(p.createdAt)}</p>
<!-- SOZY Workspace V25 Privacy Summary update: trusted-device local-storage notice added. -->
</body>`); w.document.close();}else alert((p.text||'Pinned note')+'\n\nCreated: '+fmt(p.createdAt));}
function editPin(id){openPinModal(id);}
function downloadPin(id){const p=(state.dashboardPins||[]).find(x=>x.id===id); if(!p)return; const a=document.createElement('a'); if(p.dataUrl||p.img){a.href=p.dataUrl||p.img; a.download=p.fileName||'SOZY_Pin_File';}else{a.href=URL.createObjectURL(new Blob([p.text||''],{type:'text/plain'})); a.download='SOZY_Pin_Note_'+new Date().toISOString().slice(0,10)+'.txt';} a.click(); if(a.href.startsWith('blob:'))URL.revokeObjectURL(a.href);}
function archivePin(id){const p=(state.dashboardPins||[]).find(x=>x.id===id); if(!p)return; p.archived=!p.archived; p.updatedAt=nowIso(); save(p.archived?'Pin archived.':'Pin restored.');}
function deleteDashPin(id){state.dashboardPins=(state.dashboardPins||[]).filter(p=>p.id!==id); save('Pin deleted.');}
function togglePinArchives(){state.showArchivedPins=!state.showArchivedPins; renderAll();}
function openCorkSettings(){state.corkSettingsOpen=true; renderAll();}
function closeCorkSettings(){state.corkSettingsOpen=false; renderAll();}
function saveCorkSettings(){state.corkSettings=state.corkSettings||{}; state.corkSettings.freeMove=!!document.getElementById('corkFreeMove')?.checked; state.corkSettings.floralBorder=!!document.getElementById('corkFloralBorder')?.checked; state.corkSettingsOpen=false; save('Cork board settings saved.');}
function resetPinLayout(){(state.dashboardPins||[]).forEach((p,i)=>{p.x=18+(i%5)*190; p.y=22+Math.floor(i/5)*140; p.rot=((i%5)-2)*2; p.z=2+i; p.updatedAt=nowIso();}); save('Pin layout reset.');}
function rotatePin(id,dir){const p=(state.dashboardPins||[]).find(x=>x.id===id); if(!p)return; p.rot=(Number(p.rot)||0)+(Number(dir)||8); p.updatedAt=nowIso(); save('Pin rotated.');}
function addDashPhotoFile(file){if(!file)return; const reader=new FileReader(); reader.onload=()=>{state.dashboardPins.unshift({id:uid('pin'),type:'photo',img:reader.result,dataUrl:reader.result,text:file.name||'Photo highlight',fileName:file.name||'',mime:file.type||'',size:file.size||0,archived:false,createdAt:nowIso(),updatedAt:nowIso()}); save('Photo pinned.');}; reader.onerror=()=>toast('That photo could not be added.'); reader.readAsDataURL(file);}


function addFilesToGallery(files,area,itemId,label){files=[...files]; if(!files.length)return; let left=files.length, added=0; files.forEach(file=>{const reader=new FileReader(); reader.onload=()=>{state.gallery=state.gallery||[]; state.gallery.unshift({id:uid('doc'),name:file.name||'Untitled file',type:file.type||'application/octet-stream',size:file.size||0,dataUrl:reader.result,area:area||'general',itemId:itemId||'',label:label||linkedItemLabel(area,itemId),createdAt:nowIso(),updatedAt:nowIso()}); added++; left--; if(left===0)save(`${added} file${added===1?'':'s'} added to Gallery.`);}; reader.onerror=()=>{left--; toast('One file could not be uploaded.'); if(left===0&&added)save(`${added} file${added===1?'':'s'} added to Gallery.`);}; reader.readAsDataURL(file);});}
function deleteGalleryDoc(id){state.gallery=(state.gallery||[]).filter(d=>d.id!==id); save('File removed from Gallery.');}

function downloadWeeklyCsv(){const rows=[['Day','Time','Subject','Title','Notes','Last edited']].concat(state.weekly.map(w=>[w.day,w.time,w.subject,w.title,w.note||'',fmt(w.updatedAt)])); const csv=rows.map(r=>r.map(x=>'"'+String(x).replace(/"/g,'""')+'"').join(',')).join('\n'); const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv'})); a.download='SOZY_Workspace_Weekly_Plan_'+new Date().toISOString().slice(0,10)+'.csv'; a.click(); URL.revokeObjectURL(a.href); toast('Weekly plan downloaded.');}
function backup(){const blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='SOZY_Workspace_Backup_'+new Date().toISOString().slice(0,10)+'.json'; a.click(); URL.revokeObjectURL(a.href); toast('Backup downloaded. Keep it private.');}
function restoreFile(file){const r=new FileReader(); r.onload=()=>{try{state=merge(sampleState(),JSON.parse(r.result)); save('Backup restored.');}catch(e){toast('Could not read that backup file.');}}; r.readAsText(file);}
function downloadGradesCsv(){let rows=[['Student',...activeAssignments().map(a=>a.title),'Average']]; activeStudents().forEach(s=>{rows.push([s.name,...activeAssignments().map(a=>{const sc=state.scores[s.id+'_'+a.id]||{}; return sc.excused?'EX':sc.missing?'M':(sc.score??'')}),studentAverage(s.id)??'']);}); const csv=rows.map(r=>r.map(x=>'"'+String(x).replace(/"/g,'""')+'"').join(',')).join('\n'); const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv'})); a.download='SOZY_Workspace_Grades_'+new Date().toISOString().slice(0,10)+'.csv'; a.click(); URL.revokeObjectURL(a.href);}
function downloadStudentsCsv(){let rows=[['Student','Status','Notes','Archived','Last edited']]; state.students.forEach(s=>rows.push([s.name,s.status||'',s.notes||'',s.archived?'Yes':'No',fmt(s.updatedAt)])); const csv=rows.map(r=>r.map(x=>'"'+String(x).replace(/"/g,'""')+'"').join(',')).join('\n'); const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv'})); a.download='SOZY_Workspace_Student_List_'+new Date().toISOString().slice(0,10)+'.csv'; a.click(); URL.revokeObjectURL(a.href);}
function printGrades(){
  const html=`<h1>Grade Summary</h1>${gradeDashboardHtml()}${gradebookHtml()}`;
  const w=window.open('','_blank');
  if(!w){toast('Pop-up blocked. Allow pop-ups to print grades.');return;}
  const css='body{font-family:Arial,sans-serif;padding:20px}table{border-collapse:collapse;width:100%}td,th{border:1px solid #444;padding:6px}.tiny{font-size:12px}.grade-badge{font-weight:bold}';
  w.document.write('<!doctype html><html><head><title>Grade Summary</title><style>'+css+'</style></head><body>'+html+'</body></html>');
  w.document.close();
  w.print();
}

function requestNotifications(){if(!('Notification'in window)){toast('This browser does not support notifications.');return;} Notification.requestPermission().then(p=>toast('Notification permission: '+p));}
function notify(title,body){if(state.notificationSettings.enabled&&'Notification'in window&&Notification.permission==='granted')new Notification(title,{body});}
function playSound(){if(!state.notificationSettings.sound)return; try{audioCtx=audioCtx||new (window.AudioContext||window.webkitAudioContext)(); const vol=Number(state.notificationSettings.volume||.4); const type=state.notificationSettings.soundType||'chime'; const freqs=type==='bell'?[880,660,880]:type==='ding'?[740]:type==='soft'?[440,554]:[523,659,784]; freqs.forEach((f,i)=>{const o=audioCtx.createOscillator(), g=audioCtx.createGain(); o.frequency.value=f; o.type='sine'; g.gain.setValueAtTime(0,audioCtx.currentTime+i*.16); g.gain.linearRampToValueAtTime(vol,audioCtx.currentTime+i*.16+.02); g.gain.exponentialRampToValueAtTime(.001,audioCtx.currentTime+i*.16+.35); o.connect(g); g.connect(audioCtx.destination); o.start(audioCtx.currentTime+i*.16); o.stop(audioCtx.currentTime+i*.16+.38);});}catch(e){console.warn(e);}}
function scheduleReminderCheck(){clearInterval(scheduleReminderCheck.int); scheduleReminderCheck.int=setInterval(()=>{const now=Date.now(); state.reminders.forEach(r=>{if(!r.done&&!r.alerted&&new Date(r.time).getTime()<=now){r.alerted=true; playSound(); notify('SOZY Workspace reminder',r.title); toast('Reminder: '+r.title); save('',false);}});},30000);} 
function startTimer(){state.notificationSettings.soundType=val('quickSound')||state.notificationSettings.soundType; state.notificationSettings.volume=Number(val('quickVolume')||state.notificationSettings.volume); timerLeft=Math.max(1,Number(val('timerMinutes')||1))*60; updateTimer(); clearInterval(timerInt); timerInt=setInterval(()=>{timerLeft--; updateTimer(); if(timerLeft<=0){clearInterval(timerInt); playSound(); notify('SOZY Workspace timer','Time is up.'); toast('Timer finished.');}},1000);} function pauseTimer(){clearInterval(timerInt);toast('Timer paused.');} function resetTimer(){clearInterval(timerInt);timerLeft=0;updateTimer();} function updateTimer(){const el=document.getElementById('timerDisplay'); if(el){const m=String(Math.floor(timerLeft/60)).padStart(2,'0'),s=String(timerLeft%60).padStart(2,'0'); el.textContent=m+':'+s;}}
function handleAction(action,el){normalize(); const id=el.dataset.id; const type=el.dataset.type; switch(action){case'toggleMenu':state.menuHidden=!state.menuHidden;state.quickThemesOpen=false;state.showMenuSettings=false;save('',true);break;case'toggleQuickThemes':state.quickThemesOpen=!state.quickThemesOpen;state.menuHidden=false;renderAll();break;case'toggleMenuSettings':state.showMenuSettings=!state.showMenuSettings;renderAll();break;case'toggleToolsSubmenu':state.toolsMenuOpen=!state.toolsMenuOpen;renderAll();break;case'pageSettings':state.layout.openSettingsPage=state.layout.openSettingsPage===state.activePage?null:state.activePage;renderAll();break;case'backup':backup();break;case'restoreClick':document.getElementById('restoreFile').click();break;case'openHelp':document.getElementById('helpModal').classList.add('open');document.getElementById('faqResults').innerHTML=faqResultsHtml(state.faqSearch);break;case'goHelpSettings':state.activePage='settings';state.layout.openSettingsPage=null;save('',false);renderAll();setTimeout(()=>document.getElementById('helpPageSearch')?.scrollIntoView({behavior:'smooth',block:'center'}),50);break;case'closeHelp':document.getElementById('helpModal').classList.remove('open');break;case'toggleMenuPage':if(el.dataset.page==='settings'){toast('Settings stays available at the bottom.');break;} toggleIn(state.layout.menuHidden,el.dataset.page); state.settingsOpenSection='menu'; if(state.activePage!=='settings'&&state.layout.menuHidden.includes(state.activePage))state.activePage='dashboard'; save('Menu layout saved.');break;case'resetMenu':state.layout.menuOrder=[...topMenuIds];state.layout.menuHidden=[];save('Menu reset.');break;case'openPinModal':openPinModal();break;case'closePinModal':closePinModal();break;case'savePin':savePin();break;case'viewPin':viewPin(id);break;case'editPin':editPin(id);break;case'downloadPin':downloadPin(id);break;case'archivePin':archivePin(id);break;case'togglePinArchives':togglePinArchives();break;case'openCorkSettings':openCorkSettings();break;case'closeCorkSettings':closeCorkSettings();break;case'saveCorkSettings':saveCorkSettings();break;case'resetPinLayout':resetPinLayout();break;case'rotatePin':rotatePin(id,el.dataset.dir);break;case'togglePinMenu':break;case'openDashPhoto':document.getElementById('dashPhotoInput')?.click();break;case'deleteDashPin':deleteDashPin(id);break;case'deleteGalleryDoc':deleteGalleryDoc(id);break;case'toggleCollapse':toggleIn(state.layout.collapsed[el.dataset.page],el.dataset.card);save('',true);break;case'toggleMax':toggleIn(state.layout.maximized[el.dataset.page],el.dataset.card);save('',true);break;case'resizeCard':{const p=el.dataset.page,c=el.dataset.card; const cur=state.layout.sizes[p][c]||'md'; const next={sm:'md',md:'lg',lg:'sm',xl:'sm'}[cur]||'lg'; state.layout.sizes[p][c]=next; save('',true);break;}case'removeDashCard':if(!state.layout.dashboardRemoved.includes(el.dataset.card))state.layout.dashboardRemoved.push(el.dataset.card); save('Dashboard box removed.');break;case'restoreDashCard':state.layout.dashboardRemoved=state.layout.dashboardRemoved.filter(x=>x!==el.dataset.card);save('Dashboard box added back.');break;case'resetPageLayout':state.layout.cardOrder[el.dataset.page]=pageCards[el.dataset.page]||[];state.layout.collapsed[el.dataset.page]=[];state.layout.maximized[el.dataset.page]=[];state.layout.sizes[el.dataset.page]={}; if(el.dataset.page==='dashboard')state.layout.dashboardRemoved=[]; save('Page layout reset.');break;case'changeDashboardStyle':state.layout.dashboardStyle=val('dashboardStyle');save('Dashboard look saved.');break;case'openWeeklyModal':state.weeklyModalOpen=true;renderAll();break;case'closeWeeklyModal':state.weeklyModalOpen=false;renderAll();break;case'addWeekly':addWeekly();state.weeklyModalOpen=false;break;case'viewWeekly':viewWeekly(id);break;case'openGalleryForItem':openGalleryForItem(el.dataset.area,id);break;case'editWeekly':state.editing.weekly[id]=true;renderAll();break;case'saveWeekly':saveWeekly(id);break;case'deleteWeekly':state.weekly=state.weekly.filter(x=>x.id!==id);save('Weekly block deleted.');break;case'downloadWeeklyCsv':downloadWeeklyCsv();break;case'shiftSchedule':shiftSchedule();break;case'openLessonModal':state.lessonModalOpen=true;renderAll();break;case'closeLessonModal':state.lessonModalOpen=false;renderAll();break;case'openStandardModal':state.standardModalOpen=true;renderAll();break;case'closeStandardModal':state.standardModalOpen=false;renderAll();break;case'closeStandardsGuide':if(document.getElementById('dontShowStandardGuide')?.checked){state.hideStandardsGuide=true;save('Standards explanation hidden. You can find it again in FAQ.');}else{standardsGuideClosedSession=true;renderAll();}break;case'addLesson':addLesson();state.lessonModalOpen=false;break;case'editLesson':state.editing.lessons[id]=true;state.activePage='lessons';renderAll();setTimeout(()=>document.querySelector(`[data-edit-lesson="${id}"]`)?.scrollIntoView({behavior:'smooth',block:'center'}),50);break;case'focusLesson':state.editing.lessons[id]=true;state.activePage='lessons';renderAll();setTimeout(()=>document.querySelector(`[data-edit-lesson="${id}"]`)?.scrollIntoView({behavior:'smooth',block:'center'}),50);break;case'saveLesson':saveLesson(id);break;case'toggleLessonReady':{const l=state.lessons.find(x=>x.id===id); if(l){l.subReady=!l.subReady;l.updatedAt=nowIso();save('Lesson status changed.');}break;}case'deleteLesson':state.lessons=state.lessons.filter(x=>x.id!==id);save('Lesson deleted.');break;case'clearLessonSearch':state.currentLessonSearch='';renderAll();break;case'addStudent':addStudent();break;case'editStudent':state.editing.students[id]=true;renderAll();break;case'saveStudent':saveStudent(id);break;case'archiveStudent':{const s=state.students.find(x=>x.id===id); if(s){s.archived=true;s.updatedAt=nowIso();save('Student archived.');}break;}case'restoreStudent':{const s=state.students.find(x=>x.id===id); if(s){s.archived=false;save('Student restored.');}break;}case'deleteStudent':state.students=state.students.filter(x=>x.id!==id); Object.keys(state.scores||{}).forEach(k=>{if(k.startsWith(id+'_'))delete state.scores[k];}); save('Student deleted.');break;case'addAssignment':addAssignment();break;case'editAssignment':state.editing.assignments[id]=true;renderAll();break;case'saveAssignment':saveAssignment(id);break;case'archiveAssignment':{const a=state.assignments.find(x=>x.id===id); if(a){a.archived=true;a.updatedAt=nowIso();save('Assignment archived.');}break;}case'restoreAssignment':{const a=state.assignments.find(x=>x.id===id); if(a){a.archived=false;save('Assignment restored.');}break;}case'deleteAssignment':state.assignments=state.assignments.filter(x=>x.id!==id); Object.keys(state.scores||{}).forEach(k=>{if(k.endsWith('_'+id))delete state.scores[k];}); save('Assignment deleted.');break;case'toggleGradeArchives':state.gradeViewArchives=!state.gradeViewArchives;renderAll();break;case'downloadGradesCsv':downloadGradesCsv();break;case'printGrades':printGrades();break;case'downloadStudentsCsv':downloadStudentsCsv();break;case'makeGroups':makeGroups();break;case'startTimer':startTimer();break;case'pauseTimer':pauseTimer();break;case'resetTimer':resetTimer();break;case'testSound':playSound();break;case'toggleMeetingForm':state.showMeetingForm=!state.showMeetingForm;renderAll();break;case'addMeeting':addMeeting();state.showMeetingForm=false;break;case'editMeeting':state.editing.meetings[id]=true;renderAll();break;case'saveMeeting':saveMeeting(id);break;case'deleteMeeting':state.meetings=state.meetings.filter(x=>x.id!==id);save('Meeting deleted.');break;case'addTodo':addTodo();break;case'editTodo':state.editing.todos[id]=true;renderAll();break;case'saveTodo':saveTodo(id);break;case'toggleTodo':{const t=state.todos.find(x=>x.id===id); if(t){t.done=!t.done;t.updatedAt=nowIso();save('Task updated.');}break;}case'archiveTodo':{const t=state.todos.find(x=>x.id===id); if(t){t.archived=!t.archived;t.updatedAt=nowIso();save(t.archived?'Task archived.':'Task restored.');}break;}case'toggleTodoArchives':state.todoViewArchives=!state.todoViewArchives;renderAll();break;case'deleteTodo':state.todos=state.todos.filter(x=>x.id!==id);save('Task deleted.');break;case'addReminder':addReminder();break;case'editReminder':state.editing.reminders[id]=true;renderAll();break;case'saveReminder':saveReminder(id);break;case'toggleReminder':{const r=state.reminders.find(x=>x.id===id); if(r){r.done=!r.done;r.updatedAt=nowIso();save('Reminder updated.');}break;}case'deleteReminder':state.reminders=state.reminders.filter(x=>x.id!==id);save('Reminder deleted.');break;case'requestNotifications':requestNotifications();break;case'saveNotificationSettings':saveNotificationSettings();break;case'testNotification':notify('SOZY Workspace test','Notifications are working if you can see this.');toast('Test notification sent if permission is allowed.');break;case'addRoutine':addRoutine();break;case'editRoutine':state.editing.routines[id]=true;renderAll();break;case'saveRoutine':saveRoutine(id);break;case'toggleRoutine':{const r=state.routines.find(x=>x.id===id); if(r){r.done=!r.done;r.updatedAt=nowIso();save('Routine updated.');}break;}case'deleteRoutine':state.routines=state.routines.filter(x=>x.id!==id);save('Routine deleted.');break;case'addSupply':addSupply();break;case'editSupply':state.editing.supplies[id]=true;renderAll();break;case'saveSupply':saveSupply(id);break;case'archiveSupply':{const s=state.supplies.find(x=>x.id===id); if(s){s.archived=true;s.updatedAt=nowIso();save('Supply archived.');}break;}case'restoreSupply':{const s=state.supplies.find(x=>x.id===id); if(s){s.archived=false;save('Supply restored.');}break;}case'deleteSupply':state.supplies=state.supplies.filter(x=>x.id!==id);save('Supply deleted.');break;case'toggleSupplyArchives':state.supplyViewArchives=!state.supplyViewArchives;renderAll();break;case'addStandard':addStandard();break;case'clearStandardSearch':state.currentStandardSearch='';renderAll();break;case'editStandard':state.editing.standards[id]=true;renderAll();break;case'saveStandard':saveStandard(id);break;case'deleteStandard':state.standards=state.standards.filter(x=>x.id!==id);save('Skill deleted.');break;case'saveSubNotes':saveSubNotes();break;case'undoSubNotes':undoSubNotes();break;case'clearSubNotes':clearSubNotes();break;case'printSubPacket':window.print();break;case'saveCustomTheme':saveCustomTheme();break;case'resetCustomTheme':resetCustomTheme();break;case'addMapDesk':addMapItem('desk');break;case'addMapTable':addMapItem('table');break;case'saveMapSettings':saveMapSettings();break;case'downloadMap':downloadMap();break;case'clearMap':clearMap();break;case'assignMapStudent':assignMapStudent(el.dataset.mapSelect,el.value);break;case'unassignMapItem':assignMapStudent(id,'');break;case'unassignMapStudent':unassignMapStudent(id,el.dataset.student);break;case'resizeMapItem':resizeMapItem(id);break;case'deleteMapItem':deleteMapItem(id);break;case'cancelEdit':delete state.editing[type][id];renderAll();break;}}
// Event delegation
document.addEventListener('click',e=>{if(pinSuppressClickUntil&&Date.now()<pinSuppressClickUntil&&e.target.closest('.dash-pin')){e.preventDefault(); e.stopPropagation(); return;} if(e.target.id==='pinModal'){closePinModal();return;} if(e.target.id==='corkSettingsModal'){closeCorkSettings();return;} if(e.target.id==='lessonModal'){state.lessonModalOpen=false;renderAll();return;} if(e.target.id==='weeklyModal'){state.weeklyModalOpen=false;renderAll();return;} if(e.target.id==='monthlyModal'){state.monthlyModalOpen=false;renderAll();return;} if(e.target.id==='standardModal'){state.standardModalOpen=false;renderAll();return;} const gp=e.target.closest('[data-gopage]'); if(gp){e.preventDefault(); goToPageCard(gp.dataset.gopage,gp.dataset.gocard||'');return;} const sw=e.target.closest('[data-theme]'); if(sw){e.preventDefault(); state.customTheme.enabled=false; state.theme=sw.dataset.theme; save('Theme saved.'); return;} const el=e.target.closest('[data-action]'); if(el){e.preventDefault(); try{handleAction(el.dataset.action,el);}catch(err){console.error('SOZY Workspace button error:',err);toast('That button had a hiccup. I kept your data safe. Try once more.');}}});
document.addEventListener('input',e=>{if(e.target.id==='lessonSearchInput'){state.currentLessonSearch=e.target.value; document.getElementById('lessonSearchResults').innerHTML=lessonSearchResults(); save('',false);} if(e.target.id==='standardSearchInput'){state.currentStandardSearch=e.target.value; const sl=document.getElementById('card-standards-standardList'); if(sl){sl.querySelector('.card-body').innerHTML=standardList();} save('',false);} if(e.target.id==='gallerySearchInput'){state.gallerySearch=e.target.value; const gl=document.getElementById('card-gallery-galleryList'); if(gl){gl.querySelector('.card-body').innerHTML=galleryListHtml();} save('',false);} if(e.target.id==='meetingFilterInput'){state.meetingFilter=e.target.value; const ml=document.getElementById('card-meetings-meetingForm'); if(ml){ml.querySelector('.card-body').innerHTML=meetingHtml();} save('',false);} if(e.target.id==='faqSearch'){state.faqSearch=e.target.value; document.getElementById('faqResults').innerHTML=faqResultsHtml(state.faqSearch);} if(e.target.id==='helpPageSearch'){state.faqSearch=e.target.value; const hp=document.getElementById('helpPageResults'); if(hp)hp.innerHTML=faqResultsHtml(state.faqSearch);} if(e.target.dataset.colorInput){const wrap=e.target.closest('.color-pick-wrap'); if(wrap){const chip=wrap.querySelector('.color-chip'); if(chip)chip.style.background=e.target.value; const hx=document.getElementById('ct_'+e.target.dataset.colorInput+'_hex'); if(hx)hx.textContent=e.target.value;}} if(e.target.dataset.subfield){state.subNotes.fields=state.subNotes.fields||{}; state.subNotes.fields[e.target.dataset.subfield]=e.target.value;}});
document.addEventListener('change',e=>{if(e.target.dataset.score)setScore(e.target); if(e.target.id==='restoreFile'&&e.target.files[0])restoreFile(e.target.files[0]); if(e.target.id==='dashPhotoInput'&&e.target.files[0])addDashPhotoFile(e.target.files[0]); if(e.target.id==='dashboardStyle'){state.layout.dashboardStyle=e.target.value; save('Dashboard look saved.');} if(e.target.id==='savedLessonFilter'){state.lessonFilter=e.target.value; save('Lesson filter saved.');} if(e.target.id==='savedLessonSort'){state.lessonSort=e.target.value; save('Lesson order saved.');} if(e.target.id==='galleryFilter'){state.galleryFilter=e.target.value; save('Gallery filter saved.');} if(e.target.id==='meetingOrder'){state.meetingOrder=e.target.value; save('Meeting order saved.');} if(e.target.dataset.attachArea&&e.target.files?.length){addFilesToGallery(e.target.files,e.target.dataset.attachArea,e.target.dataset.attachId||'',e.target.dataset.attachLabel||''); e.target.value='';} });
document.addEventListener('dragstart',e=>{const chip=e.target.closest('[data-student-chip]'); if(chip){dragItem={type:'student',id:chip.dataset.studentChip}; e.dataTransfer.setData('text/plain',dragItem.id); return;} const mi=e.target.closest('[data-map-id]'); if(mi&&!e.target.closest('select,button,.resize-corner')){dragItem={type:'mapItem',id:mi.dataset.mapId,offsetX:e.offsetX,offsetY:e.offsetY}; e.dataTransfer.setData('text/plain',dragItem.id); return;} const h=e.target.closest('.drag-handle,.nav-handle'); if(!h)return; const card=h.closest('.card'); const menu=h.closest('[data-menu-row]')||h.closest('.navbtn'); if(card){dragItem={type:'card',page:card.dataset.pageCard,id:card.dataset.cardId}; card.classList.add('dragging'); e.dataTransfer.setData('text/plain',dragItem.id);} else if(menu){dragItem={type:'menu',id:menu.dataset.menuRow||menu.dataset.page}; e.dataTransfer.setData('text/plain',dragItem.id);}});
document.addEventListener('dragover',e=>{const card=e.target.closest('.card'); const menu=e.target.closest('[data-menu-row],.navbtn'); const board=e.target.closest('[data-classroom-board]'); const mapItem=e.target.closest('[data-map-id]'); if(dragItem&&card&&dragItem.type==='card'&&card.dataset.pageCard===dragItem.page){e.preventDefault(); card.classList.add('drag-over');} if(dragItem&&menu&&dragItem.type==='menu'){e.preventDefault();} if(dragItem&&board&&dragItem.type==='mapItem'){e.preventDefault();} if(dragItem&&mapItem&&dragItem.type==='student'){e.preventDefault();}});
document.addEventListener('dragleave',e=>{const card=e.target.closest('.card'); if(card)card.classList.remove('drag-over');});
document.addEventListener('drop',e=>{const card=e.target.closest('.card'); const menu=e.target.closest('[data-menu-row],.navbtn'); const board=e.target.closest('[data-classroom-board]'); const mapItem=e.target.closest('[data-map-id]'); if(dragItem&&card&&dragItem.type==='card'&&card.dataset.pageCard===dragItem.page){e.preventDefault(); reorderArray(state.layout.cardOrder[dragItem.page],dragItem.id,card.dataset.cardId); dragItem=null; save('Box order saved.'); return;} if(dragItem&&menu&&dragItem.type==='menu'){e.preventDefault(); reorderArray(state.layout.menuOrder,dragItem.id,menu.dataset.menuRow||menu.dataset.page); dragItem=null; save('Menu order saved.'); return;} if(dragItem&&mapItem&&dragItem.type==='student'){e.preventDefault(); assignMapStudent(mapItem.dataset.mapId,dragItem.id); dragItem=null; return;} if(dragItem&&board&&dragItem.type==='mapItem'){e.preventDefault(); const rect=board.getBoundingClientRect(); moveMapItem(dragItem.id,e.clientX-rect.left-(dragItem.offsetX||20),e.clientY-rect.top-(dragItem.offsetY||20)); dragItem=null; return;}});
document.addEventListener('dragend',()=>{dragItem=null; document.querySelectorAll('.drag-over,.dragging').forEach(x=>x.classList.remove('drag-over','dragging'));});

document.addEventListener('mousedown',e=>{const h=e.target.closest('[data-resize-map]'); if(!h)return; e.preventDefault(); e.stopPropagation(); const it=(state.classroomMap.items||[]).find(x=>x.id===h.dataset.resizeMap); if(!it)return; resizeDrag={id:it.id,startX:e.clientX,startY:e.clientY,w:Number(it.w)||110,h:Number(it.h)||80}; document.body.classList.add('map-resizing');});
document.addEventListener('mousemove',e=>{if(!resizeDrag)return; e.preventDefault(); const it=(state.classroomMap.items||[]).find(x=>x.id===resizeDrag.id); if(!it)return; it.w=Math.max(82,Math.round(resizeDrag.w+(e.clientX-resizeDrag.startX))); it.h=Math.max(60,Math.round(resizeDrag.h+(e.clientY-resizeDrag.startY))); const el=document.querySelector(`[data-map-id="${resizeDrag.id}"]`); if(el){el.style.width=it.w+'px'; el.style.height=it.h+'px';}});
document.addEventListener('mouseup',()=>{if(!resizeDrag)return; const it=(state.classroomMap.items||[]).find(x=>x.id===resizeDrag.id); if(it)it.updatedAt=nowIso(); resizeDrag=null; document.body.classList.remove('map-resizing'); save('Furniture size saved.');});


document.addEventListener('mousedown',e=>{const pin=e.target.closest('.dash-pin[data-pin-id]'); if(!pin||!state.corkSettings?.freeMove||e.target.closest('button,.pin-menu'))return; const board=pin.closest('[data-pin-board]'); const p=(state.dashboardPins||[]).find(x=>x.id===pin.dataset.pinId); if(!board||!p)return; e.preventDefault(); const maxZ=Math.max(2,...(state.dashboardPins||[]).map(x=>Number(x.z)||2)); p.z=maxZ+1; const rect=board.getBoundingClientRect(); pinDrag={id:p.id,startX:e.clientX,startY:e.clientY,origX:Number(p.x)||0,origY:Number(p.y)||0,boardW:rect.width,boardH:rect.height,moved:false}; pin.style.zIndex=p.z;});
document.addEventListener('mousemove',e=>{if(!pinDrag)return; const p=(state.dashboardPins||[]).find(x=>x.id===pinDrag.id); if(!p)return; const dx=e.clientX-pinDrag.startX, dy=e.clientY-pinDrag.startY; if(Math.abs(dx)>2||Math.abs(dy)>2)pinDrag.moved=true; p.x=Math.max(0,Math.min(pinDrag.boardW-70,Math.round(pinDrag.origX+dx))); p.y=Math.max(0,Math.min(pinDrag.boardH-50,Math.round(pinDrag.origY+dy))); const el=document.querySelector(`[data-pin-id="${pinDrag.id}"]`); if(el){el.style.left=p.x+'px'; el.style.top=p.y+'px'; el.style.zIndex=p.z;}});
document.addEventListener('mouseup',()=>{if(!pinDrag)return; const p=(state.dashboardPins||[]).find(x=>x.id===pinDrag.id); if(p){p.updatedAt=nowIso(); save('',false);} if(pinDrag.moved)pinSuppressClickUntil=Date.now()+300; pinDrag=null;});


/* Restored helper functions for render stability */
function areaName(area){return ({weekly:'Weekly Planner',lessons:'Lesson Library',students:'My Students',assignments:'Student Assignments',meetings:'Meetings',todos:'To-Dos',standards:'Standards / Skills',general:'Gallery'})[area]||area;}
function areaToCard(area){return ({weekly:'board',lessons:'lessonList',students:'students',assignments:'assignments',meetings:'meetingForm',todos:'todoList',standards:'standardList',general:'galleryList'})[area]||'galleryList';}
function areaToPage(area){return ({weekly:'planner',lessons:'lessons',students:'grades',assignments:'grades',meetings:'meetings',todos:'meetings',standards:'standards',general:'gallery'})[area]||'gallery';}
function customThemeHtml(){const c=state.customTheme; const rows=[['bg','Background'],['surface','Cards'],['surface2','Soft panels'],['ink','Text'],['muted','Muted text'],['brand','Main color'],['brand2','Second color'],['brand3','Third color'],['line','Border lines']]; return `<p class="tiny">Use this if the premade themes are not enough. Pick colors, save, and the app becomes your own.</p><label><input type="checkbox" id="customEnabled" ${c.enabled?'checked':''} style="width:auto"> Use my custom colors</label><div class="color-row">${rows.map(([k,l])=>`<div class="color-pick-wrap"><label>${l}</label><input type="color" id="ct_${k}" data-color-input="${k}" value="${esc(c[k])}"><div class="color-chip" style="background:${esc(c[k])}"></div><small class="color-hex" id="ct_${k}_hex">${esc(c[k])}</small></div>`).join('')}</div><div class="actions"><button data-action="saveCustomTheme">Save custom theme</button><button class="secondary" data-action="resetCustomTheme">Reset custom colors</button></div>`;}
function docsFor(area,itemId){return (state.gallery||[]).filter(d=>d.area===area&&String(d.itemId||'')===String(itemId||''));}
function helpPage(){return renderCards('help',[['helpFull',card('help','helpFull','❓ Help / FAQ',`<input id="helpPageSearch" placeholder="Search help questions..." value="${esc(state.faqSearch)}"><div id="helpPageResults">${faqResultsHtml(state.faqSearch)}</div>`,{size:'lg'})]],'grid');}
function lessonSearchResults(){const term=(state.currentLessonSearch||'').toLowerCase().trim(); if(!term)return ''; const list=state.lessons.filter(l=>!l.archived&&Object.values(l).join(' ').toLowerCase().includes(term)); return list.map(l=>`<div class="item lesson-result" data-action="focusLesson" data-id="${l.id}" title="Click to open and edit this lesson"><div class="item-title">${esc(l.title)}</div><div class="item-meta">${esc(l.subject)} • ${esc(l.standard)} • ${esc(l.lexile||'n/a')} • ${esc(l.theme||'none')} • ${l.subReady?'Sub-ready':'Needs prep'}</div><p class="tiny">${esc(l.summary)}</p></div>`).join('')||empty('No matching lessons found. Try a simpler word.');}
function linkedItemLabel(area,itemId){let x=null; if(area==='weekly')x=state.weekly.find(i=>i.id===itemId); if(area==='lessons')x=state.lessons.find(i=>i.id===itemId); if(area==='students')x=state.students.find(i=>i.id===itemId); if(area==='assignments')x=state.assignments.find(i=>i.id===itemId); if(area==='meetings')x=state.meetings.find(i=>i.id===itemId); if(area==='todos')x=state.todos.find(i=>i.id===itemId); if(area==='standards')x=state.standards.find(i=>i.id===itemId); return (x&&(x.title||x.name||x.text||x.skill||x.item))||'General file';}
function menuSettingsHtml(){return `<p class="tiny">Drag main menu items with ☰. Hide top-level pages you do not need. The Tools & Resources submenu stays grouped so it is easier to use.</p>${orderedPages().map(p=>`<div class="menu-list-row" data-menu-row="${p[0]}"><span class="nav-handle" draggable="true" title="Drag page">☰</span><span>${p[1]} ${p[2]}<br><small>${esc(p[3])}</small></span><button class="small secondary" data-action="toggleMenuPage" data-page="${p[0]}">${state.layout.menuHidden.includes(p[0])?'Show':'Hide'}</button></div>`).join('')}<div class="actions"><button class="secondary" data-action="resetMenu">Reset menu</button></div>`;}
function settingsPage(){return `<div class="settings-stack">
 <details class="settings-box"><summary>💾 Backup / restore</summary><div class="settings-content"><p class="tiny">Backup makes one private JSON save file. Restore loads that save file back into this browser.</p><div class="actions"><button data-action="backup">⬇ Backup data</button><button class="secondary" data-action="restoreClick">⬆ Restore data</button><input id="restoreFile" type="file" accept="application/json" style="display:none"></div><div class="archive-box"><b>Plain-English reminder</b><p class="tiny">A backup file saves your planner, lessons, Gallery files, grades, student list, assignments, scores, meetings, tasks, reminders, routines, supplies, standards, classroom map, substitute notes, themes, and layout settings. Keep it private because it can contain classroom information.</p></div></div></details>
 <details class="settings-box"><summary>🎨 Theme collection</summary><div class="settings-content"><p class="tiny">Pick a ready-made look. This saves on this device.</p><div class="swatches">${themeList.map(t=>`<div class="swatch ${(!state.customTheme.enabled&&state.theme===t[0])?'active':''}" data-theme="${t[0]}" style="background:linear-gradient(135deg,${t[2]},${t[3]},${t[4]})">${esc(t[1])}</div>`).join('')}</div></div></details>
 <details class="settings-box"><summary>🖌️ Custom colors</summary><div class="settings-content">${customThemeHtml()}</div></details>
 <details class="settings-box"><summary>🔊 Notifications & sounds</summary><div class="settings-content">${notificationHtml()}</div></details>
 <details class="settings-box"><summary>❓ Help / FAQ</summary><div class="settings-content"><input id="helpPageSearch" placeholder="Search help questions..." value="${esc(state.faqSearch)}"><div id="helpPageResults">${faqResultsHtml(state.faqSearch)}</div></div></details>
 <details class="settings-box"><summary>☰ Menu Layout</summary><div class="settings-content">${menuSettingsHtml()}</div></details>
</div>`;}
function subNotesHtml(){const f=state.subNotes.fields||{}; const status=(JSON.stringify(f)!==state.subNotes.saved)?'Unsaved changes':'Saved locally'; return `<p class="tiny">Answer the prompts. They are written like questions so teachers know what a substitute needs.</p>${subPrompt('overview','Class overview','What should the sub know about your class personality, energy level, or general expectations?',f.overview)}${subPrompt('attendance','Attendance / lunch count','How should attendance, lunch count, bathroom passes, or office notes be handled?',f.attendance)}${subPrompt('schedule','Daily flow','What does the normal day look like? What should not be skipped?',f.schedule)}${subPrompt('behavior','Behavior support','What behavior system, rewards, consequences, calming tools, or redirection words should the sub use?',f.behavior)}${subPrompt('students','Student support notes','Are there students who may need extra help, seating reminders, medical attention, or quiet support? Keep this professional and need-to-know.',f.students)}${subPrompt('materials','Materials / technology','Where are worksheets, books, logins, remotes, projector tools, and center materials? Avoid writing private passwords if your school does not allow it.',f.materials)}${subPrompt('emergency','Emergency procedures','What should the sub do for fire drill, lockdown, nurse, office call, or urgent classroom help?',f.emergency)}${subPrompt('dismissal','Dismissal','How do students leave? Bus, pickup, after-school program, walkers, or dismissal jobs?',f.dismissal)}${subPrompt('extra','Extra Comments','Anything else the substitute should know that does not fit above?',f.extra)}<div class="split"><div class="${status.startsWith('Unsaved')?'unsaved-status':'saved-status'}">${status}${state.subNotes.lastSaved?' • '+fmt(state.subNotes.lastSaved):''}</div><div class="actions"><button data-action="saveSubNotes">Save changes</button><button class="secondary" data-action="undoSubNotes">Undo</button><button class="danger" data-action="clearSubNotes">Clear all</button></div></div>`;}
function subPrompt(id,label,help,value){return `<label>${label}</label><p class="tiny">${help}</p><textarea data-subfield="${id}" id="sub_${id}">${esc(value||'')}</textarea>`;}
function subhubPage(){const defs=[['subNotes',card('subhub','subNotes','📝 Substitute notes',subNotesHtml(),{size:'lg'})],['subReadiness',card('subhub','subReadiness','🧰 Sub-readiness checklist',readinessList(false))],['subPacket',card('subhub','subPacket','📄 Substitute packet export',`<p class="tiny">This creates a clean packet using your saved notes, schedule, routines, sub-ready lessons, supplies, reminders, and grade-safe teacher notes.</p><div class="actions"><button data-action="printSubPacket">Print / Save as PDF</button></div><div id="packetPreview" class="archive-box">${subPacketHtml()}</div>`,{size:'lg'})]]; return renderCards('subhub',defs,'grid');}
function themesPage(){return renderCards('themes',[['themeChooser',card('themes','themeChooser','🎨 Theme collection',`<p class="tiny">Pick a ready-made look. This saves on this device.</p><div class="swatches">${themeList.map(t=>`<div class="swatch ${(!state.customTheme.enabled&&state.theme===t[0])?'active':''}" data-theme="${t[0]}" style="background:linear-gradient(135deg,${t[2]},${t[3]},${t[4]})">${esc(t[1])}</div>`).join('')}</div>`,{size:'lg'})],['customTheme',card('themes','customTheme','🖌️ Custom colors',customThemeHtml(),{size:'lg'})]],'grid');}


/* SOZY Workspace design + monthly planner patch 2026-06-06_1856-CT */
const sozyFontOptions=[
 ['system','System clean','Inter, ui-sans-serif, system-ui, -apple-system, Segoe UI, Arial, sans-serif'],
 ['rounded','Rounded cozy','Arial Rounded MT Bold, Trebuchet MS, Arial, sans-serif'],
 ['serif','Soft serif','Georgia, Times New Roman, serif'],
 ['modern','Modern desk','Avenir Next, Montserrat, Helvetica, Arial, sans-serif'],
 ['mono','Neat notes','ui-monospace, SFMono-Regular, Menlo, Consolas, monospace']
];
const corkFontOptions=[
 ['comic','Cozy marker','Comic Sans MS, Marker Felt, Bradley Hand, cursive'],
 ['bradley','Gentle hand','Bradley Hand, Comic Sans MS, cursive'],
 ['chalk','Chalk note','Chalkboard SE, Comic Sans MS, cursive'],
 ['marker','Marker note','Marker Felt, Comic Sans MS, cursive'],
 ['casual','Casual note','Segoe Print, Comic Sans MS, cursive']
];
const corkBorderPresets=[['theme','Theme border','theme'],['blush','#f5b7c8','#f5b7c8'],['lavender','#cdb8ff','#cdb8ff'],['sage','#9fc8a9','#9fc8a9'],['sky','#9ed8f5','#9ed8f5'],['lemon','#f1d36b','#f1d36b'],['mocha','#b8865b','#b8865b'],['ink','#4b4b5f','#4b4b5f']];
const corkBoardColors=[['natural','Natural brown','#d6a777'],['light','Light brown','#e4c79c'],['dark','Deep cork','#b6844f'],['white','White board','#faf8f1'],['black','Black board','#23232c'],['theme','Use theme soft panel','theme']];
function ensureSozyUpgrades(){
 if(!pages.some(p=>p[0]==='monthly')) pages.splice(2,0,['monthly','🗓️','Monthly Planner','Plan a full month, see important dates, and download a monthly plan.']);
 if(!topMenuIds.includes('monthly')) topMenuIds.splice(2,0,'monthly');
 pageCards.monthly=pageCards.monthly||['month'];
 state.monthly=state.monthly||[{id:uid('month'),date:new Date().toISOString().slice(0,10),subject:'Planning',title:'Check monthly pacing',note:'Add key lessons, events, testing windows, and school dates here.',createdAt:nowIso(),updatedAt:nowIso()}];
 state.monthlyView=state.monthlyView||new Date().toISOString().slice(0,7);
 state.monthlyModalOpen=!!state.monthlyModalOpen;
 state.editing.monthly=state.editing.monthly||{};
 state.workspaceFont=state.workspaceFont||'system';
 state.standardFilter=state.standardFilter||'all';
 state.standardSort=state.standardSort||'updated';
 state.settingsOpenSection=state.settingsOpenSection||'';
 state.corkSettings=merge({freeMove:false,floralBorder:true,borderDesign:'floral',borderColor:'theme',customBorder:'#f5b7c8',boardColor:'natural',customBoard:'#d6a777',font:'comic',matchWorkspaceFont:false,matchThemeText:true}, state.corkSettings||{});
}
const originalApplyTheme=applyTheme;
applyTheme=function(){originalApplyTheme(); ensureSozyUpgrades(); const r=document.documentElement.style; const appFont=(sozyFontOptions.find(f=>f[0]===state.workspaceFont)||sozyFontOptions[0])[2]; r.setProperty('--app-font',appFont); const c=state.corkSettings||{}; const theme=themeList.find(x=>x[0]===state.theme)||themeList[0]; const border=c.borderColor==='theme'?(state.customTheme.enabled?state.customTheme.brand2:theme[3]):(c.borderColor==='custom'?c.customBorder:(c.borderColor||'#f5b7c8')); const board=c.boardColor==='theme'?(state.customTheme.enabled?state.customTheme.surface2:theme[4]):(c.boardColor==='custom'?c.customBoard:(corkBoardColors.find(x=>x[0]===c.boardColor)?.[2]||'#d6a777')); const corkFont=c.matchWorkspaceFont?appFont:(corkFontOptions.find(f=>f[0]===c.font)||corkFontOptions[0])[2]; const textColor=c.matchThemeText?'var(--ink)':(board==='#23232c'?'#fffaf0':'#2b2018'); r.setProperty('--cork-border',border); r.setProperty('--cork-bg',board); r.setProperty('--cork-font',corkFont); r.setProperty('--cork-text',textColor);};
const originalNormalize=normalize;
normalize=function(){originalNormalize(); ensureSozyUpgrades();};
renderAll=function(){normalize(); applyTheme(); document.getElementById('app').classList.toggle('menu-hidden',!!state.menuHidden); renderNav(); renderMiniThemes(); renderHeader(); renderPages(); renderMenuPanel(); renderPinModal(); renderCorkSettingsModal(); renderLessonModal(); renderWeeklyModal(); renderMonthlyModal(); renderStandardModal(); renderPrint(); renderStatus(); scheduleReminderCheck();};
renderMiniThemes=function(){const el=document.getElementById('quickThemePop'); if(!el)return; el.classList.toggle('open',!!state.quickThemesOpen); el.innerHTML=`<h4>Quick themes</h4><div class="mini-themes">${themeList.slice(0,19).map(t=>`<button class="mini-swatch ${(!state.customTheme.enabled&&state.theme===t[0])?'active':''}" aria-label="${esc(t[1])}" title="${esc(t[1])}" data-theme="${t[0]}" style="background:linear-gradient(135deg,${t[2]} 0%,${t[3]} 52%,${t[4]} 100%)!important"></button>`).join('')}</div>`;};
renderPage=function(id){let html=(state.layout.openSettingsPage===id?pageSettingsPanel(id):''); switch(id){case 'dashboard':return html+dashboardPage();case 'planner':return html+plannerPage();case 'monthly':return html+monthlyPage();case 'lessons':return html+lessonsPage();case 'gallery':return html+galleryPage();case 'grades':return html+gradesPage();case 'meetings':return html+meetingsPage();case 'standards':return html+standardsPage();case 'groups':return html+groupsPage();case 'timer':return html+timerPage();case 'reminders':return html+remindersPage();case 'map':return html+mapPage();case 'routines':return html+routinesOnlyPage();case 'supplies':return html+suppliesOnlyPage();case 'subnotes':return html+subnotesPage();case 'subreadiness':return html+subreadinessPage();case 'subexport':return html+subexportPage();case 'settings':return html+settingsPage();case 'tools':return toolsLandingPage();default:return html+dashboardPage();}};
function workspaceFontHtml(){return `<p class="tiny">Choose the main font for the workspace. This changes menus, cards, settings, planners, and most app text.</p><div class="font-row"><div><label>Workspace font</label><select id="workspaceFontSelect">${sozyFontOptions.map(f=>`<option value="${f[0]}" ${state.workspaceFont===f[0]?'selected':''}>${f[1]}</option>`).join('')}</select></div><div class="font-preview" style="font-family:${(sozyFontOptions.find(f=>f[0]===state.workspaceFont)||sozyFontOptions[0])[2]}"><b>Preview:</b><br>Plan lessons. Track grades. Stay cozy.</div></div>`;}
settingsPage=function(){const open=(s)=>state.settingsOpenSection===s?' open':''; return `<div class="settings-stack">
 <details class="settings-box"${open('backup')}><summary>💾 Backup / restore</summary><div class="settings-content"><p class="tiny">Backup makes one private JSON save file. Restore loads that save file back into this browser.</p><div class="actions"><button data-action="backup">⬇ Backup data</button><button class="secondary" data-action="restoreClick">⬆ Restore data</button><input id="restoreFile" type="file" accept="application/json" style="display:none"></div><div class="archive-box"><b>Plain-English reminder</b><p class="tiny">A backup file saves your planner, monthly planner, lessons, Gallery files, grades, student list, assignments, scores, meetings, tasks, reminders, routines, supplies, standards, classroom map, substitute notes, themes, fonts, cork board, and layout settings. Keep it private because it can contain classroom information.</p></div></div></details>
 <details class="settings-box"${open('themes')}><summary>🎨 Theme collection</summary><div class="settings-content"><p class="tiny">Pick a ready-made look. This saves on this device.</p><div class="swatches">${themeList.map(t=>`<div class="swatch ${(!state.customTheme.enabled&&state.theme===t[0])?'active':''}" data-theme="${t[0]}" style="background:linear-gradient(135deg,${t[2]},${t[3]},${t[4]})">${esc(t[1])}</div>`).join('')}</div></div></details>
 <details class="settings-box"${open('fonts')}><summary>🔤 Font style</summary><div class="settings-content">${workspaceFontHtml()}</div></details>
 <details class="settings-box"${open('colors')}><summary>🖌️ Custom colors</summary><div class="settings-content">${customThemeHtml()}</div></details>
 <details class="settings-box"${open('notifications')}><summary>🔊 Notifications & sounds</summary><div class="settings-content">${notificationHtml()}</div></details>
 <details class="settings-box"${open('help')}><summary>❓ Help / FAQ</summary><div class="settings-content"><input id="helpPageSearch" placeholder="Search help questions..." value="${esc(state.faqSearch)}"><div id="helpPageResults">${faqResultsHtml(state.faqSearch)}</div></div></details>
 <details class="settings-box"${open('menu')}><summary>☰ Menu Layout</summary><div class="settings-content">${menuSettingsHtml()}</div></details>
</div>`;};
function corkSettingsHtml(){const c=state.corkSettings||{}; const borderVal=c.borderColor||'theme'; const boardVal=c.boardColor||'natural'; return `<p class="tiny">Design the cork board separately from the rest of the workspace. Changes preview right away.</p>
<label class="setting-row"><input type="checkbox" id="corkFreeMove" ${c.freeMove?'checked':''}> Let me move, overlap, and rotate pins anywhere on the board.</label>
<div class="formrow three"><div><label>Border design</label><select id="corkDesign"><option value="floral" ${c.borderDesign==='floral'?'selected':''}>Soft floral</option><option value="botanical" ${c.borderDesign==='botanical'?'selected':''}>Simple botanical</option><option value="stars" ${c.borderDesign==='stars'?'selected':''}>Tiny stars</option><option value="scallop" ${c.borderDesign==='scallop'?'selected':''}>Scalloped/dashed</option><option value="simple" ${c.borderDesign==='simple'?'selected':''}>Simple clean</option><option value="none" ${c.borderDesign==='none'?'selected':''}>No decoration</option></select></div><div><label>Border color</label><select id="corkBorderColor">${corkBorderPresets.map(p=>`<option value="${p[0]}" ${borderVal===p[0]?'selected':''}>${p[1]}</option>`).join('')}<option value="custom" ${borderVal==='custom'?'selected':''}>Pick my own</option></select></div><div><label>Custom border color</label><input type="color" id="corkCustomBorder" value="${esc(c.customBorder||'#f5b7c8')}"></div></div>
<div class="formrow three"><div><label>Main board color</label><select id="corkBoardColor">${corkBoardColors.map(p=>`<option value="${p[0]}" ${boardVal===p[0]?'selected':''}>${p[1]}</option>`).join('')}<option value="custom" ${boardVal==='custom'?'selected':''}>Pick my own</option></select></div><div><label>Custom board color</label><input type="color" id="corkCustomBoard" value="${esc(c.customBoard||'#d6a777')}"></div><div><label>Board preview</label><div class="board-preview"></div></div></div>
<div class="formrow two"><div><label>Cork board handwriting font</label><select id="corkFont">${corkFontOptions.map(f=>`<option value="${f[0]}" ${c.font===f[0]?'selected':''}>${f[1]}</option>`).join('')}</select></div><div><label>Font sync</label><label class="setting-row"><input type="checkbox" id="corkMatchFont" ${c.matchWorkspaceFont?'checked':''}> Use workspace font instead of handwriting.</label></div></div>
<label class="setting-row"><input type="checkbox" id="corkMatchText" ${c.matchThemeText!==false?'checked':''}> Make board text match the workspace theme.</label>
<div class="tiny">Tip: when free move is on, drag a pin to move it. Use the pin’s ⋯ menu to rotate, edit, archive, download, or delete it.</div><div class="actions"><button data-action="saveCorkSettings">Save Cork Board Settings</button><button class="secondary" data-action="resetPinLayout">Reset pin layout</button></div>`;}
dashboardCorkBoard=function(){const showArch=!!state.showArchivedPins; const pins=(state.dashboardPins||[]).filter(p=>showArch?!!p.archived:!p.archived); const free=!!state.corkSettings?.freeMove; const design=state.corkSettings?.borderDesign||'floral'; return `<div class="cork-toolbar"><button class="secondary" data-action="openPinModal">Add a Pin</button><button class="secondary" data-action="togglePinArchives">${showArch?'Hide archives':'View archives'}</button><button class="secondary" data-action="openCorkSettings">Cork Board Settings</button></div><section class="dashboard-cork design-${esc(design)}"><div class="pin-board ${free?'free':''}" data-pin-board>${pins.map((p,i)=>dashPinHtml(p,i,free)).join('')||empty(showArch?'No archived pins.':'No pins yet. Add a note, file, or photo highlight.')}</div></section>`;};
function applyCorkSettingsFromInputs(){state.corkSettings=state.corkSettings||{}; state.corkSettings.freeMove=!!document.getElementById('corkFreeMove')?.checked; state.corkSettings.borderDesign=val('corkDesign')||'floral'; state.corkSettings.borderColor=val('corkBorderColor')||'theme'; state.corkSettings.customBorder=val('corkCustomBorder')||'#f5b7c8'; state.corkSettings.boardColor=val('corkBoardColor')||'natural'; state.corkSettings.customBoard=val('corkCustomBoard')||'#d6a777'; state.corkSettings.font=val('corkFont')||'comic'; state.corkSettings.matchWorkspaceFont=!!document.getElementById('corkMatchFont')?.checked; state.corkSettings.matchThemeText=!!document.getElementById('corkMatchText')?.checked;}
saveCorkSettings=function(){applyCorkSettingsFromInputs(); state.corkSettingsOpen=false; save('Cork board settings saved.');};
function monthKey(d){return (d||'').slice(0,7);} function monthTitle(key){const [y,m]=String(key||new Date().toISOString().slice(0,7)).split('-').map(Number); return new Date(y,m-1,1).toLocaleString([], {month:'long',year:'numeric'});} function monthDays(key){const [y,m]=String(key).split('-').map(Number); const first=new Date(y,m-1,1); const start=new Date(first); start.setDate(first.getDate()-first.getDay()); const arr=[]; for(let i=0;i<42;i++){const d=new Date(start);d.setDate(start.getDate()+i); arr.push(d);} return arr;}
function monthlyPage(){return `<div class="plain-block"><div class="month-toolbar"><button data-action="openMonthlyModal">➕ Add Monthly Block</button><button class="secondary" data-action="downloadMonthlyCsv">Download Monthly Plan</button></div></div>${renderCards('monthly',[["month",card('monthly','month','🗓️ Monthly Plan',monthlyCalendarHtml(),{size:'lg',controls:false})]],'grid')}`;}
function monthlyCalendarHtml(){const key=state.monthlyView||new Date().toISOString().slice(0,7); const list=state.monthly||[]; const today=new Date().toISOString().slice(0,10); return `<div class="month-header"><button class="secondary small" data-action="prevMonth">‹ Previous</button><div><b>${monthTitle(key)}</b><div class="tiny">Monthly view mirrors the weekly planner, but gives the teacher a full-month picture.</div></div><button class="secondary small" data-action="nextMonth">Next ›</button></div><div class="month-grid">${['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].map(d=>`<div class="month-day-name">${d}</div>`).join('')}${monthDays(key).map(d=>{const iso=d.toISOString().slice(0,10); const items=list.filter(x=>x.date===iso); return `<div class="month-cell ${monthKey(iso)!==key?'other':''} ${iso===today?'today':''}"><div class="month-date">${d.getDate()}</div>${items.map(monthlyEntryHtml).join('')}</div>`;}).join('')}</div>`;}
function monthlyEntryHtml(x){if(state.editing.monthly[x.id])return `<div class="month-item"><label>Title</label><input id="em_title_${x.id}" value="${esc(x.title||'')}"><label>Date</label><input type="date" id="em_date_${x.id}" value="${esc(x.date||'')}"><label>Subject</label><input id="em_subject_${x.id}" value="${esc(x.subject||'')}"><label>Note</label><textarea id="em_note_${x.id}">${esc(x.note||'')}</textarea><div class="actions"><button class="small good" data-action="saveMonthly" data-id="${x.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="monthly" data-id="${x.id}">Cancel</button></div></div>`;const isWeekly=(x._source||'monthly')==='weekly';const id=esc(x._sourceId||x.id);const meta=[x.time,x.subject,isWeekly?'Weekly Planner':'Monthly Planner'].filter(Boolean).join(' • ');return `<button class="month-item clickable-month-item ${isWeekly?'month-weekly':'month-local'}" data-action="viewMonthlyVisible" data-source="${isWeekly?'weekly':'monthly'}" data-id="${id}" type="button"><span class="month-click-title">${esc(x.title||x.subject||'Monthly item')}</span><span class="month-click-meta">${esc(meta)}</span></button>`;}
function renderMonthlyModal(){const modal=document.getElementById('monthlyModal'); if(!modal)return; modal.classList.toggle('open',!!state.monthlyModalOpen); const body=document.getElementById('monthlyModalBody'); if(body)body.innerHTML=monthlyForm();}
function monthlyForm(){return `<div class="formrow three"><div><label>Date</label><input type="date" id="monthDate" value="${new Date().toISOString().slice(0,10)}"></div><div><label>Subject</label><input id="monthSubject" placeholder="Reading, Math, Event"></div><div><label>Title</label><input id="monthTitle" placeholder="Unit launch, testing, field trip"></div></div><label>Note</label><textarea id="monthNote" placeholder="Add monthly notes here..."></textarea><div class="actions"><button data-action="addMonthly">Save monthly block</button><button class="secondary" data-action="closeMonthlyModal">Cancel</button></div>`;}
function addMonthly(){const t=nowIso(); state.monthly.push({id:uid('month'),date:val('monthDate')||new Date().toISOString().slice(0,10),subject:val('monthSubject'),title:val('monthTitle')||'Monthly block',note:val('monthNote'),createdAt:t,updatedAt:t}); state.monthlyView=(val('monthDate')||new Date().toISOString().slice(0,10)).slice(0,7); save('Monthly block added.');}
function saveMonthly(id){const x=state.monthly.find(i=>i.id===id); if(!x)return; x.title=val('em_title_'+id); x.date=val('em_date_'+id); x.subject=val('em_subject_'+id); x.note=val('em_note_'+id); x.updatedAt=nowIso(); delete state.editing.monthly[id]; state.monthlyView=(x.date||new Date().toISOString().slice(0,10)).slice(0,7); save('Monthly block saved.');}
function downloadMonthlyCsv(){downloadText('sozy-monthly-plan.csv',csv(['Date','Subject','Title','Note','Updated'],(state.monthly||[]).map(x=>[x.date,x.subject,x.title,x.note,fmt(x.updatedAt)])));}
function fontSettingsChanged(id,value){state.workspaceFont=value||'system'; save('Workspace font saved.');}
const originalHandleAction=handleAction;
handleAction=function(action,el){switch(action){case'openMonthlyModal':state.monthlyModalOpen=true;renderAll();break;case'closeMonthlyModal':state.monthlyModalOpen=false;renderAll();break;case'addMonthly':addMonthly();state.monthlyModalOpen=false;break;case'editMonthly':state.editing.monthly[el.dataset.id]=true;renderAll();break;case'saveMonthly':saveMonthly(el.dataset.id);break;case'deleteMonthly':state.monthly=state.monthly.filter(x=>x.id!==el.dataset.id);save('Monthly block deleted.');break;case'downloadMonthlyCsv':downloadMonthlyCsv();break;case'prevMonth':{const [y,m]=state.monthlyView.split('-').map(Number); const d=new Date(y,m-2,1); state.monthlyView=d.toISOString().slice(0,7);renderAll();break;}case'nextMonth':{const [y,m]=state.monthlyView.split('-').map(Number); const d=new Date(y,m,1); state.monthlyView=d.toISOString().slice(0,7);renderAll();break;}case'addMapDoor':addMapItem('door');break;case'addMapWindow':addMapItem('window');break;case'printSubPacket':printSubPacket();break;default:originalHandleAction(action,el);}}
function printSubPacket(){const w=window.open('','_blank'); const html=subPacketHtml(); w.document.write('<!doctype html><html><head><title>SOZY Substitute Guide</title><style>body{font-family:Arial,sans-serif;color:#111;padding:20px;margin:0}.subpacket table{width:100%;border-collapse:collapse}.subpacket td,.subpacket th{border:1px solid #444;padding:6px}.subpacket h1{font-size:24px;margin-top:0}.subpacket h2{font-size:18px;margin-top:18px}@page{margin:.5in}</style></head><body>'+html+'</body></html>'); w.document.close(); setTimeout(()=>w.print(),250);}
const originalAddMapItem=addMapItem;
addMapItem=function(type){const m=state.classroomMap; const t=nowIso(); m.items=m.items||[]; const n=m.items.filter(i=>i.type===type).length+1; const sizes={desk:[110,80],table:[180,110],door:[90,34],window:[110,32]}; const wh=sizes[type]||[110,80]; const labels={desk:'Desk '+n,table:'Table '+String.fromCharCode(64+n),door:'Door '+n,window:'Window '+n}; m.items.push({id:uid(type),type,label:labels[type]||type+' '+n,x:30+((n*42)%420),y:type==='door'||type==='window'?10:60+((n*30)%280),w:wh[0],h:wh[1],studentIds:[],createdAt:t,updatedAt:t}); save((labels[type]||'Furniture')+' added.');};
mapItemHtml=function(it){const ids=mapAssignedIds(it); const names=ids.map(id=>state.students.find(s=>s.id===id)).filter(Boolean); const x=Math.max(0,Number(it.x)||0),y=Math.max(0,Number(it.y)||0),w=Math.max(54,Number(it.w)||110),h=Math.max(30,Number(it.h)||80); const isFixed=it.type==='door'||it.type==='window'; const emptyText=it.type==='table'?'Drop student(s) here':(isFixed?'': 'Drop student here'); return `<div class="map-item ${it.type==='table'?'table':it.type==='door'?'door':it.type==='window'?'window':'desk'}" draggable="true" data-map-id="${it.id}" style="left:${x}px;top:${y}px;width:${w}px;height:${h}px"><button class="map-menu-btn" title="Furniture options" aria-label="Furniture options">⋯</button><div class="map-menu-pop"><button class="secondary" data-action="unassignMapItem" data-id="${it.id}">Clear</button><button class="danger" data-action="deleteMapItem" data-id="${it.id}">Delete</button></div><b>${esc(it.label||it.type)}</b><div class="assigned ${names.length?'has-names':''}">${isFixed?'':(names.length?names.map(s=>`<span class="seat-name">${esc(s.name)} <button class="mini-x" data-action="unassignMapStudent" data-id="${it.id}" data-student="${s.id}">×</button></span>`).join(''):emptyText)}</div><span class="resize-corner" data-resize-map="${it.id}" title="Drag to resize"></span></div>`;};
classroomMapHtml=function(){const m=state.classroomMap||{}; const assigned=new Set((m.items||[]).flatMap(i=>mapAssignedIds(i))); const unassigned=activeStudents().filter(s=>!assigned.has(s.id)); return `<div class="map-add-box"><label>Add furniture</label><div class="actions"><button class="secondary" data-action="addMapDesk">+ Desk</button><button class="secondary" data-action="addMapTable">+ Table</button><button class="secondary" data-action="addMapDoor">+ Door</button><button class="secondary" data-action="addMapWindow">+ Window</button></div></div><div class="map-workspace"><div class="classroom-board" data-classroom-board>${(m.items||[]).map(mapItemHtml).join('')}<button class="small secondary clear-map-btn" data-action="clearMap">Clear map</button></div><aside class="map-side unassigned-zone"><div class="map-options-box"><h3>Map Options</h3><div class="actions"><button data-action="saveMapSettings">Save Settings</button><button class="secondary" data-action="downloadMap">Download</button></div></div><b>Unassigned students</b><p class="tiny">Drag names onto a desk or table.</p><div class="student-scroll">${unassigned.map(s=>`<span class="student-chip" draggable="true" data-student-chip="${s.id}">${esc(s.name)}</span>`).join('')||'<span class="tiny">Every active student is assigned, or no students are listed yet.</span>'}</div></aside></div>`;};
const originalGalleryListHtml=galleryListHtml;
galleryListHtml=function(){const q=(state.gallerySearch||'').toLowerCase().trim(); const filter=state.galleryFilter||'all'; let docs=[...(state.gallery||[])]; const seen=new Set(); docs=docs.filter(d=>{const key=[(d.name||'').toLowerCase(),d.size||'',d.area||'',d.itemId||''].join('|'); if(seen.has(key))return false; seen.add(key); return true;}); if(filter!=='all')docs=docs.filter(d=>d.area===filter); if(q)docs=docs.filter(d=>[d.name,d.area,d.label,d.note,areaName(d.area),linkedItemLabel(d.area,d.itemId)].join(' ').toLowerCase().includes(q)); docs.sort((a,b)=>new Date(b.updatedAt||b.createdAt||0)-new Date(a.updatedAt||a.createdAt||0)); const opts=['all','general','weekly','lessons','students','assignments','meetings','todos','standards']; return `<div class="filterbar"><div><label>Search Gallery</label><input id="gallerySearchInput" value="${esc(state.gallerySearch)}" placeholder="Search file name, page, lesson, student, task..."></div><div><label>Filter</label><select id="galleryFilter">${opts.map(o=>`<option value="${o}" ${filter===o?'selected':''}>${o==='all'?'All files':areaName(o)}</option>`).join('')}</select></div><div><label>Total</label><div class="pill">${docs.length} file${docs.length===1?'':'s'}</div></div><div><label>Tip</label><div class="tiny">Click Open to view or download. Click Go to jump to the linked page.</div></div></div><div class="gallery-grid">${docs.map(galleryDocHtml).join('')||empty('No files in Gallery yet.')}</div>`;};
function standardStatusOptions(rows){const vals=[...new Set(rows.map(s=>s.status).filter(Boolean))]; return ['all',...vals];}
standardList=function(){const q=(state.currentStandardSearch||'').toLowerCase().trim(); let rows=[...state.standards]; const opts=standardStatusOptions(rows); const filter=state.standardFilter||'all'; if(filter!=='all')rows=rows.filter(x=>x.status===filter); if(q)rows=rows.filter(x=>[x.skill,x.subject,x.standard,x.status,x.notes].join(' ').toLowerCase().includes(q)); const sort=state.standardSort||'updated'; rows.sort((a,b)=> sort==='progress'?((Number(b.progress)||0)-(Number(a.progress)||0)):sort==='subject'?(String(a.subject||'').localeCompare(String(b.subject||''))):sort==='skill'?(String(a.skill||'').localeCompare(String(b.skill||''))):(new Date(b.updatedAt||0)-new Date(a.updatedAt||0))); return `<div class="standard-list-toolbar"><button data-action="openStandardModal">➕ Add a Standard/Skill</button><select id="standardFilter"><option value="all">Filter: All statuses</option>${opts.filter(o=>o!=='all').map(o=>`<option value="${esc(o)}" ${filter===o?'selected':''}>${esc(o)}</option>`).join('')}</select><select id="standardSort"><option value="updated" ${sort==='updated'?'selected':''}>Order: Recently edited</option><option value="skill" ${sort==='skill'?'selected':''}>Order: Skill A-Z</option><option value="subject" ${sort==='subject'?'selected':''}>Order: Subject A-Z</option><option value="progress" ${sort==='progress'?'selected':''}>Order: Progress high to low</option></select><div class="pill">${rows.length} skill${rows.length===1?'':'s'}</div></div>`+(rows.map(s=>state.editing.standards[s.id]?`<div class="item">${standardForm(s)}</div>`:`<div class="item with-paperclip">${attachmentIndicator('standards',s.id)}<div class="item-title">${esc(s.skill)}</div><div class="item-meta">${esc(s.subject)} • ${esc(s.standard)} • ${esc(s.status)} • Last edited ${fmt(s.updatedAt)}</div><div class="progressbar"><span style="width:${Number(s.progress)||0}%"></span></div><p class="tiny">${esc(s.notes)}</p><div class="entry-actions"><button class="small secondary" data-action="editStandard" data-id="${s.id}">Edit</button><button class="small danger delete-right" data-action="deleteStandard" data-id="${s.id}">Delete</button></div></div>`).join('')||empty(q?'No skills match that search.':'No skills yet.'));};
todoHtml=function(){const order={High:0,Medium:1,Low:2}; const show=!!state.todoViewArchives; const tasks=[...state.todos].filter(t=>show?!!t.archived:!t.archived).sort((a,b)=>(order[a.priority]??9)-(order[b.priority]??9)||Number(a.done)-Number(b.done)||new Date(a.createdAt||0)-new Date(b.createdAt||0)); return `<div class="formrow three"><div><label>Task</label><input id="todoText" placeholder="Prep copies"></div><div><label>Priority</label><select id="todoPriority"><option>Low</option><option selected>Medium</option><option>High</option></select></div><div><label>&nbsp;</label><button data-action="addTodo">Add task</button></div></div><p class="tiny">After adding a task, you can attach files in edit mode. High = red, Medium = yellow, Low = green.</p><div class="todo-head"><h3>My To-Do List</h3><button class="secondary" data-action="toggleTodoArchives">${show?'Hide archived tasks':'View archived tasks'}</button></div><div class="todo-list">${tasks.map(todoRow).join('')||empty(show?'No archived tasks.':'No tasks yet.')}</div>`;};
todoRow=function(t){if(state.editing.todos[t.id])return `<div class="item"><div class="formrow three"><div><label>Task</label><input id="et_text_${t.id}" value="${esc(t.text)}"></div><div><label>Priority</label><select id="et_priority_${t.id}"><option ${t.priority==='Low'?'selected':''}>Low</option><option ${t.priority==='Medium'?'selected':''}>Medium</option><option ${t.priority==='High'?'selected':''}>High</option></select></div><div><label>Last edited</label><input type="datetime-local" id="et_time_${t.id}" value="${toLocalInput(t.updatedAt)}"></div></div>${attachmentPanel('todos',t.id,t.text)}<div class="actions"><button class="small good" data-action="saveTodo" data-id="${t.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="todos" data-id="${t.id}">Cancel</button></div></div>`; const cls='todo-card-'+priorityClass(t.priority); return `<div class="item with-paperclip ${cls}">${attachmentIndicator('todos',t.id)}<div class="item-head"><div><div class="item-title">${t.done?'✅':'⬜'} ${esc(t.text)}</div><div class="item-meta"><span class="priority-pill ${priorityClass(t.priority)}">${esc(t.priority||'Medium')}</span> • Last edited ${fmt(t.updatedAt)} ${t.archived?'• Archived':''}</div></div></div><div class="todo-actions"><button class="small secondary" data-action="toggleTodo" data-id="${t.id}">${t.done?'Reopen':'Done'}</button><button class="small secondary" data-action="editTodo" data-id="${t.id}">Edit</button><button class="small secondary" data-action="archiveTodo" data-id="${t.id}">${t.archived?'Restore':'Archive'}</button><button class="small danger" data-action="deleteTodo" data-id="${t.id}">Delete</button></div></div>`;};
groupsPage=function(){const defs=[['groupMaker',card('groups','groupMaker','',`<div class="split"><div class="group-control-stack"><div><label>Number of groups</label><input id="groupCount" type="number" value="3"></div><button data-action="makeGroups">Make groups</button><div class="groups">${renderGroups()}</div></div><div><label>Student names</label><textarea id="studentNames" placeholder="Avery, Mia, Leo, Sam">${activeStudents().map(s=>esc(s.name)).join(', ')}</textarea><p class="tiny">Tip: Names sync from My Students as a starting point, but you can edit this box before making groups.</p></div></div>`,{size:'lg',controls:false,heading:false})]]; return renderCards('groups',defs,'grid');};
supplyRow=function(s){const low=Number(s.have)<Number(s.need); const high=Number(s.have)>=Number(s.need); const cls=low?'supply-low':(high?'supply-high':'supply-ok'); if(state.editing.supplies[s.id])return `<div class="item"><div class="formrow four"><div><label>Item</label><input id="esu_item_${s.id}" value="${esc(s.item)}"></div><div><label>Have</label><input id="esu_have_${s.id}" type="number" value="${esc(s.have)}"></div><div><label>Need</label><input id="esu_need_${s.id}" type="number" value="${esc(s.need)}"></div><div><label>Location</label><input id="esu_loc_${s.id}" value="${esc(s.location)}"></div></div><label>Note</label><input id="esu_note_${s.id}" value="${esc(s.note)}"><label>Last edited</label><input type="datetime-local" id="esu_time_${s.id}" value="${toLocalInput(s.updatedAt)}"><div class="actions"><button class="small good" data-action="saveSupply" data-id="${s.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="supplies" data-id="${s.id}">Cancel</button></div></div>`; return `<div class="item ${cls}"><div class="item-head"><div><div class="item-title">${low?'⚠️ ':''}${esc(s.item)}</div><div class="item-meta">Have ${esc(s.have)} / Need ${esc(s.need)} • ${esc(s.location)} • Last edited ${fmt(s.updatedAt)}</div><p class="tiny">${esc(s.note)}</p></div><span class="pill ${low?'warn':'good'}">${low?'Low':'High/OK'}</span></div><div class="entry-actions"><button class="small secondary" data-action="editSupply" data-id="${s.id}">Edit</button><button class="small secondary" data-action="archiveSupply" data-id="${s.id}">Archive</button><button class="small danger delete-right" data-action="deleteSupply" data-id="${s.id}">Delete</button></div></div>`;};
subNotesHtml=function(){const f=state.subNotes.fields||{}; const status=(JSON.stringify(f)!==state.subNotes.saved)?'Unsaved changes':'Saved locally'; return `${subPrompt('overview','Class overview','What should the sub know about your class personality, energy level, or general expectations?',f.overview)}${subPrompt('attendance','Attendance / lunch count','How should attendance, lunch count, bathroom passes, or office notes be handled?',f.attendance)}${subPrompt('schedule','Daily flow','What does the normal day look like? What should not be skipped?',f.schedule)}${subPrompt('behavior','Behavior support','What behavior system, rewards, consequences, calming tools, or redirection words should the sub use?',f.behavior)}${subPrompt('students','Student support notes','Are there students who may need extra help, seating reminders, medical attention, or quiet support? Keep this professional and need-to-know.',f.students)}${subPrompt('materials','Materials / technology','Where are worksheets, books, logins, remotes, projector tools, and center materials? Avoid writing private passwords if your school does not allow it.',f.materials)}${subPrompt('emergency','Emergency procedures','What should the sub do for fire drill, lockdown, nurse, office call, or urgent classroom help?',f.emergency)}${subPrompt('dismissal','Dismissal','How do students leave? Bus, pickup, after-school program, walkers, or dismissal jobs?',f.dismissal)}${subPrompt('extra','Extra Comments','Anything else the substitute should know that does not fit above?',f.extra)}<div class="split"><div class="${status.startsWith('Unsaved')?'unsaved-status':'saved-status'}">${status}${state.subNotes.lastSaved?' • '+fmt(state.subNotes.lastSaved):''}</div><div class="actions"><button data-action="saveSubNotes">Save changes</button><button class="secondary" data-action="undoSubNotes">Undo</button><button class="danger" data-action="clearSubNotes">Clear all</button></div></div>`;};

const oldChangeHandlerSozy=true;
document.addEventListener('change',e=>{
 if(e.target.id==='quickFontSelect'){state.workspaceFont=e.target.value; save('Workspace font saved.');}
 if(e.target.id==='workspaceFontSelect'){state.workspaceFont=e.target.value; state.settingsOpenSection='fonts'; save('Workspace font saved.');}
 if(['corkFreeMove','corkDesign','corkBorderColor','corkCustomBorder','corkBoardColor','corkCustomBoard','corkFont','corkMatchFont','corkMatchText'].includes(e.target.id)){applyCorkSettingsFromInputs(); save('',false);}
 if(e.target.id==='standardFilter'){state.standardFilter=e.target.value; save('Standard filter saved.');}
 if(e.target.id==='standardSort'){state.standardSort=e.target.value; save('Standard order saved.');}
});
document.addEventListener('input',e=>{
 if(['corkCustomBorder','corkCustomBoard'].includes(e.target.id)){applyCorkSettingsFromInputs(); save('',false);}
});
document.addEventListener('toggle',e=>{const box=e.target.closest?.('.settings-box'); if(box&&e.target.open){const s=(e.target.querySelector('summary')?.textContent||'').toLowerCase(); state.settingsOpenSection=s.includes('backup')?'backup':s.includes('theme')?'themes':s.includes('font')?'fonts':s.includes('color')?'colors':s.includes('notification')?'notifications':s.includes('help')?'help':s.includes('menu')?'menu':'';}},true);


/* SOZY Workspace menu side + Menu Layout patch 2026-06-06_1912-CT */
(function(){
 const oldNormalizeMenuSide = normalize;
 normalize=function(){oldNormalizeMenuSide(); state.layout=state.layout||{}; state.layout.menuSide=state.layout.menuSide||'left';};
 const oldRenderAllMenuSide = renderAll;
 renderAll=function(){
   oldRenderAllMenuSide();
   const app=document.getElementById('app');
   if(app){app.classList.toggle('menu-right',state.layout?.menuSide==='right');}
   const edge=document.querySelector('.menu-edge');
   if(edge){edge.textContent=state.layout?.menuSide==='right'?'>':'<'; edge.title='Hide menu'; edge.setAttribute('aria-label','Hide menu');}
   const peek=document.querySelector('.menu-peek');
   if(peek){peek.textContent=state.layout?.menuSide==='right'?'<':'>'; peek.title='Show menu'; peek.setAttribute('aria-label','Show menu');}
 };
 menuSettingsHtml=function(){
  const side=state.layout?.menuSide||'left';
  return `<div class="menu-layout-note"><b>Menu side</b><p class="tiny">Put the main menu on the side that feels best for your screen setup.</p><div class="menu-side-choice"><button class="secondary ${side==='left'?'active':''}" data-action="setMenuSide" data-side="left">⬅ Left side</button><button class="secondary ${side==='right'?'active':''}" data-action="setMenuSide" data-side="right">Right side ➡</button></div></div><p class="tiny">Hide top-level pages you do not need. The Tools & Resources submenu stays grouped so it is easier to use.</p>${orderedPages().map(p=>`<div class="menu-list-row" data-menu-row="${p[0]}"><span>${p[1]} ${p[2]}<br><small>${esc(p[3])}</small></span><button class="small secondary" data-action="toggleMenuPage" data-page="${p[0]}">${state.layout.menuHidden.includes(p[0])?'Show':'Hide'}</button></div>`).join('')}<div class="actions"><button class="secondary" data-action="resetMenu">Reset menu</button></div>`;
 };
 const oldHandleActionMenuSide=handleAction;
 handleAction=function(action,el){
   if(action==='setMenuSide'){
     state.layout=state.layout||{};
     state.layout.menuSide=el.dataset.side==='right'?'right':'left';
     state.settingsOpenSection='menu';
     save('Menu layout saved.');
     return;
   }
   return oldHandleActionMenuSide(action,el);
 };
})();



// === Uniformity update 2026-06-06_1917-CT ===
function standardSearchResults(){
  const term=(state.currentStandardSearch||'').toLowerCase().trim();
  if(!term)return '';
  const list=state.standards.filter(x=>!x.archived&&[x.skill,x.subject,x.standard,x.status,x.notes].join(' ').toLowerCase().includes(term));
  return `<div class="standard-search-results">${list.map(s=>`<div class="item" data-action="focusStandard" data-id="${s.id}" title="Click to open and edit this standard or skill"><div class="item-title">${esc(s.skill)}</div><div class="item-meta">${esc(s.subject)} • ${esc(s.standard)} • ${esc(s.status)} • ${esc(s.progress)}%</div><p class="tiny">${esc(s.notes)}</p></div>`).join('')||empty('No matching standards or skills found. Try a simpler word.')}</div>`;
}
standardsPage=function(){
  const guideBox=(!state.hideStandardsGuide&&!standardsGuideClosedSession)?`<div class="standard-explainer plain-block standard-guide"><button class="icon-btn guide-close" title="Close explanation" aria-label="Close explanation" data-action="closeStandardsGuide">×</button><p><strong>What is this page for?</strong> Use this to track the skill or standard itself, like “main idea,” “multiplication facts,” or “writing complete sentences.”</p><p><strong>How is this different from Lesson Library?</strong> Lesson Library stores the actual lesson plan. Standards / Skills tracks whether the class is learning, practicing, or mastering the skill across many lessons.</p><p class="tiny">Example: You may have 5 reading lessons in Lesson Library, but only 1 skill tracker for “finding text evidence.”</p><label class="guide-check"><input id="dontShowStandardGuide" type="checkbox"> Don't show me this again</label></div>`:'';
  const search=`<div class="plain-block standards-search-row"><div class="searchbar"><input id="standardSearchInput" value="${esc(state.currentStandardSearch||'')}" placeholder="Search standards, skills, subjects, status, or notes..."><button class="secondary" data-action="clearStandardSearch">Clear</button></div><div class="tiny search-tip-inline">Tip: Search results below are clickable.</div><div id="standardSearchResults">${standardSearchResults()}</div></div>`;
  const defs=[['standardList',card('standards','standardList','📈 Our Progress',standardList(),{size:'lg',controls:false})]];
  return guideBox+search+renderCards('standards',defs,'grid');
};
standardList=function(){
  const q=(state.currentStandardSearch||'').toLowerCase().trim();
  let rows=[...state.standards];
  const opts=standardStatusOptions(rows);
  const filter=state.standardFilter||'all';
  if(filter!=='all')rows=rows.filter(x=>x.status===filter);
  if(q)rows=rows.filter(x=>[x.skill,x.subject,x.standard,x.status,x.notes].join(' ').toLowerCase().includes(q));
  const sort=state.standardSort||'updated';
  rows.sort((a,b)=> sort==='progress'?((Number(b.progress)||0)-(Number(a.progress)||0)):sort==='subject'?(String(a.subject||'').localeCompare(String(b.subject||''))):sort==='skill'?(String(a.skill||'').localeCompare(String(b.skill||''))):(new Date(b.updatedAt||0)-new Date(a.updatedAt||0)));
  return `<div class="standard-list-toolbar"><button data-action="openStandardModal">➕ Add a Standard/Skill</button><select id="standardFilter"><option value="all">Filter: All statuses</option>${opts.filter(o=>o!=='all').map(o=>`<option value="${esc(o)}" ${filter===o?'selected':''}>${esc(o)}</option>`).join('')}</select><select id="standardSort"><option value="updated" ${sort==='updated'?'selected':''}>Order: Recently edited</option><option value="skill" ${sort==='skill'?'selected':''}>Order: Skill A-Z</option><option value="subject" ${sort==='subject'?'selected':''}>Order: Subject A-Z</option><option value="progress" ${sort==='progress'?'selected':''}>Order: Progress high to low</option></select><div class="pill">${rows.length} skill${rows.length===1?'':'s'}</div></div>`+(rows.map(s=>state.editing.standards[s.id]?`<div class="item" data-edit-standard="${s.id}">${standardForm(s)}</div>`:`<div class="item with-paperclip">${attachmentIndicator('standards',s.id)}<div class="item-title">${esc(s.skill)}</div><div class="item-meta">${esc(s.subject)} • ${esc(s.standard)} • ${esc(s.status)} • Last edited ${fmt(s.updatedAt)}</div><div class="progressbar"><span style="width:${Number(s.progress)||0}%"></span></div><p class="tiny">${esc(s.notes)}</p><div class="entry-actions"><button class="small secondary" data-action="editStandard" data-id="${s.id}">Edit</button><button class="small danger delete-right" data-action="deleteStandard" data-id="${s.id}">Delete</button></div></div>`).join('')||empty(q?'No skills match that search.':'No skills yet.'));
};
meetingHtml=function(){
  let notes=[...state.meetings];
  const q=(state.meetingFilter||'').toLowerCase().trim();
  if(q)notes=notes.filter(m=>[m.title,m.date,m.notes].join(' ').toLowerCase().includes(q));
  const order=state.meetingOrder||'received';
  notes.sort((a,b)=>{if(order==='newest')return new Date(b.createdAt||b.date||0)-new Date(a.createdAt||a.date||0); if(order==='title')return (a.title||'').localeCompare(b.title||''); return new Date(a.createdAt||a.date||0)-new Date(b.createdAt||b.date||0);});
  const form=state.showMeetingForm?`<div class="meet-add-panel"><div class="formrow two"><div><label>Meeting title</label><input id="meetingTitle" placeholder="IEP meeting, grade-level planning..."></div><div><label>Date</label><input id="meetingDate" type="date" value="${new Date().toISOString().slice(0,10)}"></div></div><label>Notes</label><textarea id="meetingNotes" placeholder="What was decided? What needs follow-up?"></textarea><p class="tiny">After saving a meeting note, you can attach agendas, PDFs, screenshots, or forms in edit mode.</p><div class="actions"><button data-action="addMeeting">Save meeting note</button><button class="secondary" data-action="toggleMeetingForm">Cancel</button></div></div>`:'';
  return `<div class="meeting-add-panel-wide full-width-action"><button data-action="toggleMeetingForm">➕ Add Meeting Note</button></div>${form}<div class="meeting-history-head"><h4>Meeting Notes History</h4><span class="pill">${notes.length} note${notes.length===1?'':'s'}</span></div><div class="meeting-controls"><input id="meetingFilterInput" value="${esc(state.meetingFilter||'')}" placeholder="Filter meeting notes..."><select id="meetingOrder"><option value="received" ${order==='received'?'selected':''}>Oldest received first</option><option value="newest" ${order==='newest'?'selected':''}>Newest first</option><option value="title" ${order==='title'?'selected':''}>Title A to Z</option></select></div><div class="meeting-list">${notes.map(m=>meetingRow(m)).join('')||empty('No meeting notes yet.')}</div>`;
};
function taskForm(){return `<label>Task</label><input id="todoText" placeholder="Prep copies, call office, print center cards..."><label>Priority</label><select id="todoPriority"><option>Low</option><option selected>Medium</option><option>High</option></select><p class="tiny">After adding a task, you can attach files in edit mode. High = red, Medium = yellow, Low = green.</p><div class="actions"><button data-action="addTodoFromModal">Save task</button><button class="secondary" data-action="closeTaskModal">Cancel</button></div>`;}
function renderTaskModal(){const modal=document.getElementById('taskModal'); if(!modal)return; modal.classList.toggle('open',!!state.taskModalOpen); const body=document.getElementById('taskModalBody'); if(body)body.innerHTML=taskForm();}
todoHtml=function(){
  const order={High:0,Medium:1,Low:2};
  const show=!!state.todoViewArchives;
  const tasks=[...state.todos].filter(t=>show?!!t.archived:!t.archived).sort((a,b)=>(order[a.priority]??9)-(order[b.priority]??9)||Number(a.done)-Number(b.done)||new Date(a.createdAt||0)-new Date(b.createdAt||0));
  return `<div class="todo-add-panel full-width-action"><button data-action="openTaskModal">➕ Add Task</button></div><div class="todo-head"><h3>My To-Do List</h3><button class="secondary" data-action="toggleTodoArchives">${show?'Hide archived tasks':'View archived tasks'}</button></div><div class="todo-list">${tasks.map(todoRow).join('')||empty(show?'No archived tasks.':'No tasks yet.')}</div>`;
};
const renderAllBeforeUniformity=renderAll;
renderAll=function(){normalize(); applyTheme(); document.getElementById('app').classList.toggle('menu-hidden',!!state.menuHidden); renderNav(); renderMiniThemes(); renderHeader(); renderPages(); renderMenuPanel(); renderPinModal(); renderCorkSettingsModal(); renderLessonModal(); renderWeeklyModal(); renderMonthlyModal(); renderStandardModal(); renderTaskModal(); renderPrint(); renderStatus(); scheduleReminderCheck();};
const handleActionBeforeUniformity=handleAction;
handleAction=function(action,el){
  switch(action){
    case 'openTaskModal': state.taskModalOpen=true; renderAll(); break;
    case 'closeTaskModal': state.taskModalOpen=false; renderAll(); break;
    case 'addTodoFromModal': addTodo(); state.taskModalOpen=false; break;
    case 'focusStandard': state.editing.standards[el.dataset.id]=true; state.activePage='standards'; renderAll(); setTimeout(()=>document.querySelector(`[data-edit-standard="${el.dataset.id}"]`)?.scrollIntoView({behavior:'smooth',block:'center'}),50); break;
    default: handleActionBeforeUniformity(action,el);
  }
};
document.addEventListener('click',e=>{ if(e.target.id==='taskModal'){ state.taskModalOpen=false; renderAll(); }});
document.addEventListener('input',e=>{ if(e.target.id==='standardSearchInput'){ state.currentStandardSearch=e.target.value; const res=document.getElementById('standardSearchResults'); if(res)res.innerHTML=standardSearchResults(); const sl=document.getElementById('card-standards-standardList'); if(sl)sl.querySelector('.card-body').innerHTML=standardList(); save('',false); }});



// === Monthly planner and cleanup patch 2026-06-06_1952-CT ===
(function(){
 let dashboardHeroClosedSession=false;
 function weeklyDayNameFromDate(iso){ const d=new Date(iso+'T12:00:00'); return ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][d.getDay()]; }
 function menuDefaultOrderWithMonthly(){ const ids=[...topMenuIds]; const mi=ids.indexOf('monthly'); if(mi>-1)ids.splice(mi,1); const pi=ids.indexOf('planner'); ids.splice(pi>-1?pi+1:2,0,'monthly'); return ids; }
 function normalizeMenuMonthly(){
   if(!topMenuIds.includes('monthly')) topMenuIds.splice(Math.max(0,topMenuIds.indexOf('planner')+1),0,'monthly');
   else { const i=topMenuIds.indexOf('monthly'), p=topMenuIds.indexOf('planner'); if(p>-1 && i!==p+1){ topMenuIds.splice(i,1); topMenuIds.splice(topMenuIds.indexOf('planner')+1,0,'monthly'); } }
   state.layout=state.layout||{};
   if(!Array.isArray(state.layout.menuOrder)) state.layout.menuOrder=menuDefaultOrderWithMonthly();
   if(!state.layout.monthlyPlacedDefault){
     const order=state.layout.menuOrder.filter(id=>topMenuIds.includes(id));
     if(!order.includes('monthly')) order.splice(Math.max(0,order.indexOf('planner')+1),0,'monthly');
     else { const mi=order.indexOf('monthly'), pi=order.indexOf('planner'); if(pi>-1 && mi!==pi+1){ order.splice(mi,1); order.splice(order.indexOf('planner')+1,0,'monthly'); } }
     topMenuIds.forEach(id=>{ if(!order.includes(id)) order.push(id); });
     state.layout.menuOrder=order;
     state.layout.monthlyPlacedDefault=true;
   }
 }
 const prevNormalize=normalize;
 normalize=function(){ prevNormalize(); normalizeMenuMonthly(); state.hideDashboardHero=!!state.hideDashboardHero; state.monthly=(state.monthly||[]).map(x=>({time:x.time||'',...x})); };
 menuSettingsHtml=function(){
   const side=state.layout?.menuSide||'left';
   return `<div class="menu-layout-note"><b>Menu side</b><p class="tiny">Put the main menu on the side that feels best for your screen setup.</p><div class="menu-side-choice"><button class="secondary ${side==='left'?'active':''}" data-action="setMenuSide" data-side="left">⬅ Left side</button><button class="secondary ${side==='right'?'active':''}" data-action="setMenuSide" data-side="right">Right side ➡</button></div></div><p class="tiny">Hide top-level pages you do not need. Tools & Resources stays grouped so it is easier to use.</p>${orderedPages().map(p=>`<div class="menu-list-row" data-menu-row="${p[0]}"><span>${p[1]} ${esc(p[2])}<br><small>${esc(p[3])}</small></span><button class="small secondary" data-action="toggleMenuPage" data-page="${p[0]}">${state.layout.menuHidden.includes(p[0])?'Show':'Hide'}</button></div>`).join('')}<div class="actions"><button class="secondary" data-action="resetMenu">Reset menu</button></div>`;
 };
 const oldDashboardPage=dashboardPage;
 dashboardPage=function(){
   const rs=readinessScore(), gs=gradeStats();
   const hero=(!state.hideDashboardHero&&!dashboardHeroClosedSession)?`<section class="dashboard-hero"><button class="icon-btn hero-close" title="Close" aria-label="Close command center message" data-action="closeDashboardHero">×</button><div><h2>Your cozy classroom command center</h2><p>This workspace syncs your planner, lessons, grades, supplies, routines, reminders, and substitute readiness.</p><label class="hero-hide-row"><input id="dontShowDashboardHero" type="checkbox"> Don't show me this again</label></div><div class="actions"><button class="secondary" data-gopage="planner">Plan week</button><button class="secondary" data-gopage="grades">Open grades</button><button class="secondary" data-gopage="subexport">Prep substitute guide</button></div></section>`:'';
   const defs=[
 ['stats',card('dashboard','stats','📊 Today’s Numbers',`<div class="stat-grid"><div class="stat"><div class="num">${state.lessons.filter(l=>!l.archived).length}</div><div class="lbl">Lessons</div></div><div class="stat"><div class="num">${activeAssignments().length}</div><div class="lbl">Assignments</div></div><div class="stat"><div class="num">${state.todos.filter(t=>!t.done&&!t.archived).length}</div><div class="lbl">Open tasks</div></div><div class="stat"><div class="num">${lowSupplies().length}</div><div class="lbl">Low supplies</div></div></div>`,{size:'lg'})],
 ['planner',card('dashboard','planner','🗓️ Weekly Plan',`${state.weekly.slice(0,5).map(w=>`<div class="item"><div class="item-title">${esc(w.day)} • ${esc(w.time)}</div><div class="item-meta">${esc(w.subject)} — ${esc(w.title)}</div></div>`).join('')||empty('No planner entries yet.')}<div class="actions"><button class="secondary" data-gopage="planner">Edit planner</button></div>`,{size:'lg'})],
 ['lessons',card('dashboard','lessons','📚 Current Lessons',`<div class="progressbar"><span style="width:${lessonReadyPct()}%"></span></div><p class="tiny">${lessonReadyPct()}% of lessons are marked sub-ready.</p>${state.lessons.filter(l=>!l.archived).slice(0,3).map(l=>`<div class="item"><div class="item-title">${esc(l.title)}</div><div class="item-meta">${esc(l.subject)} • ${esc(l.standard)} • ${l.subReady?'Sub-ready':'Needs prep'}</div></div>`).join('')}<div class="actions"><button class="secondary" data-gopage="lessons">Search lessons</button></div>`)],
 ['grades',card('dashboard','grades','📝 Grading progress',`<div class="stat-grid"><div class="stat"><div class="num">${gs.avgText}</div><div class="lbl">Class average</div></div><div class="stat"><div class="num">${gs.completion}%</div><div class="lbl">Scores entered</div></div></div><div class="progressbar" style="margin-top:10px"><span style="width:${gs.completion}%"></span></div><div class="mini-chart" style="margin-top:12px">${gradeBarsHtml()}</div><div class="actions"><button class="secondary" data-gopage="grades">Open gradebook</button></div>`,{size:'lg'})],
 ['tasks',card('dashboard','tasks','📌 Tasks & Reminders',`${state.todos.filter(t=>!t.done&&!t.archived).slice(0,3).map(t=>`<div class="item"><div class="item-title">${esc(t.text)}</div><div class="item-meta">${esc(t.priority)} • last edited ${fmt(t.updatedAt)}</div></div>`).join('')||empty('No open tasks.')}<hr>${reminderList(2)}<div class="actions"><button class="secondary" data-gopage="meetings">Edit tasks</button><button class="secondary" data-gopage="reminders">Open reminders</button></div>`)],
 ['supplies',card('dashboard','supplies','🧻 Low supplies',`${lowSupplies().slice(0,4).map(s=>`<div class="item"><div class="item-title">${esc(s.item)}</div><div class="item-meta">Have ${esc(s.have)} / Need ${esc(s.need)} • ${esc(s.location)}</div></div>`).join('')||empty('No low supplies right now.')}<div class="actions"><button class="secondary" data-gopage="supplies">Edit supplies</button></div>`)],
 ['routines',card('dashboard','routines','✅ Routines',`<div class="progressbar"><span style="width:${routinePct()}%"></span></div><p class="tiny">${routinePct()}% checked today.</p>${state.routines.slice(0,4).map(r=>`<div class="item">${r.done?'✅':'⬜'} ${esc(r.text)}</div>`).join('')}<div class="actions"><button class="secondary" data-gopage="routines">Open routines</button></div>`)],
 ['readiness',card('dashboard','readiness','🧰 Substitute Readiness',`<div class="progressbar"><span style="width:${Math.round(rs.done/rs.total*100)}%"></span></div><p class="tiny">${rs.done} of ${rs.total} sub packet basics are ready.</p>${readinessList(true)}<div class="actions"><button class="secondary" data-gopage="subreadiness">Open checklist</button></div>`)],
 ['skills',card('dashboard','skills','📈 Skill progress',`${state.standards.slice(0,4).map(s=>`<div class="item"><div class="item-title">${esc(s.skill)}</div><div class="item-meta">${esc(s.subject)} • ${esc(s.standard)} • ${esc(s.progress)}%</div><div class="progressbar"><span style="width:${Number(s.progress)||0}%"></span></div></div>`).join('')||empty('No skills entered.')}<div class="actions"><button class="secondary" data-gopage="standards">Edit skills</button></div>`)]
   ];
   return hero+dashboardCorkBoard()+`<div class="dashboard-shell style-${state.layout.dashboardStyle||'soft'}">${renderCards('dashboard',defs,'grid')}</div>`;
 };
 weeklyBoard=function(){return `<div class="schedule-board horizontal-week">${days().map(d=>`<div class="dayrow"><h4>${d}</h4><div class="dayrow-entries">${state.weekly.filter(w=>w.day===d).sort((a,b)=>parseTime(a.time)-parseTime(b.time)).map(weeklyCard).join('')||`<div class="dayrow-empty">${empty('No blocks yet.')}</div>`}</div></div>`).join('')}</div>`;};
 function monthCombinedItems(iso){
   const dow=weeklyDayNameFromDate(iso);
   const monthItems=(state.monthly||[]).filter(x=>x.date===iso).map(x=>({...x,_source:'monthly',_sourceId:x.id,_sortTime:x.time||'99:99'}));
   const weeklyItems=(state.weekly||[]).filter(w=>w.day===dow).map(w=>({id:'wk_'+w.id+'_'+iso,_source:'weekly',_sourceId:w.id,date:iso,time:w.time||'',title:w.title||w.subject||'Weekly block',subject:w.subject||'',note:w.note||'',_sortTime:w.time||'99:99'}));
   return monthItems.concat(weeklyItems).sort((a,b)=>parseTime(a._sortTime)-parseTime(b._sortTime)||(a.title||'').localeCompare(b.title||''));
 }
 monthlyPage=function(){return `<div class="plain-block"><div class="month-toolbar"><div class="actions"><button data-action="openMonthlyModal">➕ Add Monthly Block</button><button class="secondary" data-action="downloadMonthlyCsv">Download Monthly Plan</button></div></div></div>${renderCards('monthly',[["month",card('monthly','month','🗓️ Monthly Plan',monthlyCalendarHtml(),{size:'lg',controls:false})]],'grid')}`;};
 monthlyCalendarHtml=function(){const key=state.monthlyView||new Date().toISOString().slice(0,7); const today=new Date().toISOString().slice(0,10); return `<div class="month-header"><button class="secondary small" data-action="prevMonth">‹ Previous</button><div class="month-title-block"><b>${monthTitle(key)}</b><div class="month-sync-badge">Synced with Weekly Planner</div></div><button class="secondary small" data-action="nextMonth">Next ›</button></div><div class="month-grid">${['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].map(d=>`<div class="month-day-name">${d}</div>`).join('')}${monthDays(key).map(d=>{const iso=d.toISOString().slice(0,10); const items=monthCombinedItems(iso); return `<div class="month-cell ${monthKey(iso)!==key?'other':''} ${iso===today?'today':''}"><div class="month-date">${d.getDate()}</div>${items.map(monthlyEntryHtml).join('')}</div>`;}).join('')}</div>`;};
 monthlyEntryHtml=function(x){
   if(x._source==='monthly' && state.editing.monthly[x.id])return `<div class="month-item"><label>Time</label><input id="em_time_${x.id}" placeholder="8:30 AM" value="${esc(x.time||'')}"><label>Title</label><input id="em_title_${x.id}" value="${esc(x.title||'')}"><label>Date</label><input type="date" id="em_date_${x.id}" value="${esc(x.date||'')}"><label>Subject</label><input id="em_subject_${x.id}" value="${esc(x.subject||'')}"><label>Note</label><textarea id="em_note_${x.id}">${esc(x.note||'')}</textarea><div class="actions"><button class="small good" data-action="saveMonthly" data-id="${x.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="monthly" data-id="${x.id}">Cancel</button></div></div>`;
   const isWeekly=x._source==='weekly';
   const id=esc(x._sourceId||x.id);
   const meta=[x.time,x.subject,isWeekly?'Weekly Planner':'Monthly Planner'].filter(Boolean).join(' • ');
   return `<button class="month-item clickable-month-item ${isWeekly?'month-weekly':'month-local'}" data-action="viewMonthlyVisible" data-source="${isWeekly?'weekly':'monthly'}" data-id="${id}" type="button"><span class="month-click-title">${esc(x.title||'Monthly item')}</span><span class="month-click-meta">${esc(meta)}</span></button>`;
 };
 monthlyForm=function(){return `<div class="formrow four"><div><label>Date</label><input type="date" id="monthDate" value="${new Date().toISOString().slice(0,10)}"></div><div><label>Time</label><input id="monthTime" placeholder="8:30 AM"></div><div><label>Subject</label><input id="monthSubject" placeholder="Reading, Math, Event"></div><div><label>Title</label><input id="monthTitle" placeholder="Unit launch, testing, field trip"></div></div><label>Note</label><textarea id="monthNote" placeholder="Add monthly notes here..."></textarea><div class="actions"><button data-action="addMonthly">Save monthly block</button><button class="secondary" data-action="closeMonthlyModal">Cancel</button></div>`;};
 addMonthly=function(){const t=nowIso(); state.monthly.push({id:uid('month'),date:val('monthDate')||new Date().toISOString().slice(0,10),time:val('monthTime'),subject:val('monthSubject'),title:val('monthTitle')||'Monthly block',note:val('monthNote'),createdAt:t,updatedAt:t}); state.monthlyView=(val('monthDate')||new Date().toISOString().slice(0,10)).slice(0,7); save('Monthly block added.');};
 saveMonthly=function(id){const x=state.monthly.find(i=>i.id===id); if(!x)return; x.time=val('em_time_'+id); x.title=val('em_title_'+id); x.date=val('em_date_'+id); x.subject=val('em_subject_'+id); x.note=val('em_note_'+id); x.updatedAt=nowIso(); delete state.editing.monthly[id]; state.monthlyView=(x.date||new Date().toISOString().slice(0,10)).slice(0,7); save('Monthly block saved.');};
 downloadMonthlyCsv=function(){downloadText('sozy-monthly-plan.csv',csv(['Date','Time','Subject','Title','Note','Updated'],(state.monthly||[]).map(x=>[x.date,x.time||'',x.subject,x.title,x.note,fmt(x.updatedAt)])))};
 subNotesHtml=function(){const f=state.subNotes.fields||{}; return `${subPrompt('overview','Class overview','What should the sub know about your class personality, energy level, or general expectations?',f.overview)}${subPrompt('attendance','Attendance / lunch count','How should attendance, lunch count, bathroom passes, or office notes be handled?',f.attendance)}${subPrompt('schedule','Daily flow','What does the normal day look like? What should not be skipped?',f.schedule)}${subPrompt('behavior','Behavior support','What behavior system, rewards, consequences, calming tools, or redirection words should the sub use?',f.behavior)}${subPrompt('students','Student support notes','Are there students who may need extra help, seating reminders, medical attention, or quiet support? Keep this professional and need-to-know.',f.students)}${subPrompt('materials','Materials / technology','Where are worksheets, books, logins, remotes, projector tools, and center materials? Avoid writing private passwords if your school does not allow it.',f.materials)}${subPrompt('emergency','Emergency procedures','What should the sub do for fire drill, lockdown, nurse, office call, or urgent classroom help?',f.emergency)}${subPrompt('dismissal','Dismissal','How do students leave? Bus, pickup, after-school program, walkers, or dismissal jobs?',f.dismissal)}${subPrompt('extra','Extra Comments','Anything else the substitute should know that does not fit above?',f.extra)}<div class="subnote-actions-center"><button data-action="saveSubNotes">Save changes</button><button class="secondary" data-action="undoSubNotes">Undo</button><button class="danger" data-action="clearSubNotes">Clear all</button></div>`;};
 const borderChoices=[['theme','Theme Match','linear-gradient(135deg,var(--brand),var(--brand2))'],['blush','Blush Pink','#f5b7c8'],['lavender','Lavender','#cdb8ff'],['sage','Soft Sage','#9fc8a9'],['sky','Sky Blue','#9ed8f5'],['lemon','Lemon Yellow','#f1d36b'],['mocha','Mocha Brown','#b8865b'],['ink','Ink Gray','#4b4b5f'],['custom','My Own Color','var(--cork-border)']];
 const boardChoices=[['natural','Natural Brown','#d6a777'],['light','Light Brown','#e4c79c'],['dark','Warm Brown','#b6844f'],['white','Soft White','#faf8f1'],['black','Chalkboard Black','#23232c'],['theme','Theme Soft Panel','linear-gradient(135deg,var(--surface2),var(--brand3))'],['custom','My Own Color','var(--cork-bg)']];
 function choiceGrid(id,choices,current){return `<div class="cork-color-grid">${choices.map(c=>`<label class="cork-choice ${current===c[0]?'active':''}"><input type="radio" name="${id}" value="${c[0]}" ${current===c[0]?'checked':''} style="display:none"><span style="background:${c[2]}"></span><b>${c[1]}</b></label>`).join('')}</div>`;}
 corkSettingsHtml=function(){const c=state.corkSettings||{}; const borderVal=c.borderColor||'theme'; const boardVal=c.boardColor||'natural'; return `<p class="tiny">Design the cork board separately from the rest of the workspace. Changes preview right away.</p>
<label class="setting-row"><input type="checkbox" id="corkFreeMove" ${c.freeMove?'checked':''}> Let me move, overlap, and rotate pins anywhere on the board.</label>
<label>Border design</label><select id="corkDesign"><option value="floral" ${c.borderDesign==='floral'?'selected':''}>Soft floral</option><option value="botanical" ${c.borderDesign==='botanical'?'selected':''}>Simple botanical</option><option value="stars" ${c.borderDesign==='stars'?'selected':''}>Tiny stars</option><option value="scallop" ${c.borderDesign==='scallop'?'selected':''}>Scalloped/dashed</option><option value="simple" ${c.borderDesign==='simple'?'selected':''}>Simple clean</option><option value="none" ${c.borderDesign==='none'?'selected':''}>No decoration</option></select>
<label>Border color</label>${choiceGrid('corkBorderRadio',borderChoices,borderVal)}<div class="cork-custom-row"><div><label>Custom border color</label><input type="color" id="corkCustomBorder" value="${esc(c.customBorder||'#f5b7c8')}"></div><div id="corkBorderPreview" class="cork-custom-preview" style="background:${esc(c.customBorder||'#f5b7c8')}">Selected border color</div></div>
<label>Main board color</label>${choiceGrid('corkBoardRadio',boardChoices,boardVal)}<div class="cork-custom-row"><div><label>Custom board color</label><input type="color" id="corkCustomBoard" value="${esc(c.customBoard||'#d6a777')}"></div><div id="corkBoardPreview" class="cork-custom-preview" style="background:${esc(c.customBoard||'#d6a777')}">Selected board color</div></div>
<div class="formrow two"><div><label>Cork board handwriting font</label><select id="corkFont">${corkFontOptions.map(f=>`<option value="${f[0]}" ${c.font===f[0]?'selected':''}>${f[1]}</option>`).join('')}</select></div><div><label>Font sync</label><label class="setting-row"><input type="checkbox" id="corkMatchFont" ${c.matchWorkspaceFont?'checked':''}> Use workspace font instead of handwriting.</label></div></div>
<label class="setting-row"><input type="checkbox" id="corkMatchText" ${c.matchThemeText!==false?'checked':''}> Make board text match the workspace theme.</label>
<div class="tiny">Tip: when free move is on, drag a pin to move it. Use the pin’s ⋯ menu to rotate, edit, archive, download, or delete it.</div><div class="actions"><button data-action="saveCorkSettings">Save Cork Board Settings</button><button class="secondary" data-action="resetPinLayout">Reset pin layout</button></div>`;};
 applyCorkSettingsFromInputs=function(){state.corkSettings=state.corkSettings||{}; state.corkSettings.freeMove=!!document.getElementById('corkFreeMove')?.checked; state.corkSettings.borderDesign=val('corkDesign')||'floral'; state.corkSettings.borderColor=document.querySelector('input[name="corkBorderRadio"]:checked')?.value||'theme'; state.corkSettings.customBorder=val('corkCustomBorder')||'#f5b7c8'; state.corkSettings.boardColor=document.querySelector('input[name="corkBoardRadio"]:checked')?.value||'natural'; state.corkSettings.customBoard=val('corkCustomBoard')||'#d6a777'; state.corkSettings.font=val('corkFont')||'comic'; state.corkSettings.matchWorkspaceFont=!!document.getElementById('corkMatchFont')?.checked; state.corkSettings.matchThemeText=!!document.getElementById('corkMatchText')?.checked;};
 const prevApplyTheme=applyTheme;
 applyTheme=function(){prevApplyTheme(); const bp=document.getElementById('corkBorderPreview'), cp=document.getElementById('corkBoardPreview'); if(bp)bp.style.background=val('corkCustomBorder')||state.corkSettings?.customBorder||'#f5b7c8'; if(cp)cp.style.background=val('corkCustomBoard')||state.corkSettings?.customBoard||'#d6a777';};
 const prevHandleAction=handleAction;
 handleAction=function(action,el){
   if(action==='toggleMenuPage'){ if(el.dataset.page==='settings'){toast('Settings stays available at the bottom.');return;} toggleIn(state.layout.menuHidden,el.dataset.page); state.settingsOpenSection='menu'; if(state.activePage!=='settings'&&state.layout.menuHidden.includes(state.activePage))state.activePage='dashboard'; save('Menu layout saved.'); return; }
   if(action==='closeDashboardHero'){ if(document.getElementById('dontShowDashboardHero')?.checked){state.hideDashboardHero=true; save('Command center message hidden.');} else {dashboardHeroClosedSession=true; renderAll();} return; }
   if(action==='viewMonthlySource'){ const source=el.dataset.source, id=el.dataset.id; if(source==='weekly')viewWeekly(id); else viewMonthlyVisible(id); return; }
   return prevHandleAction(action,el);
 };
 const prevRenderAll=renderAll;
 renderAll=function(){prevRenderAll(); document.querySelectorAll('.menu-list-row button[data-action="toggleMenuPage"]').forEach(b=>b.classList.add('menu-hide-small'));};
 document.addEventListener('click',e=>{const btn=e.target.closest('.map-menu-btn'); if(btn){e.preventDefault(); e.stopPropagation(); const item=btn.closest('.map-item'); document.querySelectorAll('.map-item.menu-open').forEach(x=>{if(x!==item)x.classList.remove('menu-open')}); item?.classList.toggle('menu-open'); return;} if(!e.target.closest('.map-item'))document.querySelectorAll('.map-item.menu-open').forEach(x=>x.classList.remove('menu-open'));});
 document.addEventListener('input',e=>{ if(e.target.id==='corkCustomBorder'){const p=document.getElementById('corkBorderPreview'); if(p)p.style.background=e.target.value;} if(e.target.id==='corkCustomBoard'){const p=document.getElementById('corkBoardPreview'); if(p)p.style.background=e.target.value;} });
 document.addEventListener('change',e=>{ if(e.target.name==='corkBorderRadio'||e.target.name==='corkBoardRadio'){ document.querySelectorAll(`input[name="${e.target.name}"]`).forEach(r=>r.closest('.cork-choice')?.classList.toggle('active',r.checked)); }});
 const prevPrintSubPacket=typeof printSubPacket==='function'?printSubPacket:null;
 printSubPacket=function(){const w=window.open('','_blank'); const html=subPacketHtml(); w.document.write('<!doctype html><html><head><title>SOZY Substitute Guide</title><style>@page{margin:.5in}html,body{margin:0!important;padding:0!important;height:auto!important;min-height:0!important;background:#fff!important}body{font-family:Arial,sans-serif;color:#111}.subpacket{margin:0;padding:0;break-before:auto;break-after:auto;page-break-before:auto;page-break-after:auto}.subpacket table{width:100%;border-collapse:collapse}.subpacket td,.subpacket th{border:1px solid #444;padding:6px}.subpacket h1{font-size:24px;margin:0 0 10px}.subpacket h2{font-size:18px;margin:14px 0 8px}</style></head><body>'+html+'</body></html>'); w.document.close(); setTimeout(()=>w.print(),250);};
})();


/* SOZY Workspace full polish patch 2026-06-06_2038-CT */
const sozyFullPatchStyle=document.createElement('style');
sozyFullPatchStyle.textContent=`
/* Header + title polish */
.topbar{text-align:center;justify-content:center}.topbar>div:first-child{flex:1;justify-content:center;text-align:center}.topbar h2,.topbar p{text-align:center!important}.topbar .top-actions{position:absolute;right:22px;top:50%;transform:translateY(-50%)}body.map-page .topbar{position:static}.card h3,.compact-title,.standardized-card-title{text-align:center}.card .card-body>p.tiny:first-child{text-align:center}.card .muted{text-align:center}
/* Buttons should stand out */
.actions button,button[data-action],.buttonlike{font-weight:1000;border-color:color-mix(in srgb,var(--brand) 42%,var(--line));box-shadow:0 8px 20px rgba(0,0,0,.08)}button:not(.icon-btn):not(.menu-edge):not(.map-menu-btn):not(.mini-x):not(.brandmark){background:linear-gradient(135deg,var(--brand),var(--brand2));color:#fff}button.secondary,.buttonlike.secondary{background:linear-gradient(135deg,color-mix(in srgb,var(--brand3) 36%,var(--surface)),color-mix(in srgb,var(--brand) 18%,var(--surface2)))!important;color:var(--ink)!important}.danger,button.danger{background:linear-gradient(135deg,#d94c5c,#ff8b8b)!important;color:#fff!important;border-color:#d94c5c!important}.good,button.good{background:linear-gradient(135deg,#2f9b6f,#7bd39d)!important;color:#fff!important;border-color:#2f9b6f!important}.wide-action{width:100%;justify-content:center;margin:6px 0}.stack-actions{display:grid;gap:8px;margin:10px 0}.bottom-actions{margin-top:12px;display:grid;gap:8px}
/* Modals, lists, exports */
.student-modal-form .actions,.assignment-modal-form .actions{justify-content:center}.x-close{border-radius:999px;min-width:40px}.student-export-block,.assignment-export-block,.grade-export-block{display:grid;gap:8px;margin-top:12px}.archive-inline{margin-top:10px;border:1px dashed var(--line);border-radius:16px;padding:10px;background:color-mix(in srgb,var(--surface2) 55%,transparent)}.archive-title,.supplies-list-title{display:flex;align-items:center;justify-content:space-between;gap:8px;margin:8px 0}.student-card-highlight{border-width:2px}.student-standing-red,.score-standing-red,.todo-priority-high,.supply-low{background:color-mix(in srgb,#ff5c70 20%,var(--surface))!important;border-color:color-mix(in srgb,#ff5c70 55%,var(--line))!important}.student-standing-yellow,.score-standing-yellow,.todo-priority-medium,.supply-mid{background:color-mix(in srgb,#f5c84b 24%,var(--surface))!important;border-color:color-mix(in srgb,#f5c84b 60%,var(--line))!important}.student-standing-green,.score-standing-green,.todo-priority-low,.supply-ok{background:color-mix(in srgb,#50b979 20%,var(--surface))!important;border-color:color-mix(in srgb,#50b979 55%,var(--line))!important}.grade-table tr.student-standing-red .student-cell,.grade-table tr.student-standing-yellow .student-cell,.grade-table tr.student-standing-green .student-cell{background:inherit!important}.grade-table td.score-standing-red input,.grade-table td.score-standing-yellow input,.grade-table td.score-standing-green input{background:rgba(255,255,255,.72);font-weight:950}
/* Meetings and to-dos */
.meeting-toolbar,.todo-toolbar{display:grid;gap:8px}.meeting-controls,.todo-controls{display:grid;grid-template-columns:1fr 180px;gap:8px;margin:10px 0}.meeting-list,.todo-list{display:grid;gap:10px}.todo-card-row{display:flex;align-items:center;gap:10px;justify-content:space-between}.todo-actions,.entry-actions{display:flex;gap:8px;align-items:center;justify-content:flex-end;flex-wrap:wrap}.subnote-actions-centered,.subnote-actions-center{display:flex;justify-content:center;gap:10px;flex-wrap:wrap;margin-top:14px}
/* Classroom map */
.map-top-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:12px}.map-top-grid .plain-block{margin:0}.map-side .actions{display:grid;grid-template-columns:1fr;gap:8px}.map-options-title{font-weight:1000;text-align:center;margin-bottom:8px}.unassigned-scroll{max-height:330px;overflow:auto;border:1px dashed var(--line);border-radius:14px;padding:8px;background:rgba(255,255,255,.35)}.map-item.door,.map-item.window{background:color-mix(in srgb,var(--brand3) 22%,var(--surface));border-style:dashed}.map-item .assigned,.map-item b{text-align:center;line-height:1.15;overflow-wrap:anywhere}.print-map-note{font-size:12px;color:var(--muted);margin-top:6px}
/* Gallery cleanup */
.gallery-hero{display:flex;justify-content:space-between;align-items:center;gap:16px;padding:18px;border-radius:22px;background:linear-gradient(135deg,color-mix(in srgb,var(--brand3) 20%, var(--surface)),color-mix(in srgb,var(--brand2) 12%, var(--surface)));border:1px solid var(--line);box-shadow:var(--shadow);margin-bottom:16px}.gallery-hero h3{margin:0}.gallery-hero p{margin:6px 0 0;color:var(--muted);font-weight:750}.gallery-grid{display:grid!important;grid-template-columns:repeat(auto-fill,minmax(230px,1fr));gap:14px}.gallery-doc{border:1px solid var(--line);border-radius:20px;padding:12px;background:var(--surface);box-shadow:var(--shadow);transition:.18s ease}.gallery-doc:hover{transform:translateY(-2px);border-color:var(--brand);background:color-mix(in srgb,var(--brand3) 10%,var(--surface))}.gallery-thumb{height:120px;border-radius:16px;display:grid;place-items:center;background:linear-gradient(135deg,color-mix(in srgb,var(--brand3) 18%,var(--surface2)),var(--surface2));border:1px solid var(--line);overflow:hidden;margin-bottom:10px}.gallery-thumb img{width:100%;height:100%;object-fit:cover}.gallery-thumb span{font-size:38px}.gallery-meta-chip{display:inline-flex;padding:5px 8px;border-radius:999px;background:var(--surface2);border:1px solid var(--line);font-size:11px;font-weight:950;color:var(--muted);margin-top:6px}.gallery-doc .actions{justify-content:space-between;margin-top:10px}
/* Group names + cork colors */
.group-card{border:1px solid var(--line);background:var(--surface);border-radius:18px;padding:12px;box-shadow:var(--shadow);display:grid;gap:8px}.group-name-label{font-size:11px;font-weight:1000;color:var(--muted);text-transform:uppercase;letter-spacing:.04em}.group-name-input{font-weight:1000;font-size:16px;background:color-mix(in srgb,var(--brand3) 12%, var(--surface));border-color:var(--line)}.group-members{display:grid;gap:4px}.group-member{padding:6px 8px;border-radius:10px;background:var(--surface2);font-weight:850}.cork-color-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:10px;margin:8px 0 12px}.cork-choice{border:1px solid var(--line);background:var(--surface2);border-radius:16px;padding:10px;display:grid!important;grid-template-columns:42px 1fr;align-items:center;gap:10px;cursor:pointer;min-height:54px}.cork-choice span:first-child{width:42px!important;height:34px!important;border-radius:12px!important;border:2px solid rgba(0,0,0,.18)!important;box-shadow:inset 0 0 0 2px rgba(255,255,255,.35),0 4px 12px rgba(0,0,0,.12)}.cork-choice b{font-size:13px;line-height:1.1}.cork-choice.active{outline:3px solid color-mix(in srgb,var(--brand) 36%, transparent);border-color:var(--brand)}.cork-custom-preview{height:46px!important;border:2px solid var(--line);color:var(--ink)!important;text-shadow:0 1px 1px rgba(255,255,255,.45)}
@media(max-width:900px){.map-top-grid,.meeting-controls,.todo-controls{grid-template-columns:1fr}.topbar .top-actions{position:static;transform:none}.topbar{display:block}.topbar>div:first-child{display:block}.planner-actions-wide,.monthly-toolbar-clean{grid-template-columns:1fr}}
`;
document.head.appendChild(sozyFullPatchStyle);

function scoreLevelClass(avg){ if(avg==null || isNaN(avg)) return ''; avg=Number(avg); if(avg>=50) return 'standing-green'; if(avg>=26) return 'standing-yellow'; return 'standing-red'; }
function scoreCellClass(score,points,missing,excused){ if(excused) return ''; if(missing) return 'score-standing-red'; const p=Number(points)||0; if(!p || score==='' || score==null || isNaN(Number(score))) return ''; const pct=(Number(score)/p)*100; if(pct>=50) return 'score-standing-green'; if(pct>=26) return 'score-standing-yellow'; return 'score-standing-red'; }

const normalizeBeforeFullPatch=normalize;
normalize=function(){normalizeBeforeFullPatch();state.studentModalOpen=!!state.studentModalOpen;state.assignmentModalOpen=!!state.assignmentModalOpen;state.studentViewArchived=!!state.studentViewArchived;state.assignmentViewArchived=!!state.assignmentViewArchived;state.meetingViewArchived=!!state.meetingViewArchived;state.todoFilter=state.todoFilter||'';state.todoOrder=state.todoOrder||'priority';state.groups=(state.groups||[]).map((g,i)=>Array.isArray(g)?{id:uid('group'),name:`Group ${i+1}`,members:g}:{id:g.id||uid('group'),name:g.name||`Group ${i+1}`,members:Array.isArray(g.members)?g.members:[]});(state.meetings||[]).forEach(m=>{if(typeof m.archived==='undefined')m.archived=false});(state.todos||[]).forEach(t=>{if(typeof t.archived==='undefined')t.archived=false});state.corkSettings=state.corkSettings||{};if(!state.corkSettings.defaultNoDecorApplied){if(!state.corkSettings.borderDesign || state.corkSettings.borderDesign==='floral')state.corkSettings.borderDesign='none';state.corkSettings.defaultNoDecorApplied=true;}};

function ensureModalShell(id,title,subtitle,closeAction){let m=document.getElementById(id);if(!m){m=document.createElement('div');m.id=id;m.className='modal';m.setAttribute('aria-hidden','true');document.body.appendChild(m);}m.innerHTML=`<div class="modal-box"><div class="item-head"><div><h2 style="margin:0">${title}</h2><p class="muted">${subtitle}</p></div><button class="secondary x-close" data-action="${closeAction}">✕</button></div><div id="${id}Body"></div></div>`;return m;}
function renderStudentModal(){const m=ensureModalShell('studentModal','Add Student','Add one student record. You can edit or archive it later.','closeStudentModal');m.classList.toggle('open',!!state.studentModalOpen);const b=document.getElementById('studentModalBody');if(b)b.innerHTML=`<div class="student-modal-form"><label>Student First Name Or Nickname</label><input id="studentName" placeholder="Avery"><div class="formrow two"><div><label>Status</label><select id="studentStatus"><option>Active</option><option>Needs Support</option><option>Monitor</option></select></div><div><label>Notes</label><input id="studentNotes" placeholder="Optional Teacher Notes"></div></div><div class="actions"><button data-action="saveStudentFromModal">Save</button><button class="secondary" data-action="closeStudentModal">Cancel</button></div></div>`;}
function renderAssignmentModal(){const m=ensureModalShell('assignmentModal','Add Assignment','Add one assignment for your gradebook. You can edit it later.','closeAssignmentModal');m.classList.toggle('open',!!state.assignmentModalOpen);const b=document.getElementById('assignmentModalBody');if(b)b.innerHTML=`<div class="assignment-modal-form"><label>Assignment</label><input id="assignmentTitle" placeholder="Reading Check"><div class="formrow three"><div><label>Subject</label><input id="assignmentSubject" placeholder="Reading"></div><div><label>Category</label><select id="assignmentCategory"><option>Classwork</option><option>Homework</option><option>Quiz</option><option>Test</option><option>Project</option><option>Participation</option></select></div><div><label>Points</label><input id="assignmentPoints" type="number" value="10"></div></div><div class="formrow two"><div><label>Date</label><input id="assignmentDate" type="date" value="${new Date().toISOString().slice(0,10)}"></div><div><label>Link To Lesson</label><select id="assignmentLesson"><option value="">No Lesson Link</option>${state.lessons.filter(l=>!l.archived).map(l=>`<option value="${l.id}">${esc(l.title)}</option>`).join('')}</select></div></div><div class="actions"><button data-action="saveAssignmentFromModal">Save</button><button class="secondary" data-action="closeAssignmentModal">Cancel</button></div></div>`;}
const renderAllBeforeFullPatch=renderAll;
renderAll=function(){renderAllBeforeFullPatch();document.body.classList.toggle('map-page',state.activePage==='map');renderStudentModal();renderAssignmentModal();};
const renderHeaderBeforeFullPatch=renderHeader;
renderHeader=function(){renderHeaderBeforeFullPatch();document.body.classList.toggle('map-page',state.activePage==='map');};

function studentArchiveHtml(){const archived=state.students.filter(s=>s.archived);return state.studentViewArchived?`<div class="archive-inline"><div class="archive-title"><b>Archived Students</b><span class="pill">${archived.length}</span></div>${archived.map(s=>`<div class="item"><div class="item-title">${esc(s.name)}</div><div class="item-meta">${esc(s.status||'')} • ${esc(s.notes||'')}</div><div class="entry-actions"><button class="small secondary" data-action="restoreStudent" data-id="${s.id}">Restore</button><button class="small danger" data-action="deleteStudent" data-id="${s.id}">Delete</button></div></div>`).join('')||empty('No Archived Students.')}</div>`:'';}
studentsHtml=function(){const list=state.students.filter(s=>!s.archived);return `<div class="stack-actions"><button class="wide-action" data-action="openStudentModal">➕ Add Student</button><button class="secondary wide-action" data-action="toggleStudentArchives">${state.studentViewArchived?'Hide Archived Students':'View Archived Students'}</button></div>${studentArchiveHtml()}${list.map(studentRow).join('')||empty('No Students Yet. Add first names or nicknames only if you want extra privacy.')}<div class="student-export-block"><button class="secondary" data-action="downloadStudentsCsv">Download Student List CSV</button></div>`;};
studentRow=function(s){if(state.editing.students[s.id])return `<div class="item"><div class="formrow three"><div><label>Name</label><input id="es_name_${s.id}" value="${esc(s.name)}"></div><div><label>Status</label><input id="es_status_${s.id}" value="${esc(s.status)}"></div><div><label>Notes</label><input id="es_notes_${s.id}" value="${esc(s.notes)}"></div></div><label>Last Edited</label><input type="datetime-local" id="es_time_${s.id}" value="${toLocalInput(s.updatedAt)}">${attachmentPanel('students',s.id,s.name)}<div class="actions"><button class="small good" data-action="saveStudent" data-id="${s.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="students" data-id="${s.id}">Cancel</button></div></div>`;const avg=studentAverage(s.id);const cls=scoreLevelClass(avg);return `<div class="item with-paperclip student-card-highlight student-${cls}">${attachmentIndicator('students',s.id)}<div class="item-head"><div><div class="item-title">${esc(s.name)}</div><div class="item-meta">${esc(s.status||'Active')} • ${esc(s.notes||'No Notes')} • Last Edited ${fmt(s.updatedAt)}</div></div><span>${gradeBadge(avg)}</span></div><div class="entry-actions"><button class="small secondary" data-action="editStudent" data-id="${s.id}">Edit</button><button class="small secondary" data-action="archiveStudent" data-id="${s.id}">Archive</button><button class="small danger delete-right" data-action="deleteStudent" data-id="${s.id}">Delete</button></div></div>`;};
function assignmentArchiveHtml(){const archived=state.assignments.filter(a=>a.archived);return state.assignmentViewArchived?`<div class="archive-inline"><div class="archive-title"><b>Archived Assignments</b><span class="pill">${archived.length}</span></div>${archived.map(a=>`<div class="item"><div class="item-title">${esc(a.title)}</div><div class="item-meta">${esc(a.subject||'')} • ${esc(a.category||'')} • ${esc(a.points||0)} pts</div><div class="entry-actions"><button class="small secondary" data-action="restoreAssignment" data-id="${a.id}">Restore</button><button class="small danger" data-action="deleteAssignment" data-id="${a.id}">Delete</button></div></div>`).join('')||empty('No Archived Assignments.')}</div>`:'';}
assignmentsHtml=function(){return `<div class="stack-actions"><button class="wide-action" data-action="openAssignmentModal">➕ Add Assignment</button><button class="secondary wide-action" data-action="toggleAssignmentArchives">${state.assignmentViewArchived?'Hide Archived Assignments':'View Archived Assignments'}</button></div>${assignmentArchiveHtml()}${activeAssignments().map(assignmentRow).join('')||empty('No Assignments Yet.')}<div class="assignment-export-block"><button class="secondary" data-action="downloadAssignmentsCsv">Download Assignments CSV</button></div>`;};
assignmentRow=function(a){if(state.editing.assignments[a.id])return `<div class="item"><div class="formrow four"><div><label>Title</label><input id="ea_title_${a.id}" value="${esc(a.title)}"></div><div><label>Subject</label><input id="ea_subject_${a.id}" value="${esc(a.subject)}"></div><div><label>Category</label><input id="ea_category_${a.id}" value="${esc(a.category)}"></div><div><label>Points</label><input id="ea_points_${a.id}" type="number" value="${esc(a.points)}"></div></div><div class="formrow two"><div><label>Date</label><input id="ea_date_${a.id}" type="date" value="${esc(a.date)}"></div><div><label>Last Edited</label><input id="ea_time_${a.id}" type="datetime-local" value="${toLocalInput(a.updatedAt)}"></div></div>${attachmentPanel('assignments',a.id,a.title)}<div class="actions"><button class="small good" data-action="saveAssignment" data-id="${a.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="assignments" data-id="${a.id}">Cancel</button></div></div>`;const linked=state.lessons.find(l=>l.id===a.lessonId);return `<div class="item with-paperclip">${attachmentIndicator('assignments',a.id)}<div class="item-title">${esc(a.title)}</div><div class="item-meta">${esc(a.subject||'No Subject')} • ${esc(a.category||'Classwork')} • ${esc(a.points||0)} pts • ${esc(a.date||'No Date')} ${linked?'• Lesson: '+esc(linked.title):''} • Last Edited ${fmt(a.updatedAt)}</div><div class="entry-actions"><button class="small secondary" data-action="editAssignment" data-id="${a.id}">Edit</button><button class="small secondary" data-action="archiveAssignment" data-id="${a.id}">Archive</button><button class="small danger delete-right" data-action="deleteAssignment" data-id="${a.id}">Delete</button></div></div>`;};

gradebookHtml=function(){const st=activeStudents(),as=activeAssignments();if(!st.length||!as.length)return `${empty('Add Students And Assignments First. Then The Grade Book Table Appears Here.')}<div class="grade-export-block"><button class="secondary" data-action="downloadGradesCsv">Download Grade Book CSV</button><button class="secondary" data-action="printGrades">Print / Save as PDF Grade Summary</button></div>`;return `<p class="tiny">Type scores directly in the boxes. Use M for missing and X for excused. Every score gets a timestamp when saved.</p><div class="grade-table-wrap"><table class="grade-table"><thead><tr><th>Student</th>${as.map(a=>`<th>${esc(a.title)}<div class="tiny">${esc(a.points)} pts</div></th>`).join('')}<th>Average</th></tr></thead><tbody>${st.map(s=>{const avg=studentAverage(s.id);const rowCls='student-'+scoreLevelClass(avg);return `<tr class="${rowCls}"><td class="student-cell">${esc(s.name)}<div class="tiny">${esc(s.status||'')}</div></td>${as.map(a=>scoreCell(s,a)).join('')}<td>${gradeBadge(avg)}</td></tr>`}).join('')}</tbody></table></div><div class="grade-export-block"><button class="secondary" data-action="downloadGradesCsv">Download Grade Book CSV</button><button class="secondary" data-action="printGrades">Print / Save as PDF Grade Summary</button></div>`;};
scoreCell=function(s,a){const key=s.id+'_'+a.id;const sc=state.scores[key]||{};const cls=scoreCellClass(sc.score,a.points,sc.missing,sc.excused);return `<td class="${cls}"><input type="text" value="${esc(sc.missing?'M':sc.excused?'X':(sc.score??''))}" data-score="${key}" data-student="${s.id}" data-assignment="${a.id}" placeholder="0-${esc(a.points)}"><div class="tiny">${sc.updatedAt?'Saved '+fmt(sc.updatedAt):'Not Entered'}</div></td>`;};
gradesPage=function(){const defs=[['gradeStats',card('grades','gradeStats','📊 Grade Dashboard',gradeDashboardHtml(),{size:'lg',controls:false})],['students',card('grades','students','👧 Students',studentsHtml(),{size:'lg',controls:false})],['assignments',card('grades','assignments','🧾 Assignments',assignmentsHtml(),{size:'lg',controls:false})],['gradebook',card('grades','gradebook','📝 Grade Book Table',gradebookHtml(),{size:'lg',controls:false})]];return renderCards('grades',defs,'grid');};
function downloadAssignmentsCsv(){downloadText('sozy-assignments.csv',csv(['Title','Subject','Category','Points','Date','Lesson','Updated'],activeAssignments().map(a=>[a.title,a.subject,a.category,a.points,a.date,(state.lessons.find(l=>l.id===a.lessonId)||{}).title||'',fmt(a.updatedAt)])));}

function meetingArchiveHtml(){const archived=state.meetings.filter(m=>m.archived);return state.meetingViewArchived?`<div class="archive-inline"><div class="archive-title"><b>Archived Notes</b><span class="pill">${archived.length}</span></div>${archived.map(m=>meetingRow(m)).join('')||empty('No Archived Meeting Notes.')}</div>`:'';}
meetingHtml=function(){let notes=[...state.meetings].filter(m=>state.meetingViewArchived?!!m.archived:!m.archived);const q=(state.meetingFilter||'').toLowerCase().trim();if(q)notes=notes.filter(m=>[m.title,m.date,m.notes].join(' ').toLowerCase().includes(q));const order=state.meetingOrder||'received';notes.sort((a,b)=>{if(order==='newest')return new Date(b.createdAt||b.date||0)-new Date(a.createdAt||a.date||0);if(order==='title')return (a.title||'').localeCompare(b.title||'');return new Date(a.createdAt||a.date||0)-new Date(b.createdAt||b.date||0);});const form=state.showMeetingForm?`<div class="meet-add-panel"><div class="formrow two"><div><label>Meeting Title</label><input id="meetingTitle" placeholder="IEP Meeting, Grade-Level Planning..."></div><div><label>Date</label><input id="meetingDate" type="date" value="${new Date().toISOString().slice(0,10)}"></div></div><label>Notes</label><textarea id="meetingNotes" placeholder="What was decided? What needs follow-up?"></textarea><div class="actions"><button data-action="addMeeting">Save Meeting Note</button><button class="secondary" data-action="toggleMeetingForm">Cancel</button></div></div>`:'';return `<div class="meeting-toolbar"><button class="wide-action" data-action="toggleMeetingForm">➕ Add Meeting Note</button><button class="secondary wide-action" data-action="toggleMeetingArchives">${state.meetingViewArchived?'Hide Archived Notes':'View Archived Notes'}</button></div>${form}<div class="meeting-history-head"><h4 class="compact-title">Meeting Notes History</h4><span class="pill">${notes.length} Note${notes.length===1?'':'s'}</span></div><div class="meeting-controls"><input id="meetingFilterInput" value="${esc(state.meetingFilter||'')}" placeholder="Filter Meeting Notes..."><select id="meetingOrder"><option value="received" ${order==='received'?'selected':''}>Oldest Received First</option><option value="newest" ${order==='newest'?'selected':''}>Newest First</option><option value="title" ${order==='title'?'selected':''}>Title A To Z</option></select></div><div class="meeting-list">${notes.map(meetingRow).join('')||empty(state.meetingViewArchived?'No Archived Meeting Notes.':'No Meeting Notes Yet.')}</div>`;};
meetingRow=function(m){if(state.editing.meetings[m.id])return `<div class="item"><div class="formrow two"><div><label>Title</label><input id="em_title_${m.id}" value="${esc(m.title)}"></div><div><label>Date</label><input id="em_date_${m.id}" type="date" value="${esc(m.date)}"></div></div><label>Notes</label><textarea id="em_notes_${m.id}">${esc(m.notes)}</textarea><label>Last Edited</label><input type="datetime-local" id="em_time_${m.id}" value="${toLocalInput(m.updatedAt)}">${attachmentPanel('meetings',m.id,m.title)}<div class="actions"><button class="small good" data-action="saveMeeting" data-id="${m.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="meetings" data-id="${m.id}">Cancel</button></div></div>`;return `<div class="item with-paperclip">${attachmentIndicator('meetings',m.id)}<div class="item-title">${esc(m.title)}</div><div class="item-meta">${esc(m.date)} • Last Edited ${fmt(m.updatedAt)} ${m.archived?'• Archived':''}</div><p class="tiny">${esc(m.notes)}</p><div class="entry-actions"><button class="small secondary" data-action="editMeeting" data-id="${m.id}">Edit</button><button class="small secondary" data-action="archiveMeeting" data-id="${m.id}">${m.archived?'Restore':'Archive'}</button><button class="small danger delete-right" data-action="deleteMeeting" data-id="${m.id}">Delete</button></div></div>`;};

todoHtml=function(){const show=!!state.todoViewArchives;let tasks=[...state.todos].filter(t=>show?!!t.archived:!t.archived);const q=(state.todoFilter||'').toLowerCase().trim();if(q)tasks=tasks.filter(t=>[t.text,t.priority].join(' ').toLowerCase().includes(q));const ord=state.todoOrder||'priority';const rank={High:0,Medium:1,Low:2};tasks.sort((a,b)=>{if(ord==='newest')return new Date(b.createdAt||0)-new Date(a.createdAt||0);if(ord==='oldest')return new Date(a.createdAt||0)-new Date(b.createdAt||0);if(ord==='title')return (a.text||'').localeCompare(b.text||'');return (rank[a.priority]??9)-(rank[b.priority]??9)||Number(a.done)-Number(b.done)||new Date(a.createdAt||0)-new Date(b.createdAt||0);});return `<div class="todo-toolbar"><button class="wide-action" data-action="openTaskModal">➕ Add Task</button><button class="secondary wide-action" data-action="toggleTodoArchives">${show?'Hide Archived Tasks':'View Archived Tasks'}</button></div><h4 class="compact-title">My To-Do List</h4><div class="todo-controls"><input id="todoFilterInput" value="${esc(state.todoFilter||'')}" placeholder="Filter To-Dos..."><select id="todoOrder"><option value="priority" ${ord==='priority'?'selected':''}>Priority First</option><option value="newest" ${ord==='newest'?'selected':''}>Newest First</option><option value="oldest" ${ord==='oldest'?'selected':''}>Oldest First</option><option value="title" ${ord==='title'?'selected':''}>Title A To Z</option></select></div><div class="todo-list">${tasks.map(todoRow).join('')||empty(show?'No Archived Tasks.':'No Tasks Yet.')}</div>`;};
todoRow=function(t){if(state.editing.todos[t.id])return `<div class="item"><div class="formrow three"><div><label>Task</label><input id="et_text_${t.id}" value="${esc(t.text)}"></div><div><label>Priority</label><select id="et_priority_${t.id}"><option ${t.priority==='Low'?'selected':''}>Low</option><option ${t.priority==='Medium'?'selected':''}>Medium</option><option ${t.priority==='High'?'selected':''}>High</option></select></div><div><label>Last Edited</label><input type="datetime-local" id="et_time_${t.id}" value="${toLocalInput(t.updatedAt)}"></div></div>${attachmentPanel('todos',t.id,t.text)}<div class="actions"><button class="small good" data-action="saveTodo" data-id="${t.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="todos" data-id="${t.id}">Cancel</button></div></div>`;const pc=priorityClass(t.priority);return `<div class="item with-paperclip todo-priority-${pc}">${attachmentIndicator('todos',t.id)}<div class="todo-card-row"><div><div class="item-title">${t.done?'✅':'⬜'} ${esc(t.text)}</div><div class="item-meta"><span class="priority-pill ${pc}">${esc(t.priority||'Medium')}</span> • Last Edited ${fmt(t.updatedAt)} ${t.archived?'• Archived':''}</div></div><div class="todo-actions"><button class="small secondary" data-action="toggleTodo" data-id="${t.id}">${t.done?'Reopen':'Done'}</button><button class="small secondary" data-action="editTodo" data-id="${t.id}">Edit</button><button class="small secondary" data-action="archiveTodo" data-id="${t.id}">${t.archived?'Restore':'Archive'}</button><button class="small danger" data-action="deleteTodo" data-id="${t.id}">Delete</button></div></div></div>`;};

suppliesHtml=function(){const show=!!state.supplyViewArchives;const active=state.supplies.filter(s=>show?!!s.archived:!s.archived);return `<div class="formrow four"><div><label>Item</label><input id="sItem" placeholder="Glue Sticks"></div><div><label>Have</label><input id="sHave" type="number" value="0"></div><div><label>Need</label><input id="sNeed" type="number" value="0"></div><div><label>Location</label><input id="sLocation" placeholder="Cabinet"></div></div><label>Note</label><input id="sNote" placeholder="Optional Note"><div class="actions"><button data-action="addSupply">Add Supply</button><button class="secondary" data-action="toggleSupplyArchives">${show?'Hide Archived Supplies':'View Archived Supplies'}</button></div><div class="supplies-list-title"><b>${show?'Archived Supplies':'Current Supplies'}</b><span class="pill">${active.length}</span></div>${active.map(supplyRow).join('')||empty(show?'No Archived Supplies.':'No Active Supplies Saved.')}`;};
supplyRow=function(s){if(state.editing.supplies[s.id])return `<div class="item"><div class="formrow four"><div><label>Item</label><input id="esu_item_${s.id}" value="${esc(s.item)}"></div><div><label>Have</label><input id="esu_have_${s.id}" type="number" value="${esc(s.have)}"></div><div><label>Need</label><input id="esu_need_${s.id}" type="number" value="${esc(s.need)}"></div><div><label>Location</label><input id="esu_loc_${s.id}" value="${esc(s.location)}"></div></div><label>Note</label><input id="esu_note_${s.id}" value="${esc(s.note)}"><label>Last Edited</label><input type="datetime-local" id="esu_time_${s.id}" value="${toLocalInput(s.updatedAt)}"><div class="actions"><button class="small good" data-action="saveSupply" data-id="${s.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="supplies" data-id="${s.id}">Cancel</button></div></div>`;const low=Number(s.have)<Number(s.need);return `<div class="item ${low?'supply-low':'supply-ok'}"><div class="item-head"><div><div class="item-title">${low?'⚠️ ':''}${esc(s.item)}</div><div class="item-meta">Have ${esc(s.have)} / Need ${esc(s.need)} • ${esc(s.location)} • Last Edited ${fmt(s.updatedAt)} ${s.archived?'• Archived':''}</div><p class="tiny">${esc(s.note)}</p></div><span class="pill ${low?'warn':'good'}">${low?'Low':'OK'}</span></div><div class="entry-actions"><button class="small secondary" data-action="editSupply" data-id="${s.id}">Edit</button><button class="small secondary" data-action="${s.archived?'restoreSupply':'archiveSupply'}" data-id="${s.id}">${s.archived?'Restore':'Archive'}</button><button class="small danger delete-right" data-action="deleteSupply" data-id="${s.id}">Delete</button></div></div>`;};

subNotesHtml=function(){const f=state.subNotes.fields||{};return `${subPrompt('overview','Class Overview','What should the sub know about your class personality, energy level, or general expectations?',f.overview)}${subPrompt('attendance','Attendance / Lunch Count','How should attendance, lunch count, bathroom passes, or office notes be handled?',f.attendance)}${subPrompt('schedule','Daily Flow','What does the normal day look like? What should not be skipped?',f.schedule)}${subPrompt('behavior','Behavior Support','What behavior system, rewards, consequences, calming tools, or redirection words should the sub use?',f.behavior)}${subPrompt('students','Student Support Notes','Are there students who may need extra help, seating reminders, medical attention, or quiet support? Keep this professional and need-to-know.',f.students)}${subPrompt('materials','Materials / Technology','Where are worksheets, books, logins, remotes, projector tools, and center materials? Avoid writing private passwords if your school does not allow it.',f.materials)}${subPrompt('emergency','Emergency Procedures','What should the sub do for fire drill, lockdown, nurse, office call, or urgent classroom help?',f.emergency)}${subPrompt('dismissal','Dismissal','How do students leave? Bus, pickup, after-school program, walkers, or dismissal jobs?',f.dismissal)}${subPrompt('extra','Extra Comments','Anything else the substitute should know that does not fit above?',f.extra)}<div class="subnote-actions-centered"><button data-action="saveSubNotes">Save Changes</button><button class="secondary" data-action="undoSubNotes">Undo</button><button class="danger" data-action="clearSubNotes">Clear All</button></div>`;};

renderGroups=function(){return (state.groups||[]).map((g,i)=>`<div class="group-card" data-group-id="${g.id}"><span class="group-name-label">Group Name</span><input class="group-name-input" data-group-name-id="${g.id}" value="${esc(g.name||`Group ${i+1}`)}" aria-label="Group Name"><div class="group-members">${(g.members||[]).map(n=>`<div class="group-member">${esc(n)}</div>`).join('')||'<div class="group-empty">No Students In This Group Yet.</div>'}</div></div>`).join('')||empty('No Groups Made Yet.');};
makeGroups=function(){const names=val('studentNames').split(/\n|,/).map(x=>x.trim()).filter(Boolean);const count=Math.max(1,Number(val('groupCount')||1));const shuffled=[...names].sort(()=>Math.random()-.5);state.groups=Array.from({length:count},(_,i)=>({id:uid('group'),name:`Group ${i+1}`,members:[]}));shuffled.forEach((n,i)=>state.groups[i%count].members.push(n));save('Groups made. You can rename each group.');};

function colorChoiceGrid(name,choices,current){return `<div class="cork-color-grid">${choices.map(c=>`<label class="cork-choice ${current===c[0]?'active':''}" title="${esc(c[1])}"><input type="radio" name="${name}" value="${c[0]}" ${current===c[0]?'checked':''} style="display:none"><span style="background:${c[2]}"></span><b>${esc(c[1])}</b></label>`).join('')}</div>`;}
const borderChoicesPatch=[['theme','Theme Match','linear-gradient(135deg,var(--brand),var(--brand2))'],['blush','Blush Pink','#f5b7c8'],['lavender','Lavender','#cdb8ff'],['sage','Soft Sage','#9fc8a9'],['sky','Sky Blue','#9ed8f5'],['lemon','Lemon Yellow','#f1d36b'],['mocha','Mocha Brown','#b8865b'],['ink','Ink Gray','#4b4b5f'],['custom','My Own Color','var(--cork-border)']];
const boardChoicesPatch=[['natural','Natural Brown','#d6a777'],['light','Light Brown','#e4c79c'],['dark','Warm Brown','#b6844f'],['white','Soft White','#faf8f1'],['black','Chalkboard Black','#23232c'],['theme','Theme Soft Panel','linear-gradient(135deg,var(--surface2),var(--brand3))'],['custom','My Own Color','var(--cork-bg)']];
corkSettingsHtml=function(){const c=state.corkSettings||{};const borderVal=c.borderColor||'theme';const boardVal=c.boardColor||'natural';const design=c.borderDesign||'none';return `<p class="tiny">Design the cork board separately from the rest of the workspace. Changes preview right away.</p><label class="setting-row"><input type="checkbox" id="corkFreeMove" ${c.freeMove?'checked':''}> Let me move, overlap, and rotate pins anywhere on the board.</label><label>Border Design</label><select id="corkDesign"><option value="none" ${design==='none'?'selected':''}>No Decoration</option><option value="simple" ${design==='simple'?'selected':''}>Simple Clean</option><option value="floral" ${design==='floral'?'selected':''}>Soft Floral</option><option value="botanical" ${design==='botanical'?'selected':''}>Simple Botanical</option><option value="stars" ${design==='stars'?'selected':''}>Tiny Stars</option><option value="scallop" ${design==='scallop'?'selected':''}>Scalloped / Dashed</option></select><label>Border Color</label>${colorChoiceGrid('corkBorderRadio',borderChoicesPatch,borderVal)}<div class="cork-custom-row"><div><label>Custom Border Color</label><input type="color" id="corkCustomBorder" value="${esc(c.customBorder||'#f5b7c8')}"></div><div id="corkBorderPreview" class="cork-custom-preview" style="background:${esc(c.customBorder||'#f5b7c8')}">Selected Border Color</div></div><label>Main Board Color</label>${colorChoiceGrid('corkBoardRadio',boardChoicesPatch,boardVal)}<div class="cork-custom-row"><div><label>Custom Board Color</label><input type="color" id="corkCustomBoard" value="${esc(c.customBoard||'#d6a777')}"></div><div id="corkBoardPreview" class="cork-custom-preview" style="background:${esc(c.customBoard||'#d6a777')}">Selected Board Color</div></div><div class="formrow two"><div><label>Cork Board Handwriting Font</label><select id="corkFont">${corkFontOptions.map(f=>`<option value="${f[0]}" ${c.font===f[0]?'selected':''}>${f[1]}</option>`).join('')}</select></div><div><label>Font Sync</label><label class="setting-row"><input type="checkbox" id="corkMatchFont" ${c.matchWorkspaceFont?'checked':''}> Use workspace font instead of handwriting.</label></div></div><label class="setting-row"><input type="checkbox" id="corkMatchText" ${c.matchThemeText!==false?'checked':''}> Make board text match the workspace theme.</label><div class="tiny">Tip: when free move is on, drag a pin to move it. Use the pin’s ⋯ menu to rotate, edit, archive, download, or delete it.</div><div class="actions"><button data-action="saveCorkSettings">Save Cork Board Settings</button><button class="secondary" data-action="resetPinLayout">Reset Pin Layout</button></div>`;};
applyCorkSettingsFromInputs=function(){state.corkSettings=state.corkSettings||{};state.corkSettings.freeMove=!!document.getElementById('corkFreeMove')?.checked;state.corkSettings.borderDesign=val('corkDesign')||'none';state.corkSettings.borderColor=document.querySelector('input[name="corkBorderRadio"]:checked')?.value||'theme';state.corkSettings.customBorder=val('corkCustomBorder')||'#f5b7c8';state.corkSettings.boardColor=document.querySelector('input[name="corkBoardRadio"]:checked')?.value||'natural';state.corkSettings.customBoard=val('corkCustomBoard')||'#d6a777';state.corkSettings.font=val('corkFont')||'comic';state.corkSettings.matchWorkspaceFont=!!document.getElementById('corkMatchFont')?.checked;state.corkSettings.matchThemeText=!!document.getElementById('corkMatchText')?.checked;};

plannerPage=function(){const defs=[['board',card('planner','board','🗓️ Weekly Board',weeklyBoard(),{size:'lg'})],['shift',card('planner','shift','🚨 Schedule Shifter',`<p class="tiny">Use this when an assembly, fire drill, testing, or surprise event pushes the day back.</p><div class="formrow four"><div><label>Day</label><select id="shiftDay">${days().map(d=>`<option>${d}</option>`).join('')}</select></div><div><label>Shift Entries After</label><input id="shiftAfter" placeholder="10:00 AM"></div><div><label>Minutes</label><input id="shiftMin" type="number" value="15"></div><div><label>Direction</label><select id="shiftDir"><option value="1">Later</option><option value="-1">Earlier</option></select></div></div><div class="actions"><button data-action="shiftSchedule">Shift Schedule</button></div>`)] ];return `<div class="planner-actions-wide"><button data-action="openWeeklyModal">➕ Add Weekly Block</button><button class="secondary" data-action="printWeeklyPlan">Print / Save as PDF</button><button class="secondary" data-action="downloadWeeklyCsv">Download CSV</button></div>`+renderCards('planner',defs,'grid');};
monthlyPage=function(){return `<div class="plain-block"><div class="monthly-toolbar-clean"><button data-action="openMonthlyModal">➕ Add Monthly Block</button><button class="secondary" data-action="printMonthlyPlan">Print / Save as PDF</button><button class="secondary" data-action="downloadMonthlyCsv">Download CSV</button></div></div>${renderCards('monthly',[["month",card('monthly','month','🗓️ Monthly Plan',monthlyCalendarHtml(),{size:'lg',controls:false})]],'grid')}`;};
function printSimpleWindow(title,bodyHtml){const w=window.open('','_blank');if(!w){toast('Please allow pop-ups to print or save as PDF.');return;}w.document.write(`<!doctype html><html><head><title>${esc(title)}</title><style>@page{margin:.5in}body{font-family:Arial,sans-serif;color:#111}h1{text-align:center}table{width:100%;border-collapse:collapse}th,td{border:1px solid #333;padding:8px;text-align:left;vertical-align:top}th{background:#f2f2f2}.day-block{break-inside:avoid;margin-bottom:14px}</style></head><body>${bodyHtml}</body></html>`);w.document.close();setTimeout(()=>w.print(),250);}
function printWeeklyPlan(){const byDay=days().map(d=>[d,state.weekly.filter(w=>w.day===d).sort((a,b)=>parseTime(a.time)-parseTime(b.time))]);printSimpleWindow('SOZY Weekly Plan',`<h1>SOZY Workspace Weekly Plan</h1><p>Printed ${new Date().toLocaleString()}</p>${byDay.map(([d,rows])=>`<div class="day-block"><h2>${d}</h2><table><thead><tr><th>Time</th><th>Subject</th><th>Title</th><th>Notes</th></tr></thead><tbody>${rows.map(w=>`<tr><td>${esc(w.time)}</td><td>${esc(w.subject)}</td><td>${esc(w.title)}</td><td>${esc(w.note||'')}</td></tr>`).join('')||'<tr><td colspan="4">No blocks saved.</td></tr>'}</tbody></table></div>`).join('')}`);}
function printMonthlyPlan(){const key=state.monthlyView||new Date().toISOString().slice(0,7);const [y,m]=key.split('-').map(Number);const monthName=new Date(y,m-1,1).toLocaleString([], {month:'long',year:'numeric'});const rows=(state.monthly||[]).filter(x=>(x.date||'').startsWith(key)).sort((a,b)=>(a.date+a.time).localeCompare(b.date+b.time));printSimpleWindow('SOZY Monthly Plan',`<h1>SOZY Workspace Monthly Plan — ${esc(monthName)}</h1><p>Synced With Weekly Planner • Printed ${new Date().toLocaleString()}</p><table><thead><tr><th>Date</th><th>Time</th><th>Subject</th><th>Title</th><th>Notes</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.date)}</td><td>${esc(x.time||'')}</td><td>${esc(x.subject)}</td><td>${esc(x.title)}</td><td>${esc(x.note||'')}</td></tr>`).join('')||'<tr><td colspan="5">No monthly blocks saved.</td></tr>'}</tbody></table>`);}

classroomMapHtml=function(){const m=state.classroomMap||{};const assigned=new Set((m.items||[]).flatMap(i=>mapAssignedIds(i)));const unassigned=activeStudents().filter(s=>!assigned.has(s.id));const h=Math.max(520,Number(m.height)||620);return `<div class="map-top-grid"><div class="plain-block"><h3 class="compact-title">Add Furniture</h3><div class="actions"><button class="secondary" data-action="addMapDesk">+ Desk</button><button class="secondary" data-action="addMapTable">+ Table</button><button class="secondary" data-action="addMapDoor">+ Door</button><button class="secondary" data-action="addMapWindow">+ Window</button></div></div><aside class="plain-block map-side"><div class="map-options-title">Map Options</div><div class="actions"><button data-action="saveMapSettings">Save Settings</button><button class="secondary" data-action="printMap">Print / Save as PDF</button></div><p class="print-map-note">Unassigned students scroll here so the map stays easy to use.</p><b>Unassigned Students</b><div class="unassigned-scroll">${unassigned.map(s=>`<span class="student-chip" draggable="true" data-student-chip="${s.id}">${esc(s.name)}</span>`).join('')||'<span class="tiny">Every active student is assigned, or no students are listed yet.</span>'}</div></aside></div><div class="map-workspace"><div class="classroom-board" data-classroom-board style="height:${h}px">${(m.items||[]).map(mapItemHtml).join('')}<button class="small secondary clear-map-btn" data-action="clearMap">Clear Map</button></div></div>`;};
function printMap(){const m=state.classroomMap||{};const rows=(m.items||[]).map(it=>{const names=mapAssignedIds(it).map(id=>(state.students.find(s=>s.id===id)||{}).name).filter(Boolean).join(', ')||'No Students Assigned';return `<tr><td>${esc(it.label||it.type)}</td><td>${esc(it.type)}</td><td>${esc(names)}</td></tr>`}).join('')||'<tr><td colspan="3">No furniture saved.</td></tr>';printSimpleWindow('SOZY Classroom Map',`<h1>SOZY Workspace Classroom Map</h1><p>Printed ${new Date().toLocaleString()}</p><table><thead><tr><th>Furniture</th><th>Type</th><th>Student(s)</th></tr></thead><tbody>${rows}</tbody></table>`);}
const addMapItemBeforeFullPatch=addMapItem;
addMapItem=function(type){if(type==='door'||type==='window'){const t=type==='door'?'Door':'Window';state.classroomMap.items.push({id:uid('map'),type,label:t,x:20,y:type==='door'?20:90,w:type==='door'?56:90,h:32,studentIds:[]});save(t+' added.');return;}addMapItemBeforeFullPatch(type);};
const mapItemHtmlBeforeFullPatch=mapItemHtml;
mapItemHtml=function(it){if(it.type==='door'||it.type==='window'){const x=Math.max(0,Number(it.x)||0),y=Math.max(0,Number(it.y)||0),w=Math.max(40,Number(it.w)||70),h=Math.max(24,Number(it.h)||28);return `<div class="map-item ${it.type}" draggable="true" data-map-id="${it.id}" style="left:${x}px;top:${y}px;width:${w}px;height:${h}px;min-height:24px;min-width:44px;text-align:center;padding:4px"><button class="map-menu-btn" title="Furniture Options" aria-label="Furniture Options">⋯</button><div class="map-menu-pop"><button class="danger" data-action="deleteMapItem" data-id="${it.id}">Delete</button></div><b>${esc(it.label||it.type)}</b><span class="resize-corner" data-resize-map="${it.id}"></span></div>`;}return mapItemHtmlBeforeFullPatch(it);};

// Gallery dedupe + visual document cards.
galleryUploadHtml=function(){return `<div class="gallery-hero"><div><h3>🖼️ Gallery</h3><p>Your local document library for files attached across SOZY Workspace.</p></div><label class="file-button big-file">+ Upload General Files<input type="file" multiple data-attach-area="general" data-attach-id="" data-attach-label="Gallery Upload"></label></div>`;};
galleryListHtml=function(){const q=(state.gallerySearch||'').toLowerCase().trim();const filter=state.galleryFilter||'all';let docs=[...(state.gallery||[])];const seen=new Set();docs=docs.filter(d=>{const key=[d.name||'',d.size||'',d.area||'',d.itemId||'',d.dataUrl||''].join('|');if(seen.has(key))return false;seen.add(key);return true;});if(filter!=='all')docs=docs.filter(d=>d.area===filter);if(q)docs=docs.filter(d=>[d.name,d.area,d.label,d.note,areaName(d.area),linkedItemLabel(d.area,d.itemId)].join(' ').toLowerCase().includes(q));docs.sort((a,b)=>new Date(b.updatedAt||b.createdAt||0)-new Date(a.updatedAt||a.createdAt||0));const opts=['all','general','weekly','lessons','students','assignments','meetings','todos','standards'];return `<div class="filterbar"><div><label>Search Gallery</label><input id="gallerySearchInput" value="${esc(state.gallerySearch)}" placeholder="Search file name, page, lesson, student, task..."></div><div><label>Filter</label><select id="galleryFilter">${opts.map(o=>`<option value="${o}" ${filter===o?'selected':''}>${o==='all'?'All Files':areaName(o)}</option>`).join('')}</select></div><div><label>Total</label><div class="pill">${docs.length} File${docs.length===1?'':'s'}</div></div><div><label>Tip</label><div class="tiny">Open files, jump back to where they came from, or delete files here.</div></div></div><div class="gallery-grid">${docs.map(galleryDocHtml).join('')||empty('No Files In Gallery Yet.')}</div>`;};
galleryDocHtml=function(d){const isImg=(d.type||'').startsWith('image/');return `<div class="gallery-doc"><div class="gallery-thumb">${isImg?`<img src="${d.dataUrl}" alt="${esc(d.name)}">`:`<span>${docIcon(d.type,d.name)}</span>`}</div><div class="item-title">${esc(d.name)}</div><span class="gallery-meta-chip">${areaName(d.area)}</span><div class="item-meta">${d.itemId?esc(d.label||linkedItemLabel(d.area,d.itemId))+' • ':''}${docSize(d.size)} • Added ${fmt(d.createdAt)}</div><div class="actions"><a class="buttonlike small" href="${d.dataUrl}" download="${esc(d.name)}">Open</a>${d.area&&d.area!=='general'?`<button class="small secondary" data-gopage="${areaToPage(d.area)}" data-gocard="${areaToCard(d.area)}">Go</button>`:''}<button class="small danger" data-action="deleteGalleryDoc" data-id="${d.id}">Delete</button></div></div>`;};

const handleActionBeforeFullPatch=handleAction;
handleAction=function(action,el){
 if(action==='openStudentModal'){state.studentModalOpen=true;renderAll();return;}
 if(action==='closeStudentModal'){state.studentModalOpen=false;renderAll();return;}
 if(action==='saveStudentFromModal'){addStudent();state.studentModalOpen=false;return;}
 if(action==='toggleStudentArchives'){state.studentViewArchived=!state.studentViewArchived;renderAll();return;}
 if(action==='openAssignmentModal'){state.assignmentModalOpen=true;renderAll();return;}
 if(action==='closeAssignmentModal'){state.assignmentModalOpen=false;renderAll();return;}
 if(action==='saveAssignmentFromModal'){addAssignment();state.assignmentModalOpen=false;return;}
 if(action==='toggleAssignmentArchives'){state.assignmentViewArchived=!state.assignmentViewArchived;renderAll();return;}
 if(action==='downloadAssignmentsCsv'){downloadAssignmentsCsv();return;}
 if(action==='toggleMeetingArchives'){state.meetingViewArchived=!state.meetingViewArchived;renderAll();return;}
 if(action==='archiveMeeting'){const m=state.meetings.find(x=>x.id===el.dataset.id);if(m){m.archived=!m.archived;m.updatedAt=nowIso();save(m.archived?'Meeting Note Archived.':'Meeting Note Restored.');}return;}
 if(action==='printWeeklyPlan'){printWeeklyPlan();return;}
 if(action==='printMonthlyPlan'){printMonthlyPlan();return;}
 if(action==='printMap'){printMap();return;}
 if(action==='addMapDoor'){addMapItem('door');return;}
 if(action==='addMapWindow'){addMapItem('window');return;}
 return handleActionBeforeFullPatch(action,el);
};

// Live controls.
document.addEventListener('input',e=>{if(e.target.id==='todoFilterInput'){state.todoFilter=e.target.value;const card=document.getElementById('card-meetings-todoList');if(card)card.querySelector('.card-body').innerHTML=todoHtml();save('',false);}if(e.target.id==='corkCustomBorder'){const p=document.getElementById('corkBorderPreview');if(p)p.style.background=e.target.value;}if(e.target.id==='corkCustomBoard'){const p=document.getElementById('corkBoardPreview');if(p)p.style.background=e.target.value;}});
document.addEventListener('change',e=>{if(e.target.id==='todoOrder'){state.todoOrder=e.target.value;const card=document.getElementById('card-meetings-todoList');if(card)card.querySelector('.card-body').innerHTML=todoHtml();save('',false);}if(e.target.id==='meetingOrder'){state.meetingOrder=e.target.value;const card=document.getElementById('card-meetings-meetingForm');if(card)card.querySelector('.card-body').innerHTML=meetingHtml();save('',false);}if(e.target.matches('[data-group-name-id]')){const g=(state.groups||[]).find(x=>x.id===e.target.dataset.groupNameId);if(g){g.name=e.target.value.trim()||g.name;save('Group Name Saved.');}}if(e.target.name==='corkBorderRadio'||e.target.name==='corkBoardRadio'){document.querySelectorAll(`input[name="${e.target.name}"]`).forEach(r=>r.closest('.cork-choice')?.classList.toggle('active',r.checked));}});
document.addEventListener('click',e=>{if(e.target.id==='studentModal'){state.studentModalOpen=false;renderAll();}if(e.target.id==='assignmentModal'){state.assignmentModalOpen=false;renderAll();}const btn=e.target.closest('.map-menu-btn');if(btn){e.preventDefault();e.stopPropagation();const item=btn.closest('.map-item');document.querySelectorAll('.map-item.menu-open').forEach(x=>{if(x!==item)x.classList.remove('menu-open')});item?.classList.toggle('menu-open');return;}if(!e.target.closest('.map-item'))document.querySelectorAll('.map-item.menu-open').forEach(x=>x.classList.remove('menu-open'));});



// === SOZY Workspace layout/defaults polish patch 2026-06-06_2054-CT ===
(function(){
const sozyPolishStyle=document.createElement('style');
sozyPolishStyle.textContent=`
/* Forest/cozy defaults and cleaner menu */
.sidebar{background:var(--surface)!important;color:var(--ink)!important}.navbtn,.subnav{background:transparent!important;color:var(--ink)!important;border-color:transparent!important;min-height:42px!important;padding:8px 10px!important}.navbtn:hover,.subnav:hover,.navbtn.active,.subnav.active{background:color-mix(in srgb,var(--surface2) 76%,var(--surface))!important;border-color:var(--line)!important;color:var(--ink)!important}.brandmark{display:grid!important;place-items:center!important}.menu-bottom button{min-height:36px!important}.topbar{position:sticky!important;top:0;z-index:35}.app[data-active-page="map"] .topbar{position:relative!important}.topbar>div:first-child{text-align:center;justify-self:center;width:100%}.topbar h2,.topbar p{text-align:center}.top-actions{justify-self:end}.page .plain-block>h3,.card h3,.archive-title,.compact-title,.settings-box summary{text-align:center}.card h3{padding:0 58px;margin:2px 0 14px;line-height:1.15}.card .drag-corner+.card-tools+h3,.card .drag-corner~h3{min-height:36px;display:flex;align-items:center;justify-content:center}.card .card-body .item-head h4,.card .card-body h4{text-align:center}.actions.centered,.planner-actions-box,.student-export-block,.assignment-export-block,.gradebook-export-block,.subnote-buttons{display:flex;justify-content:center;gap:10px;flex-wrap:wrap}
/* Stand-out action buttons */
button:not(.icon-btn):not(.menu-edge):not(.menu-peek),.buttonlike{background:linear-gradient(135deg,var(--brand),var(--brand2))!important;color:white!important;border-color:color-mix(in srgb,var(--brand) 60%,var(--line))!important;box-shadow:0 10px 22px rgba(0,0,0,.12)!important}button.secondary:not(.icon-btn){background:color-mix(in srgb,var(--brand3) 34%,var(--surface))!important;color:var(--ink)!important;border-color:var(--line)!important}button.danger{background:linear-gradient(135deg,#d94c5c,#b83a49)!important;color:white!important}.wide-action{width:100%;min-height:44px}.stack-actions{display:grid;gap:8px;margin:8px 0 12px}.button-row{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:10px;align-items:center}.button-row button{width:100%}.box-count{margin-top:12px;color:var(--muted);font-weight:900;font-size:12px;text-align:left}.subexport-wide button{width:100%;max-width:760px;min-height:48px;margin:0 auto;display:block}.layout-panel select{pointer-events:auto!important}
/* Weekly and monthly planners */
.planner-actions-box,.monthly-toolbar-clean{border:1px solid var(--line);border-radius:20px;background:var(--surface);padding:12px;margin-bottom:14px;box-shadow:var(--shadow);display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:10px}.planner-actions-box button,.monthly-toolbar-clean button{width:100%}.schedule-board{display:grid!important;grid-template-columns:repeat(5,minmax(220px,1fr))!important;gap:12px;overflow:auto;padding-bottom:8px}.daycol{min-width:220px}.schedule-shifter{width:100%}.month-title-block{text-align:center}.month-title-block b{font-size:28px}.month-sync-badge{display:inline-block;margin-top:6px;padding:6px 14px;border-radius:999px;background:color-mix(in srgb,var(--warn) 26%,var(--surface));border:1px solid color-mix(in srgb,var(--warn) 40%,var(--line));font-weight:1000;color:var(--ink)}.month-cell.past-fill{background:color-mix(in srgb,#000 16%,var(--surface2))!important}.month-cell.past-diagonal{background-image:linear-gradient(135deg,transparent calc(50% - 1px),rgba(0,0,0,.32) calc(50% - 1px),rgba(0,0,0,.32) calc(50% + 1px),transparent calc(50% + 1px))!important}.month-past-options{margin-top:12px;border:1px solid var(--line);border-radius:16px;padding:12px;background:var(--surface);display:flex;gap:10px;align-items:center;justify-content:center;flex-wrap:wrap}.month-past-options label{display:inline-flex;align-items:center;gap:6px;font-weight:900}
/* My Students highlighting */
.item.standing-green,.grade-table .standing-green{background:color-mix(in srgb,#3b9b76 22%,var(--surface))!important;border-color:color-mix(in srgb,#3b9b76 45%,var(--line))!important}.item.standing-yellow,.grade-table .standing-yellow{background:color-mix(in srgb,#f3ce53 28%,var(--surface))!important;border-color:color-mix(in srgb,#d7a928 45%,var(--line))!important}.item.standing-red,.grade-table .standing-red{background:color-mix(in srgb,#d94c5c 22%,var(--surface))!important;border-color:color-mix(in srgb,#d94c5c 45%,var(--line))!important}.score-standing-green{background:color-mix(in srgb,#3b9b76 22%,var(--surface))!important}.score-standing-yellow{background:color-mix(in srgb,#f3ce53 30%,var(--surface))!important}.score-standing-red{background:color-mix(in srgb,#d94c5c 24%,var(--surface))!important}.student-export-block,.assignment-export-block,.gradebook-export-block{display:grid;grid-template-columns:1fr;gap:8px;margin-top:14px}.grade-table td,.grade-table th{text-align:center!important}.grade-table input{text-align:center}
/* Meetings, tasks, routines, supplies */
.meet-toolbar,.todo-toolbar,.supply-toolbar,.standard-list-toolbar,.lesson-list-toolbar{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px;align-items:center;margin:8px 0 12px}.meet-toolbar button,.todo-toolbar button,.supply-toolbar button,.standard-list-toolbar button,.lesson-list-toolbar button{width:100%}.todo-card.high{background:color-mix(in srgb,#d94c5c 22%,var(--surface))!important;border-color:color-mix(in srgb,#d94c5c 50%,var(--line))!important}.todo-card.medium{background:color-mix(in srgb,#f3ce53 30%,var(--surface))!important;border-color:color-mix(in srgb,#d7a928 45%,var(--line))!important}.todo-card.low{background:color-mix(in srgb,#3b9b76 22%,var(--surface))!important;border-color:color-mix(in srgb,#3b9b76 45%,var(--line))!important}.todo-actions,.routine-actions,.supply-actions{display:flex;justify-content:flex-end;gap:8px;flex-wrap:wrap}.routine-row{cursor:grab}.routine-row.dragging{opacity:.45}.routine-row .routine-number{font-weight:1000;color:var(--brand);min-width:28px;display:inline-flex}.routine-style-menu{position:relative;display:flex;justify-content:flex-end}.routine-style-menu select{max-width:220px}.supply-card.low{background:color-mix(in srgb,#d94c5c 20%,var(--surface))!important;border-color:color-mix(in srgb,#d94c5c 48%,var(--line))!important}.supply-card.ok{background:color-mix(in srgb,#3b9b76 18%,var(--surface))!important;border-color:color-mix(in srgb,#3b9b76 42%,var(--line))!important}
/* Classroom map */
.map-top-grid{display:grid!important;grid-template-columns:minmax(220px,320px) 1fr minmax(220px,300px)!important;gap:14px!important;align-items:start!important;margin-bottom:14px}.map-top-grid .plain-block{margin:0!important}.furniture-buttons{display:grid;grid-template-columns:1fr;gap:8px}.map-workspace{display:block!important}.classroom-board{width:100%!important;min-height:640px!important;height:650px;resize:both;overflow:auto!important;max-width:100%;border-width:3px}.map-item{display:grid;place-items:center;text-align:center;overflow:visible}.map-item .assigned{width:100%;text-align:center!important;font-size:12px;line-height:1.15;overflow-wrap:anywhere;word-break:break-word}.map-item b{text-align:center!important}.map-menu-pop{z-index:9999!important;right:auto!important;left:calc(100% + 6px)!important;top:0!important}.unassigned-scroll{max-height:240px;overflow:auto}.map-options-title{text-align:center;font-weight:1000;margin-bottom:8px}.clear-map-btn{position:absolute!important;left:14px!important;bottom:14px!important;z-index:20}
/* Cork board settings colors */
.cork-color-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:10px}.cork-choice{display:grid!important;grid-template-columns:46px 1fr;gap:10px;align-items:center!important}.cork-choice .swatch-box{width:46px;height:34px;border-radius:12px;border:2px solid rgba(0,0,0,.18);box-shadow:inset 0 0 0 2px rgba(255,255,255,.32)}.color-preview-bar{height:46px;border-radius:14px;border:2px solid var(--line);display:grid;place-items:center;font-weight:1000;color:var(--ink);text-shadow:0 1px 1px rgba(255,255,255,.35)}.dash-cork.has-none{border-image:none!important;box-shadow:var(--shadow)!important}.dash-cork.has-floral{border-image:linear-gradient(90deg,#f7a6bd,#ffd6a5,#b8e0c8,#cdb4db,#f7a6bd) 1!important}.dash-cork.has-ribbon{border-style:double!important}.dash-cork.has-stars{box-shadow:0 0 0 6px color-mix(in srgb,var(--cork-border) 34%,transparent),0 0 0 12px color-mix(in srgb,var(--brand3) 18%,transparent),var(--shadow)!important}.dash-cork.has-classic{border-style:solid!important}.cork-toolbar{display:grid!important;grid-template-columns:repeat(3,minmax(160px,1fr))!important;gap:12px!important;margin-bottom:12px}.cork-toolbar button{width:100%}
@media(max-width:1100px){.map-top-grid{grid-template-columns:1fr!important}.schedule-board{grid-template-columns:repeat(5,minmax(190px,1fr))!important}.cork-toolbar{grid-template-columns:1fr!important}}
`;
document.head.appendChild(sozyPolishStyle);

function pctLevelClass(avg){ if(avg==null || isNaN(avg)) return ''; avg=Number(avg); if(avg>=50)return 'standing-green'; if(avg>=26)return 'standing-yellow'; return 'standing-red'; }
function cellLevelClass(score,points,missing,excused){ if(excused)return ''; if(missing)return 'score-standing-red'; const p=Number(points)||0; if(!p||score===''||score==null||isNaN(Number(score)))return ''; const pct=Number(score)/p*100; if(pct>=50)return 'score-standing-green'; if(pct>=26)return 'score-standing-yellow'; return 'score-standing-red'; }
function defaultMenuOrderSozy(){return ['dashboard','grades','planner','monthly','lessons','meetings','standards','tools'].filter(id=>topMenuIds.includes(id));}
const __normalizePrev2054=normalize;
normalize=function(){__normalizePrev2054(); state.theme=state.theme||'forest'; state.layout=state.layout||{}; state.layout.menuSide=state.layout.menuSide||'left'; if(!state.layout.defaultOrder2054){state.layout.menuOrder=defaultMenuOrderSozy().concat(topMenuIds.filter(id=>!defaultMenuOrderSozy().includes(id)));state.layout.defaultOrder2054=true;} state.layout.sizes=state.layout.sizes||{}; state.layout.sizes.planner=state.layout.sizes.planner||{}; if(!state.layout.sizes.planner.shift)state.layout.sizes.planner.shift='lg'; state.monthlyPastStyle=state.monthlyPastStyle||'fill'; state.routineListStyle=state.routineListStyle||'check'; state.supplyFilter=state.supplyFilter||'all'; state.supplyOrder=state.supplyOrder||'status'; state.todoFilter=state.todoFilter||''; state.todoOrder=state.todoOrder||'priority'; state.meetingFilter=state.meetingFilter||''; state.meetingOrder=state.meetingOrder||'received'; state.standardFilter=state.standardFilter||'all'; state.standardOrder=state.standardOrder||'updated'; state.corkSettings=state.corkSettings||{}; if(!state.corkSettings.defaultNoDecoration2054){if(!state.corkSettings.borderDesign||state.corkSettings.borderDesign==='floral')state.corkSettings.borderDesign='none';state.corkSettings.defaultNoDecoration2054=true;} };
const __applyThemePrev2054=applyTheme;
applyTheme=function(){__applyThemePrev2054(); const app=document.getElementById('app'); if(app){app.classList.toggle('menu-right',state.layout?.menuSide==='right'); app.dataset.activePage=state.activePage||'dashboard';} const edge=document.getElementById('menuEdge'); if(edge){edge.textContent=state.layout?.menuSide==='right'?'>':'<';} const peek=document.getElementById('menuPeek'); if(peek){peek.textContent=state.layout?.menuSide==='right'?'<':'>';}};
const __renderAllPrev2054=renderAll;
renderAll=function(){__renderAllPrev2054(); const app=document.getElementById('app'); if(app){app.classList.toggle('menu-right',state.layout?.menuSide==='right'); app.dataset.activePage=state.activePage||'dashboard';} document.body.classList.toggle('map-page',state.activePage==='map');};

pageSettingsPanel=function(page){const isDash=page==='dashboard';return `<div class="layout-panel"><div class="item-head"><div><b>Layout Settings For This Page</b><div class="tiny">Use this to reset the layout or change the dashboard look.</div></div><button class="icon-btn" data-action="pageSettings">✕</button></div>${isDash?`<label>Dashboard Look</label><select id="dashboardStyle"><option value="soft" ${state.layout.dashboardStyle==='soft'?'selected':''}>Cute Color Boxes</option><option value="cork" ${state.layout.dashboardStyle==='cork'?'selected':''}>Cork Board</option><option value="data" ${state.layout.dashboardStyle==='data'?'selected':''}>Professional Data Dashboard</option></select><div class="archive-box"><b>Removed Dashboard Boxes</b>${state.layout.dashboardRemoved.length?state.layout.dashboardRemoved.map(id=>`<div class="item"><span>${esc((dashboardCards.find(c=>c[0]===id)||[])[1]||id)}</span><div class="actions"><button class="small secondary" data-action="restoreDashCard" data-card="${id}">Add Back</button></div></div>`).join(''):empty('Nothing Removed. Dashboard boxes stay visible unless you remove them here.')}</div>`:''}<div class="actions"><button class="secondary" data-action="resetPageLayout" data-page="${page}">Reset This Page Layout</button></div></div>`;};

plannerPage=function(){const defs=[['board',card('planner','board','🗓️ Weekly Board',weeklyBoard(),{size:'lg'})],['shift',card('planner','shift','🚨 Schedule Shifter',`<div class="schedule-shifter"><p class="tiny">Use this when an assembly, fire drill, testing, or surprise event pushes the day back.</p><div class="formrow four"><div><label>Day</label><select id="shiftDay">${days().map(d=>`<option>${d}</option>`).join('')}</select></div><div><label>Shift Entries After</label><input id="shiftAfter" placeholder="10:00 AM"></div><div><label>Minutes</label><input id="shiftMin" type="number" value="15"></div><div><label>Direction</label><select id="shiftDir"><option value="1">Later</option><option value="-1">Earlier</option></select></div></div><div class="actions centered"><button data-action="shiftSchedule">Shift Schedule</button></div></div>`,{size:'lg'})]];return `<div class="planner-actions-box"><button data-action="openWeeklyModal">➕ Add Weekly Block</button><button data-action="printWeeklyPlan">Print / Save as PDF</button><button class="secondary" data-action="downloadWeeklyCsv">Download CSV</button></div>`+renderCards('planner',defs,'grid');};

const __lessonListPrev2054=lessonList;
lessonList=function(){let lessons=state.lessons.filter(l=>!l.archived); const filter=state.lessonFilter||'all'; if(filter==='ready')lessons=lessons.filter(l=>l.subReady); else if(filter==='prep')lessons=lessons.filter(l=>!l.subReady); else if(filter!=='all')lessons=lessons.filter(l=>(l.subject||'').toLowerCase()===filter.toLowerCase()); const sort=state.lessonSort||'updated'; lessons=[...lessons].sort((a,b)=>{if(sort==='title')return (a.title||'').localeCompare(b.title||''); if(sort==='subject')return (a.subject||'').localeCompare(b.subject||'')||(a.title||'').localeCompare(b.title||''); if(sort==='status')return Number(b.subReady)-Number(a.subReady)||(a.title||'').localeCompare(b.title||''); return new Date(b.updatedAt||0)-new Date(a.updatedAt||0);}); const subjects=[...new Set(state.lessons.filter(l=>!l.archived).map(l=>l.subject).filter(Boolean))].sort(); return `<div class="lesson-list-toolbar"><button data-action="openLessonModal">➕ Add Lesson Plan</button><select id="savedLessonFilter"><option value="all" ${filter==='all'?'selected':''}>All Lessons</option><option value="ready" ${filter==='ready'?'selected':''}>Sub-Ready Only</option><option value="prep" ${filter==='prep'?'selected':''}>Needs Prep Only</option>${subjects.map(s=>`<option value="${esc(s)}" ${filter===s?'selected':''}>${esc(s)}</option>`).join('')}</select><select id="savedLessonSort"><option value="updated" ${sort==='updated'?'selected':''}>Newest Edited First</option><option value="title" ${sort==='title'?'selected':''}>A To Z Title</option><option value="subject" ${sort==='subject'?'selected':''}>Subject</option><option value="status" ${sort==='status'?'selected':''}>Sub-Ready First</option></select></div>`+(lessons.map(l=>state.editing.lessons[l.id]?`<div class="item" data-edit-lesson="${l.id}">${lessonForm(l)}</div>`:`<div class="item with-paperclip">${attachmentIndicator('lessons',l.id)}<div class="item-title-row"><div class="item-title">${esc(l.title)} <span class="pill ${l.subReady?'good':'warn'}">${l.subReady?'Sub-Ready':'Needs Prep'}</span></div></div><div class="item-meta">${esc(l.subject)} • ${esc(l.standard)} • Level ${esc(l.lexile||'N/A')} • Theme: ${esc(l.theme||'None')} • Last Edited ${fmt(l.updatedAt)}</div><p class="tiny">${esc(l.summary)}</p><div class="entry-actions"><button class="small secondary" data-action="editLesson" data-id="${l.id}">Edit</button><button class="small danger delete-right" data-action="deleteLesson" data-id="${l.id}">Delete</button></div></div>`).join('')||empty('No Lessons Match This Filter.'));};

function printStudents(){const rows=state.students.filter(s=>!s.archived).map(s=>`<tr><td>${esc(s.name)}</td><td>${esc(s.status||'')}</td><td>${esc(s.notes||'')}</td><td>${studentAverage(s.id)==null?'—':studentAverage(s.id)+'%'}</td></tr>`).join('')||'<tr><td colspan="4">No students saved.</td></tr>';printSimpleWindow('SOZY Student List',`<h1>SOZY Workspace Student List</h1><p>Printed ${new Date().toLocaleString()}</p><table><thead><tr><th>Student</th><th>Status</th><th>Notes</th><th>Average</th></tr></thead><tbody>${rows}</tbody></table>`);}
function printAssignments(){const rows=activeAssignments().map(a=>`<tr><td>${esc(a.title)}</td><td>${esc(a.subject)}</td><td>${esc(a.category)}</td><td>${esc(a.points)}</td><td>${esc(a.date)}</td></tr>`).join('')||'<tr><td colspan="5">No assignments saved.</td></tr>';printSimpleWindow('SOZY Assignment List',`<h1>SOZY Workspace Assignment List</h1><p>Printed ${new Date().toLocaleString()}</p><table><thead><tr><th>Assignment</th><th>Subject</th><th>Category</th><th>Points</th><th>Date</th></tr></thead><tbody>${rows}</tbody></table>`);}
function studentArchiveHtml2(){const archived=state.students.filter(s=>s.archived);return state.studentViewArchived?`<div class="archive-inline"><div class="archive-title"><b>Archived Students</b><span class="pill">${archived.length}</span></div>${archived.map(s=>`<div class="item"><div class="item-title">${esc(s.name)}</div><div class="entry-actions"><button class="small secondary" data-action="restoreStudent" data-id="${s.id}">Restore</button><button class="small danger" data-action="deleteStudent" data-id="${s.id}">Delete</button></div></div>`).join('')||empty('No Archived Students.')}</div>`:'';}
studentsHtml=function(){const list=state.students.filter(s=>!s.archived);return `<div class="stack-actions"><button class="wide-action" data-action="openStudentModal">➕ Add Student</button></div>${list.map(studentRow).join('')||empty('No Students Yet.')}<div class="student-export-block"><button class="secondary" data-action="downloadStudentsCsv">Download Student List CSV</button><button class="secondary" data-action="printStudents">Print / Save as PDF</button><button class="secondary" data-action="toggleStudentArchives">${state.studentViewArchived?'Hide Archived Students':'View Archived Students'}</button></div>${studentArchiveHtml2()}`;};
studentRow=function(s){if(state.editing.students[s.id])return `<div class="item"><div class="formrow three"><div><label>Name</label><input id="es_name_${s.id}" value="${esc(s.name)}"></div><div><label>Status</label><input id="es_status_${s.id}" value="${esc(s.status)}"></div><div><label>Notes</label><input id="es_notes_${s.id}" value="${esc(s.notes)}"></div></div><label>Last Edited</label><input type="datetime-local" id="es_time_${s.id}" value="${toLocalInput(s.updatedAt)}">${attachmentPanel('students',s.id,s.name)}<div class="actions"><button class="small good" data-action="saveStudent" data-id="${s.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="students" data-id="${s.id}">Cancel</button></div></div>`; const avg=studentAverage(s.id);return `<div class="item with-paperclip ${pctLevelClass(avg)}">${attachmentIndicator('students',s.id)}<div class="item-head"><div><div class="item-title">${esc(s.name)}</div><div class="item-meta">${esc(s.status||'Active')} • ${esc(s.notes||'No Notes')} • Last Edited ${fmt(s.updatedAt)}</div></div><span>${gradeBadge(avg)}</span></div><div class="entry-actions"><button class="small secondary" data-action="editStudent" data-id="${s.id}">Edit</button><button class="small secondary" data-action="archiveStudent" data-id="${s.id}">Archive</button><button class="small danger delete-right" data-action="deleteStudent" data-id="${s.id}">Delete</button></div></div>`;};
function assignmentArchiveHtml2(){const archived=state.assignments.filter(a=>a.archived);return state.assignmentViewArchived?`<div class="archive-inline"><div class="archive-title"><b>Archived Assignments</b><span class="pill">${archived.length}</span></div>${archived.map(a=>`<div class="item"><div class="item-title">${esc(a.title)}</div><div class="entry-actions"><button class="small secondary" data-action="restoreAssignment" data-id="${a.id}">Restore</button><button class="small danger" data-action="deleteAssignment" data-id="${a.id}">Delete</button></div></div>`).join('')||empty('No Archived Assignments.')}</div>`:'';}
assignmentsHtml=function(){return `<div class="stack-actions"><button class="wide-action" data-action="openAssignmentModal">➕ Add Assignment</button></div>${activeAssignments().map(assignmentRow).join('')||empty('No Assignments Yet.')}<div class="assignment-export-block"><button class="secondary" data-action="downloadAssignmentsCsv">Download Assignments CSV</button><button class="secondary" data-action="printAssignments">Print / Save as PDF</button><button class="secondary" data-action="toggleAssignmentArchives">${state.assignmentViewArchived?'Hide Archived Assignments':'View Archived Assignments'}</button></div>${assignmentArchiveHtml2()}`;};
gradebookHtml=function(){const st=activeStudents(), as=activeAssignments(); if(!st.length||!as.length)return empty('Add Students And Assignments First. Then The Gradebook Table Appears Here.'); return `<p class="tiny">Type scores directly in the boxes. Use M for missing and X for excused. Every score gets a timestamp when saved.</p><div class="grade-table-wrap"><table class="grade-table"><thead><tr><th>Student</th>${as.map(a=>`<th>${esc(a.title)}<div class="tiny">${esc(a.points)} Pts</div></th>`).join('')}<th>Average</th></tr></thead><tbody>${st.map(s=>`<tr class="${pctLevelClass(studentAverage(s.id))}"><td class="student-cell">${esc(s.name)}<div class="tiny">${esc(s.status||'Active')}</div></td>${as.map(a=>scoreCell(s,a)).join('')}<td>${gradeBadge(studentAverage(s.id))}</td></tr>`).join('')}</tbody></table></div><div class="gradebook-export-block"><button class="secondary" data-action="downloadGradesCsv">Download Grade Book CSV</button><button class="secondary" data-action="printGrades">Print / Save as PDF Grade Summary</button></div>`;};
scoreCell=function(s,a){const key=s.id+'_'+a.id; const sc=state.scores[key]||{}; return `<td class="${cellLevelClass(sc.score,a.points,sc.missing,sc.excused)}"><input type="text" value="${esc(sc.missing?'M':sc.excused?'X':(sc.score??''))}" data-score="${key}" data-student="${s.id}" data-assignment="${a.id}" placeholder="0-${esc(a.points)}"><div class="tiny">${sc.updatedAt?'Saved '+fmt(sc.updatedAt):'Not Entered'}</div></td>`;};
gradesPage=function(){const defs=[['gradeStats',card('grades','gradeStats','📊 Grade Dashboard',gradeDashboardHtml(),{size:'lg',controls:false})],['students',card('grades','students','👧 Students',studentsHtml(),{size:'lg'})],['assignments',card('grades','assignments','🧾 Assignments',assignmentsHtml(),{size:'lg'})],['gradebook',card('grades','gradebook','📝 Grade Book Table',gradebookHtml(),{size:'lg'})]];return renderCards('grades',defs,'grid');};

meetingHtml=function(){let notes=[...state.meetings].filter(m=>state.meetingViewArchived?!!m.archived:!m.archived); const q=(state.meetingFilter||'').toLowerCase().trim(); if(q)notes=notes.filter(m=>[m.title,m.date,m.notes].join(' ').toLowerCase().includes(q)); const order=state.meetingOrder||'received'; notes.sort((a,b)=>{if(order==='newest')return new Date(b.createdAt||b.date||0)-new Date(a.createdAt||a.date||0); if(order==='title')return (a.title||'').localeCompare(b.title||''); return new Date(a.createdAt||a.date||0)-new Date(b.createdAt||b.date||0);}); const form=state.showMeetingForm?`<div class="meet-add-panel"><div class="formrow two"><div><label>Meeting Title</label><input id="meetingTitle" placeholder="IEP Meeting, Grade-Level Planning..."></div><div><label>Date</label><input id="meetingDate" type="date" value="${new Date().toISOString().slice(0,10)}"></div></div><label>Notes</label><textarea id="meetingNotes" placeholder="What Was Decided? What Needs Follow-Up?"></textarea><div class="actions"><button data-action="addMeeting">Save Meeting Note</button><button class="secondary" data-action="toggleMeetingForm">Cancel</button></div></div>`:'';return `<div class="meet-toolbar"><button data-action="toggleMeetingForm">➕ Add Meeting Note</button><button class="secondary" data-action="toggleMeetingArchives">${state.meetingViewArchived?'Hide Archived Notes':'View Archived Notes'}</button></div>${form}<h4>Meeting Notes History</h4><div class="meeting-controls"><input id="meetingFilterInput" value="${esc(state.meetingFilter||'')}" placeholder="Filter Meeting Notes..."><select id="meetingOrder"><option value="received" ${order==='received'?'selected':''}>Oldest Received First</option><option value="newest" ${order==='newest'?'selected':''}>Newest First</option><option value="title" ${order==='title'?'selected':''}>Title A To Z</option></select></div><div class="meeting-list">${notes.map(meetingRow).join('')||empty(state.meetingViewArchived?'No Archived Notes.':'No Meeting Notes Yet.')}</div><div class="box-count">${notes.length} Note${notes.length===1?'':'s'}</div>`;};
todoHtml=function(){const show=!!state.todoViewArchives; let tasks=[...state.todos].filter(t=>show?!!t.archived:!t.archived); const q=(state.todoFilter||'').toLowerCase().trim(); if(q)tasks=tasks.filter(t=>[t.text,t.priority].join(' ').toLowerCase().includes(q)); const ord={High:0,Medium:1,Low:2}; const sort=state.todoOrder||'priority'; tasks.sort((a,b)=>{if(sort==='newest')return new Date(b.createdAt||0)-new Date(a.createdAt||0); if(sort==='oldest')return new Date(a.createdAt||0)-new Date(b.createdAt||0); if(sort==='done')return Number(a.done)-Number(b.done)||((ord[a.priority]??9)-(ord[b.priority]??9)); return (ord[a.priority]??9)-(ord[b.priority]??9)||Number(a.done)-Number(b.done)||new Date(a.createdAt||0)-new Date(b.createdAt||0);}); return `<div class="todo-toolbar"><button data-action="openTaskModal">➕ Add Task</button><button class="secondary" data-action="toggleTodoArchives">${show?'Hide Archived Tasks':'View Archived Tasks'}</button></div><h4>My To-Do List</h4><div class="todo-controls"><input id="todoFilterInput" value="${esc(state.todoFilter||'')}" placeholder="Filter Tasks..."><select id="todoOrder"><option value="priority" ${sort==='priority'?'selected':''}>Priority</option><option value="newest" ${sort==='newest'?'selected':''}>Newest First</option><option value="oldest" ${sort==='oldest'?'selected':''}>Oldest First</option><option value="done" ${sort==='done'?'selected':''}>Open Tasks First</option></select></div><div class="todo-list">${tasks.map(todoRow).join('')||empty(show?'No Archived Tasks.':'No Tasks Yet.')}</div><div class="box-count">${tasks.length} Task${tasks.length===1?'':'s'}</div>`;};
todoRow=function(t){if(state.editing.todos[t.id])return `<div class="item"><div class="formrow three"><div><label>Task</label><input id="et_text_${t.id}" value="${esc(t.text)}"></div><div><label>Priority</label><select id="et_priority_${t.id}"><option ${t.priority==='Low'?'selected':''}>Low</option><option ${t.priority==='Medium'?'selected':''}>Medium</option><option ${t.priority==='High'?'selected':''}>High</option></select></div><div><label>Last Edited</label><input type="datetime-local" id="et_time_${t.id}" value="${toLocalInput(t.updatedAt)}"></div></div>${attachmentPanel('todos',t.id,t.text)}<div class="actions"><button class="small good" data-action="saveTodo" data-id="${t.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="todos" data-id="${t.id}">Cancel</button></div></div>`; const cls=priorityClass(t.priority);return `<div class="item with-paperclip todo-card ${cls}">${attachmentIndicator('todos',t.id)}<div class="item-head"><div><div class="item-title">${t.done?'✅':'⬜'} ${esc(t.text)}</div><div class="item-meta"><span class="priority-pill ${cls}">${esc(t.priority||'Medium')}</span> • Last Edited ${fmt(t.updatedAt)} ${t.archived?'• Archived':''}</div></div></div><div class="todo-actions"><button class="small secondary" data-action="toggleTodo" data-id="${t.id}">${t.done?'Reopen':'Done'}</button><button class="small secondary" data-action="editTodo" data-id="${t.id}">Edit</button><button class="small secondary" data-action="archiveTodo" data-id="${t.id}">${t.archived?'Restore':'Archive'}</button><button class="small danger" data-action="deleteTodo" data-id="${t.id}">Delete</button></div></div>`;};

standardList=function(){const q=(state.currentStandardSearch||'').toLowerCase().trim(); let rows=[...state.standards]; if(q)rows=rows.filter(x=>[x.skill,x.subject,x.standard,x.status,x.notes].join(' ').toLowerCase().includes(q)); const filter=state.standardFilter||'all'; if(filter==='mastered')rows=rows.filter(x=>(x.status||'').toLowerCase().includes('master')); if(filter==='practice')rows=rows.filter(x=>(x.status||'').toLowerCase().includes('practice')); const sort=state.standardOrder||'updated'; rows.sort((a,b)=>{if(sort==='skill')return (a.skill||'').localeCompare(b.skill||''); if(sort==='subject')return (a.subject||'').localeCompare(b.subject||''); if(sort==='progress')return (Number(b.progress)||0)-(Number(a.progress)||0); return new Date(b.updatedAt||0)-new Date(a.updatedAt||0);}); return `<div class="standard-list-toolbar"><button data-action="openStandardModal">➕ Add A Standard/Skill</button><select id="standardFilter"><option value="all" ${filter==='all'?'selected':''}>All Standards</option><option value="mastered" ${filter==='mastered'?'selected':''}>Mastered</option><option value="practice" ${filter==='practice'?'selected':''}>Practicing</option></select><select id="standardOrder"><option value="updated" ${sort==='updated'?'selected':''}>Newest Edited First</option><option value="skill" ${sort==='skill'?'selected':''}>Skill A To Z</option><option value="subject" ${sort==='subject'?'selected':''}>Subject</option><option value="progress" ${sort==='progress'?'selected':''}>Highest Progress</option></select></div>`+(rows.map(s=>state.editing.standards[s.id]?`<div class="item">${standardForm(s)}</div>`:`<div class="item with-paperclip">${attachmentIndicator('standards',s.id)}<div class="item-title">${esc(s.skill)}</div><div class="item-meta">${esc(s.subject)} • ${esc(s.standard)} • ${esc(s.status)} • Last Edited ${fmt(s.updatedAt)}</div><div class="progressbar"><span style="width:${Number(s.progress)||0}%"></span></div><p class="tiny">${esc(s.notes)}</p><div class="entry-actions"><button class="small secondary" data-action="editStandard" data-id="${s.id}">Edit</button><button class="small danger delete-right" data-action="deleteStandard" data-id="${s.id}">Delete</button></div></div>`).join('')||empty(q?'No Skills Match That Search.':'No Skills Yet.'));};
standardsPage=function(){const guideBox=(!state.hideStandardsGuide&&!standardsGuideClosedSession)?`<div class="standard-explainer plain-block standard-guide"><button class="icon-btn guide-close" title="Close Explanation" aria-label="Close Explanation" data-action="closeStandardsGuide">×</button><p><strong>What Is This Page For?</strong> Use this to track the skill or standard itself, like “main idea,” “multiplication facts,” or “writing complete sentences.”</p><p><strong>How Is This Different From Lesson Library?</strong> Lesson Library stores the actual lesson plan. Standards / Skills tracks whether the class is learning, practicing, or mastering the skill across many lessons.</p><p class="tiny">Example: You may have 5 reading lessons in Lesson Library, but only 1 skill tracker for “finding text evidence.”</p><label class="guide-check"><input id="dontShowStandardGuide" type="checkbox"> Don't Show Me This Again</label></div>`:''; const search=`<div class="plain-block standards-search-row"><div class="searchbar"><input id="standardSearchInput" value="${esc(state.currentStandardSearch||'')}" placeholder="Search standards, skills, subjects, status, or notes..."><button class="secondary" data-action="clearStandardSearch">Clear</button></div><div class="tiny search-tip-inline">Tip: Search Results Below Are Clickable.</div><div id="standardSearchResults">${standardSearchResults()}</div></div>`; return guideBox+search+renderCards('standards',[['standardList',card('standards','standardList','📈 Our Progress',standardList(),{size:'lg',controls:false})]],'grid');};

makeGroups=function(){const names=val('studentNames').split(/\n|,/).map(x=>x.trim()).filter(Boolean); const count=Math.max(1,Number(val('groupCount')||1)); const shuffled=[...names].sort(()=>Math.random()-.5); state.groups=Array.from({length:count},(_,i)=>({id:uid('group'),name:`Group ${i+1}`,members:[]})); shuffled.forEach((n,i)=>state.groups[i%count].members.push(n)); save('Groups Made. Names Are Shown In The Groups.');};
renderGroups=function(){return (state.groups||[]).map((g,i)=>{const members=Array.isArray(g)?g:(g.members||[]); const gid=Array.isArray(g)?'':g.id; return `<div class="group-card"><label class="group-name-label">Group Name</label><input class="group-name-input" data-group-name-id="${gid}" value="${esc((g.name)||`Group ${i+1}`)}"><div class="group-members">${members.map(n=>`<div class="group-member">${esc(n)}</div>`).join('')||'<div class="tiny">No Names In This Group.</div>'}</div></div>`;}).join('')||empty('No Groups Made Yet.');};
groupsPage=function(){const defs=[['groupMaker',card('groups','groupMaker','',`<div class="split"><div><label>Student Names</label><textarea id="studentNames" placeholder="Avery, Mia, Leo, Sam">${activeStudents().map(s=>esc(s.name)).join(', ')}</textarea><p class="tiny">Tip: Names sync from My Students as a starting point, but you can edit this box before making groups.</p></div><div><label>Number Of Groups</label><input id="groupCount" type="number" value="3"><div class="actions"><button class="wide-action" data-action="makeGroups">Make Groups</button></div><div class="groups">${renderGroups()}</div></div></div>`,{size:'lg',controls:false,heading:false})]];return renderCards('groups',defs,'grid');};

routinesHtml=function(){const style=state.routineListStyle||'check';return `<div class="formrow two"><div><label>Routine Item</label><input id="routineText" placeholder="Post Visual Schedule"></div><div><label>&nbsp;</label><button data-action="addRoutine">Add Routine</button></div></div><div class="routine-style-menu"><select id="routineListStyle"><option value="check" ${style==='check'?'selected':''}>Checklist</option><option value="number" ${style==='number'?'selected':''}>Numbered List</option></select></div><div class="routine-list">${state.routines.map((r,i)=>routineRow(r,i)).join('')||empty('No Routines Yet.')}</div><div class="box-count">${state.routines.length} Routine${state.routines.length===1?'':'s'}</div>`;};
routineRow=function(r,i=0){if(state.editing.routines[r.id])return `<div class="item"><label>Routine</label><input id="erou_text_${r.id}" value="${esc(r.text)}"><label>Last Edited</label><input type="datetime-local" id="erou_time_${r.id}" value="${toLocalInput(r.updatedAt)}"><div class="actions"><button class="small good" data-action="saveRoutine" data-id="${r.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="routines" data-id="${r.id}">Cancel</button></div></div>`; const lead=(state.routineListStyle==='number')?`<span class="routine-number">${i+1}.</span>`:(r.done?'✅':'⬜'); return `<div class="item routine-row" draggable="true" data-routine-id="${r.id}"><div class="item-title">${lead} ${esc(r.text)}</div><div class="item-meta">Last Edited ${fmt(r.updatedAt)}</div><div class="routine-actions"><button class="small secondary" data-action="toggleRoutine" data-id="${r.id}">${r.done?'Uncheck':'Check'}</button><button class="small secondary" data-action="editRoutine" data-id="${r.id}">Edit</button><button class="small danger" data-action="deleteRoutine" data-id="${r.id}">Delete</button></div></div>`;};

suppliesHtml=function(){let rows=state.supplies.filter(s=>state.supplyViewArchives?!!s.archived:!s.archived); const filter=state.supplyFilter||'all'; if(filter==='low')rows=rows.filter(s=>Number(s.have)<Number(s.need)); if(filter==='ok')rows=rows.filter(s=>Number(s.have)>=Number(s.need)); const sort=state.supplyOrder||'status'; rows.sort((a,b)=>{if(sort==='name')return (a.item||'').localeCompare(b.item||''); if(sort==='have')return Number(a.have)-Number(b.have); return (Number(a.have)>=Number(a.need))-(Number(b.have)>=Number(b.need))||(a.item||'').localeCompare(b.item||'');});return `<div class="formrow four"><div><label>Item</label><input id="sItem" placeholder="Glue Sticks"></div><div><label>Have</label><input id="sHave" type="number" value="0"></div><div><label>Need</label><input id="sNeed" type="number" value="0"></div><div><label>Location</label><input id="sLocation" placeholder="Cabinet"></div></div><label>Note</label><input id="sNote" placeholder="Optional Note"><div class="supply-toolbar"><button data-action="addSupply">Add Supply</button><button class="secondary" data-action="toggleSupplyArchives">${state.supplyViewArchives?'Hide Archived Supplies':'View Archived Supplies'}</button><select id="supplyFilter"><option value="all" ${filter==='all'?'selected':''}>All Supplies</option><option value="low" ${filter==='low'?'selected':''}>Low Only</option><option value="ok" ${filter==='ok'?'selected':''}>OK Only</option></select><select id="supplyOrder"><option value="status" ${sort==='status'?'selected':''}>Low First</option><option value="name" ${sort==='name'?'selected':''}>A To Z</option><option value="have" ${sort==='have'?'selected':''}>Lowest Have First</option></select></div><div class="supply-list">${rows.map(s=>state.supplyViewArchives?`<div class="item"><div class="item-title">${esc(s.item)}</div><div class="entry-actions"><button class="small secondary" data-action="restoreSupply" data-id="${s.id}">Restore</button><button class="small danger" data-action="deleteSupply" data-id="${s.id}">Delete Forever</button></div></div>`:supplyRow(s)).join('')||empty(state.supplyViewArchives?'No Archived Supplies.':'No Active Supplies Saved.')}</div><div class="box-count">${rows.length} ${state.supplyViewArchives?'Archived ':''}Suppl${rows.length===1?'y':'ies'}</div>`;};
supplyRow=function(s){if(state.editing.supplies[s.id])return `<div class="item"><div class="formrow four"><div><label>Item</label><input id="esu_item_${s.id}" value="${esc(s.item)}"></div><div><label>Have</label><input id="esu_have_${s.id}" type="number" value="${esc(s.have)}"></div><div><label>Need</label><input id="esu_need_${s.id}" type="number" value="${esc(s.need)}"></div><div><label>Location</label><input id="esu_loc_${s.id}" value="${esc(s.location)}"></div></div><label>Note</label><input id="esu_note_${s.id}" value="${esc(s.note)}"><label>Last Edited</label><input type="datetime-local" id="esu_time_${s.id}" value="${toLocalInput(s.updatedAt)}"><div class="actions"><button class="small good" data-action="saveSupply" data-id="${s.id}">Save</button><button class="small secondary" data-action="cancelEdit" data-type="supplies" data-id="${s.id}">Cancel</button></div></div>`; const low=Number(s.have)<Number(s.need);return `<div class="item supply-card ${low?'low':'ok'}"><div class="item-head"><div><div class="item-title">${low?'⚠️ ':''}${esc(s.item)}</div><div class="item-meta">Have ${esc(s.have)} / Need ${esc(s.need)} • ${esc(s.location)} • Last Edited ${fmt(s.updatedAt)}</div><p class="tiny">${esc(s.note)}</p></div><span class="pill ${low?'warn':'good'}">${low?'Low':'OK'}</span></div><div class="supply-actions"><button class="small secondary" data-action="editSupply" data-id="${s.id}">Edit</button><button class="small secondary" data-action="archiveSupply" data-id="${s.id}">Archive</button><button class="small danger" data-action="deleteSupply" data-id="${s.id}">Delete</button></div></div>`;};

classroomMapHtml=function(){const m=state.classroomMap||{}; const assigned=new Set((m.items||[]).flatMap(i=>mapAssignedIds(i))); const unassigned=activeStudents().filter(s=>!assigned.has(s.id)); return `<div class="map-top-grid"><div class="plain-block"><h3 class="compact-title">Add Furniture</h3><div class="furniture-buttons"><button class="secondary" data-action="addMapDesk">+ Desk</button><button class="secondary" data-action="addMapTable">+ Table</button><button class="secondary" data-action="addMapDoor">+ Door</button><button class="secondary" data-action="addMapWindow">+ Window</button></div></div><div class="plain-block"><div class="map-options-title">Map Options</div><div class="button-row"><button data-action="saveMapSettings">Save Settings</button><button class="secondary" data-action="printMap">Print / Save as PDF</button></div></div><aside class="plain-block map-side"><b>Unassigned Students</b><div class="unassigned-scroll">${unassigned.map(s=>`<span class="student-chip" draggable="true" data-student-chip="${s.id}">${esc(s.name)}</span>`).join('')||'<span class="tiny">Every Active Student Is Assigned, Or No Students Are Listed Yet.</span>'}</div></aside></div><div class="map-workspace"><div class="classroom-board" data-classroom-board>${(m.items||[]).map(mapItemHtml).join('')}<button class="small secondary clear-map-btn" data-action="clearMap">Clear Map</button></div></div>`;};
mapItemHtml=function(it){const ids=mapAssignedIds(it); const names=ids.map(id=>state.students.find(s=>s.id===id)).filter(Boolean); const x=Math.max(0,Number(it.x)||0),y=Math.max(0,Number(it.y)||0),w=Math.max(it.type==='door'||it.type==='window'?44:80,Number(it.w)|| (it.type==='window'?90:it.type==='door'?56:110)),h=Math.max(it.type==='door'||it.type==='window'?24:58,Number(it.h)|| (it.type==='window'||it.type==='door'?32:80)); const emptyText=it.type==='table'?'Drop Student(s) Here':(it.type==='door'||it.type==='window'?'': 'Drop Student Here'); return `<div class="map-item ${it.type==='table'?'table':it.type==='door'?'door':it.type==='window'?'window':'desk'}" draggable="true" data-map-id="${it.id}" style="left:${x}px;top:${y}px;width:${w}px;height:${h}px"><button class="map-menu-btn" title="Furniture Options" aria-label="Furniture Options">⋯</button><div class="map-menu-pop"><button class="secondary" data-action="unassignMapItem" data-id="${it.id}">Clear</button><button class="danger" data-action="deleteMapItem" data-id="${it.id}">Delete</button></div><b>${esc(it.label||it.type)}</b><div class="assigned ${names.length?'has-names':''}">${names.length?names.map(s=>`<span class="seat-name">${esc(s.name)} <button class="mini-x" data-action="unassignMapStudent" data-id="${it.id}" data-student="${s.id}">×</button></span>`).join(''):emptyText}</div><span class="resize-corner" data-resize-map="${it.id}" title="Drag To Resize"></span></div>`;};

const borderChoices2054=[['theme','Theme Accent','var(--brand2)'],['blush','Blush Pink','#f5b7c8'],['sage','Soft Sage','#9fc49a'],['sky','Sky Blue','#8bd0ee'],['lavender','Lavender','#cdb4db'],['cocoa','Cocoa Brown','#8a5a44'],['ink','Ink Black','#23232c'],['white','Clean White','#ffffff'],['custom','Custom Color','var(--cork-border)']];
const boardChoices2054=[['natural','Natural Brown','#d6a777'],['light','Light Brown','#e6c49a'],['white','White Board','#fffdf7'],['black','Black Board','#23232c'],['sage','Sage Board','#b9d2b1'],['sky','Sky Board','#c7e7f5'],['custom','Custom Color','var(--cork-bg)']];
function choiceRadioHtml(name,current,choices,customId,customVal){return `<div class="cork-color-grid">${choices.map(c=>`<label class="cork-choice ${current===c[0]?'active':''}"><input type="radio" name="${name}" value="${c[0]}" ${current===c[0]?'checked':''}><span class="swatch-box" style="background:${c[2]}"></span><b>${c[1]}</b></label>`).join('')}</div><div class="formrow two"><div><label>Custom Color</label><input type="color" id="${customId}" value="${customVal}"></div><div><label>Selected Color</label><div class="color-preview-bar" id="${customId}Preview" style="background:${customVal}">${customVal}</div></div></div>`;}
corkSettingsHtml=function(){const c=state.corkSettings||{}; const design=c.borderDesign||'none'; return `<p class="tiny">Design your cork board. These settings only affect the dashboard cork board.</p><label class="setting-row"><input type="checkbox" id="corkFreeMove" ${c.freeMove?'checked':''}> Let Me Move, Overlap, And Rotate Pins Anywhere On The Board.</label><label>Border Design</label><select id="corkDesign"><option value="none" ${design==='none'?'selected':''}>No Decoration</option><option value="classic" ${design==='classic'?'selected':''}>Classic Border</option><option value="floral" ${design==='floral'?'selected':''}>Soft Floral</option><option value="ribbon" ${design==='ribbon'?'selected':''}>Ribbon Border</option><option value="stars" ${design==='stars'?'selected':''}>Starry Border</option></select><label>Border Color</label>${choiceRadioHtml('corkBorderRadio',c.borderColor||'theme',borderChoices2054,'corkCustomBorder',c.customBorder||'#f5b7c8')}<label>Main Board Color</label>${choiceRadioHtml('corkBoardRadio',c.boardColor||'natural',boardChoices2054,'corkCustomBoard',c.customBoard||'#d6a777')}<label>Cork Board Font</label><select id="corkFont"><option value="comic" ${(c.font||'comic')==='comic'?'selected':''}>Friendly Handwriting</option><option value="marker" ${c.font==='marker'?'selected':''}>Marker Handwriting</option><option value="bradley" ${c.font==='bradley'?'selected':''}>Soft Script</option><option value="chalk" ${c.font==='chalk'?'selected':''}>Chalk Notes</option></select><label class="setting-row"><input type="checkbox" id="corkMatchText" ${c.matchThemeText?'checked':''}> Make Board Text Match The Workspace Theme.</label><div class="actions"><button data-action="saveCorkSettings">Save Cork Board Settings</button><button class="secondary" data-action="resetPinLayout">Reset Pin Layout</button></div>`;};
const __applyThemeCork2054=applyTheme;
applyTheme=function(){__applyThemeCork2054(); const c=state.corkSettings||{}; const design=c.borderDesign||'none'; document.querySelectorAll('.dash-cork').forEach(el=>{el.classList.remove('has-none','has-classic','has-floral','has-ribbon','has-stars');el.classList.add('has-'+design);}); const bp=document.getElementById('corkCustomBorderPreview'), cp=document.getElementById('corkCustomBoardPreview'); if(bp)bp.style.background=val('corkCustomBorder')||c.customBorder||'#f5b7c8'; if(cp)cp.style.background=val('corkCustomBoard')||c.customBoard||'#d6a777';};


// Runtime safety: keep monthly sync helpers available for later patch layers.
function sozyWeekDayFromDate2054(iso){
  const d=new Date((iso||new Date().toISOString().slice(0,10))+'T12:00:00');
  return ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][d.getDay()];
}
function monthCombinedItems(iso){
  const dow=sozyWeekDayFromDate2054(iso);
  const monthItems=(state.monthly||[]).filter(x=>x.date===iso).map(x=>({...x,_source:'monthly',_sourceId:x.id,_sortTime:x.time||'99:99'}));
  const weekItems=(state.weekly||[]).filter(x=>x.day===dow).map(x=>({...x,date:iso,_source:'weekly',_sourceId:x.id,_sortTime:x.time||'99:99',title:x.title||x.subject||'Weekly Block'}));
  return monthItems.concat(weekItems).sort((a,b)=>parseTime(a._sortTime)-parseTime(b._sortTime)||(a.title||'').localeCompare(b.title||''));
}

monthlyPage=function(){return `<div class="monthly-toolbar-clean"><button data-action="openMonthlyModal">➕ Add Monthly Block</button><button data-action="printMonthlyPlan">Print / Save as PDF</button><button class="secondary" data-action="downloadMonthlyCsv">Download CSV</button></div>${renderCards('monthly',[["month",card('monthly','month','🗓️ Monthly Plan',monthlyCalendarHtml(),{size:'lg',controls:false})]],'grid')}`;};
monthlyCalendarHtml=function(){const key=state.monthlyView||new Date().toISOString().slice(0,7); const today=new Date().toISOString().slice(0,10); return `<div class="month-header"><button class="secondary small" data-action="prevMonth">‹ Previous</button><div class="month-title-block"><b>${monthTitle(key)}</b><div class="month-sync-badge">Synced With Weekly Planner</div></div><button class="secondary small" data-action="nextMonth">Next ›</button></div><div class="month-grid">${['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].map(d=>`<div class="month-day-name">${d}</div>`).join('')}${monthDays(key).map(d=>{const iso=d.toISOString().slice(0,10); const past=iso<today; const cls=past?(state.monthlyPastStyle==='diagonal'?'past-diagonal':'past-fill'):''; const items=monthCombinedItems(iso); return `<div class="month-cell ${monthKey(iso)!==key?'other':''} ${iso===today?'today':''} ${cls}"><div class="month-date">${d.getDate()}</div>${items.map(monthlyEntryHtml).join('')}</div>`;}).join('')}</div><div class="month-past-options"><b>Past Dates:</b><label><input type="radio" name="monthlyPastStyle" value="fill" ${state.monthlyPastStyle==='fill'?'checked':''}> Dark Fill</label><label><input type="radio" name="monthlyPastStyle" value="diagonal" ${state.monthlyPastStyle==='diagonal'?'checked':''}> Diagonal Line</label></div>`;};
monthlyEntryHtml=function(x){const isWeekly=(x._source||'monthly')==='weekly';const id=esc(x._sourceId||x.id);const title=esc(x.title||x.subject||'Monthly Item');const meta=[x.time,x.subject,isWeekly?'Weekly Planner':'Monthly Planner'].filter(Boolean).join(' • ');return `<button class="month-item clickable-month-item ${isWeekly?'month-weekly':'month-local'}" data-action="viewMonthlyVisible" data-source="${isWeekly?'weekly':'monthly'}" data-id="${id}" type="button"><span class="month-click-title">${title}</span><span class="month-click-meta">${esc(meta)}</span></button>`;};

subNotesHtml=function(){const f=state.subNotes.fields||{};return `${subPrompt('overview','Class Overview','What should the sub know about your class personality, energy level, or general expectations?',f.overview)}${subPrompt('attendance','Attendance / Lunch Count','How should attendance, lunch count, bathroom passes, or office notes be handled?',f.attendance)}${subPrompt('schedule','Daily Flow','What does the normal day look like? What should not be skipped?',f.schedule)}${subPrompt('behavior','Behavior Support','What behavior system, rewards, consequences, calming tools, or redirection words should the sub use?',f.behavior)}${subPrompt('students','Student Support Notes','Are there students who may need extra help, seating reminders, medical attention, or quiet support? Keep this professional and need-to-know.',f.students)}${subPrompt('materials','Materials / Technology','Where are worksheets, books, logins, remotes, projector tools, and center materials? Avoid writing private passwords if your school does not allow it.',f.materials)}${subPrompt('emergency','Emergency Procedures','What should the sub do for fire drill, lockdown, nurse, office call, or urgent classroom help?',f.emergency)}${subPrompt('dismissal','Dismissal','How do students leave? Bus, pickup, after-school program, walkers, or dismissal jobs?',f.dismissal)}${subPrompt('extra','Extra Comments','Anything else the substitute should know that does not fit above?',f.extra)}<div class="actions centered subnote-buttons"><button data-action="saveSubNotes">Save Changes</button><button class="secondary" data-action="undoSubNotes">Undo</button><button class="danger" data-action="clearSubNotes">Clear All</button></div>`;};
subexportPage=function(){return renderCards('subexport',[["subPacket",card('subexport','subPacket','',`<p class="tiny">This creates a clean packet using your saved notes, schedule, routines, sub-ready lessons, supplies, reminders, and grade-safe teacher notes.</p><div class="subexport-wide"><button data-action="printSubPacket">Print / Save as PDF</button></div><div id="packetPreview" class="archive-box">${subPacketHtml()}</div>`,{size:'lg',controls:false,heading:false})]],'grid');};

settingsPage=function(){const sections=[['backup','💾 Backup / Restore',`<p class="tiny">Backup makes one private JSON save file. Restore loads that save file back into this browser.</p><div class="actions"><button data-action="backup">⬇ Backup Data</button><button class="secondary" data-action="restoreClick">⬆ Restore Data</button><input id="restoreFile" type="file" accept="application/json" style="display:none"></div>`],['custom','🖌️ Custom Colors',customThemeHtml()],['help','❓ Help / FAQ',`<input id="helpPageSearch" placeholder="Search Help Questions..." value="${esc(state.faqSearch)}"><div id="helpPageResults">${faqResultsHtml(state.faqSearch)}</div>`],['menu','☰ Menu Layout',menuSettingsHtml()],['notifications','🔊 Notifications & Sounds',notificationHtml()],['theme','🎨 Theme Collection',`<p class="tiny">Pick a ready-made look. This saves on this device.</p><div class="swatches">${themeList.map(t=>`<div class="swatch ${(!state.customTheme.enabled&&state.theme===t[0])?'active':''}" data-theme="${t[0]}" style="background:linear-gradient(135deg,${t[2]},${t[3]},${t[4]})">${esc(t[1])}</div>`).join('')}</div>`],['fonts','🔤 Workspace Font',workspaceFontHtml()]];return `<div class="settings-stack">${sections.sort((a,b)=>a[1].localeCompare(b[1])).map(([key,title,body],i)=>`<details class="settings-box"><summary>${title}</summary><div class="settings-content">${body}</div></details>`).join('')}</div>`;};
menuSettingsHtml=function(){const side=state.layout?.menuSide||'left'; return `<div class="menu-layout-note"><b>Menu Side</b><p class="tiny">Put the main menu on the side that feels best for your screen setup.</p><div class="menu-side-choice"><button class="secondary ${side==='left'?'active':''}" data-action="setMenuSide" data-side="left">⬅ Left Side</button><button class="secondary ${side==='right'?'active':''}" data-action="setMenuSide" data-side="right">Right Side ➡</button></div></div><p class="tiny">Hide top-level pages you do not need. Tools & Resources stays grouped so it is easier to use.</p>${orderedPages().map(p=>`<div class="menu-list-row" data-menu-row="${p[0]}"><span>${p[1]} ${esc(p[2])}<br><small>${esc(p[3])}</small></span><button class="small secondary" data-action="toggleMenuPage" data-page="${p[0]}">${state.layout.menuHidden.includes(p[0])?'Show':'Hide'}</button></div>`).join('')}<div class="actions"><button class="secondary" data-action="resetMenu">Reset Menu</button></div>`;};

const __handleActionPrev2054=handleAction;
handleAction=function(action,el){
 if(action==='printStudents'){printStudents();return;}
 if(action==='printAssignments'){printAssignments();return;}
 if(action==='setMenuSide'){state.layout.menuSide=el.dataset.side==='right'?'right':'left';save('Menu Side Saved.');return;}
 if(action==='resetMenu'){state.layout.menuOrder=defaultMenuOrderSozy().concat(topMenuIds.filter(id=>!defaultMenuOrderSozy().includes(id)));state.layout.menuHidden=[];state.layout.defaultOrder2054=true;save('Menu Reset.');return;}
 if(action==='viewMonthly'){const source=el.dataset.source; const id=el.dataset.id; if(source==='weekly'){goToPageCard('planner','board');} else {state.editing.monthly[id]=true;state.activePage='monthly';renderAll();}return;}
 return __handleActionPrev2054(action,el);
};

// Live change/input helpers.
document.addEventListener('change',e=>{
 if(e.target.id==='dashboardStyle'){state.layout.dashboardStyle=e.target.value;save('Dashboard Look Saved.');}
 if(e.target.id==='routineListStyle'){state.routineListStyle=e.target.value;save('Routine Style Saved.');}
 if(e.target.id==='supplyFilter'){state.supplyFilter=e.target.value;const card=document.getElementById('card-supplies-supplies');if(card)card.querySelector('.card-body').innerHTML=suppliesHtml();save('',false);}
 if(e.target.id==='supplyOrder'){state.supplyOrder=e.target.value;const card=document.getElementById('card-supplies-supplies');if(card)card.querySelector('.card-body').innerHTML=suppliesHtml();save('',false);}
 if(e.target.id==='standardFilter'){state.standardFilter=e.target.value;const card=document.getElementById('card-standards-standardList');if(card)card.querySelector('.card-body').innerHTML=standardList();save('',false);}
 if(e.target.id==='standardOrder'){state.standardOrder=e.target.value;const card=document.getElementById('card-standards-standardList');if(card)card.querySelector('.card-body').innerHTML=standardList();save('',false);}
 if(e.target.name==='monthlyPastStyle'){state.monthlyPastStyle=e.target.value;save('Monthly Planner Style Saved.');}
 if(e.target.matches('[data-group-name-id]')){const g=(state.groups||[]).find(x=>x.id===e.target.dataset.groupNameId);if(g){g.name=e.target.value.trim()||g.name;save('Group Name Saved.');}}
 if(e.target.name==='corkBorderRadio'||e.target.name==='corkBoardRadio'){applyCorkSettingsFromInputs();save('',false);renderCorkSettingsModal();}
});
document.addEventListener('input',e=>{
 if(e.target.id==='meetingFilterInput'){state.meetingFilter=e.target.value;const card=document.getElementById('card-meetings-meetingForm');if(card)card.querySelector('.card-body').innerHTML=meetingHtml();save('',false);}
 if(e.target.id==='todoFilterInput'){state.todoFilter=e.target.value;const card=document.getElementById('card-meetings-todoList');if(card)card.querySelector('.card-body').innerHTML=todoHtml();save('',false);}
 if(e.target.id==='corkCustomBorder'){const p=document.getElementById('corkCustomBorderPreview');if(p){p.style.background=e.target.value;p.textContent=e.target.value;}applyCorkSettingsFromInputs();save('',false);}
 if(e.target.id==='corkCustomBoard'){const p=document.getElementById('corkCustomBoardPreview');if(p){p.style.background=e.target.value;p.textContent=e.target.value;}applyCorkSettingsFromInputs();save('',false);}
});
let draggedRoutineId=null;
document.addEventListener('dragstart',e=>{const r=e.target.closest('[data-routine-id]'); if(r){draggedRoutineId=r.dataset.routineId;r.classList.add('dragging');e.dataTransfer.effectAllowed='move';}});
document.addEventListener('dragend',e=>{document.querySelectorAll('.routine-row.dragging').forEach(x=>x.classList.remove('dragging'));draggedRoutineId=null;});
document.addEventListener('dragover',e=>{const r=e.target.closest('[data-routine-id]'); if(r&&draggedRoutineId){e.preventDefault();}});
document.addEventListener('drop',e=>{const r=e.target.closest('[data-routine-id]'); if(r&&draggedRoutineId&&r.dataset.routineId!==draggedRoutineId){e.preventDefault();const arr=state.routines;const from=arr.findIndex(x=>x.id===draggedRoutineId),to=arr.findIndex(x=>x.id===r.dataset.routineId);if(from>-1&&to>-1){const [m]=arr.splice(from,1);arr.splice(to,0,m);save('Routine Order Saved.');}}});
})();


