/* SOZY Workspace duplicate page cleanup 2026-06-07_0058-CT
   Some tool pages also exist in the main page list. Render each page ID once. */
renderPages=function(){
 const mount=document.getElementById('pages');
 if(!mount)return;
 try{
  const seen=new Set();
  const uniquePages=pages.filter(p=>{
    if(!p || seen.has(p[0])) return false;
    seen.add(p[0]);
    return true;
  });
  mount.innerHTML=uniquePages.map(p=>`<section id="page-${p[0]}" class="page ${state.activePage===p[0]?'active':''}" data-page-section="${p[0]}">${renderPage(p[0])}</section>`).join('');
 }catch(err){
  console.error('SOZY Workspace render error:',err);
  mount.innerHTML=`<section class="page active"><div class="plain-block"><h3>This page had a loading hiccup.</h3><p class="tiny">Your saved data should still be safe. Refresh once. If it happens again, export a backup from Settings and send a screenshot of this message.</p><pre class="tiny">${esc(err.message||String(err))}</pre></div></section>`;
 }
};


