  function deleteSelectedGalleryDocs(){const ids=new Set(state.gallerySelected||[]); if(!ids.size){toast('Choose files first.');return;} if(!confirm(`Delete ${ids.size} selected file${ids.size===1?'':'s'} from the document library?`))return; state.gallery=(state.gallery||[]).filter(d=>!ids.has(d.id)); state.gallerySelected=[]; save('Selected document library files deleted.');}
  function saveGalleryDoc(id){const d=(state.gallery||[]).find(x=>x.id===id); if(!d)return; d.name=val('gd_name_'+id)||d.name||'Untitled file'; d.note=val('gd_note_'+id)||''; d.updatedAt=nowIso(); delete state.editing.gallery[id]; save('Document library item saved.');}

