  const __saveMapSettings0206=saveMapSettings;
  saveMapSettings=function(){const board=document.querySelector('[data-classroom-board]'); if(board){state.classroomMap.width=Math.round(board.offsetWidth); state.classroomMap.height=Math.round(board.offsetHeight);} state.classroomMap.dirty=false; save('Classroom map saved.');};
