  const __subexportPage0206=subexportPage;
  subexportPage=function(){return renderCards('subexport',[["subPacket",card('subexport','subPacket','',`<p class="tiny">This creates a clean packet using your saved notes, schedule, routines, sub-ready lessons, supplies, reminders, and grade-safe teacher notes.</p><label class="generated-toggle-line"><input type="checkbox" data-action="toggleGeneratedStatement" ${state.layout.showGeneratedStatement!==false?'checked':''}> Show “Generated from SOZY Workspace” at the top center of printed pages.</label><div class="actions"><button data-action="printSubPacket">Print / Save as PDF</button></div><div id="packetPreview" class="archive-box">${subPacketHtml()}</div>`,{size:'lg',controls:false,heading:false})]],'grid');};

  // Teacher basic info example update: Ms. Smith only, no real user name.
