    const statsBody=`<div class="dash-edit-note">Click a number to open the original page it comes from.</div><div class="stat-grid"><button class="stat stat-click" data-gopage="lessons" data-gocard="lessonList"><div class="num">${state.lessons.filter(l=>!l.archived).length}</div><div class="lbl">Lessons</div></button><button class="stat stat-click" data-gopage="grades" data-gocard="assignments"><div class="num">${activeAssignments().length}</div><div class="lbl">Assignments</div></button><button class="stat stat-click" data-gopage="meetings" data-gocard="todoList"><div class="num">${(state.todos||[]).filter(t=>!t.done&&!t.archived).length}</div><div class="lbl">Open tasks</div></button><button class="stat stat-click" data-gopage="supplies" data-gocard="supplies"><div class="num">${lowSupplies().length}</div><div class="lbl">Low supplies</div></button></div>`;
