    const furnitureFinal=[
      ['desk','Desk'],['table','Table'],['rug','Rug'],['teacherDesk','Teacher Desk'],['smallGroup','Small Group Table'],['bookshelf','Bookshelf'],['cubbies','Cubbies'],['whiteboard','Whiteboard'],['smartboard','Smart Board'],['readingCorner','Reading Corner'],['computer','Computer Station'],['sink','Sink'],['supplyShelf','Supply Shelf'],['turnIn','Turn-in Bin'],['mailboxes','Student Mailboxes'],['calmCorner','Calm Corner'],['pocketChart','Pocket Chart'],['easel','Easel'],['clipboards','Clipboard Station'],['door','Door'],['window','Window']
    ];
    const furnitureSizesFinal={desk:[122,88],table:[184,116],rug:[205,138],teacherDesk:[176,92],smallGroup:[178,108],bookshelf:[145,58],cubbies:[164,60],whiteboard:[205,46],smartboard:[172,52],readingCorner:[178,118],computer:[158,82],sink:[104,58],supplyShelf:[150,62],turnIn:[128,60],mailboxes:[158,64],calmCorner:[166,110],pocketChart:[135,58],easel:[105,78],clipboards:[148,58],door:[74,36],window:[112,34]};
