      const wh=furnitureSizeClean[cleanType]||furnitureSizeClean.custom;
      const t=nowIso();
      m.items.push({id:uid(cleanType),type:cleanType,label:labelOverride?baseLabel:(baseLabel+' '+n),x:34+((n*43)%440),y:52+((n*35)%320),w:wh[0],h:wh[1],studentIds:[],createdAt:t,updatedAt:t});
      m.dirty=true;
