        if(title) title.textContent=state.activePage==='dashboard'?'My Dashboard':(p?.[2]||'SOZY Workspace');
        if(desc) desc.textContent=state.activePage==='dashboard'?'Your visual home base for classroom planning.':(p?.[3]||'');
        document.querySelectorAll('.top-actions [data-action="openGlobalSearchBetaV8"], .top-actions .beta-search-btn-v8').forEach(b=>b.remove());
        document.querySelectorAll('.top-actions [data-action="openQuickStartBetaV8"], .top-actions .beta-quick-btn-v8').forEach(b=>b.remove());
        const top=document.querySelector('.topbar'); if(top)top.classList.add('sozy-header-v15');
