        const todos=arrV15(state.todos).filter(t=>!t.done&&!t.archived);
        const lows=arrV15(state.supplies).filter(s=>!s.archived && (Number(s.have)||0)<(Number(s.need)||0));
        const docs=arrV15(state.gallery).filter(d=>!d.archived);
